import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirAppointmentStrings } from '..';
import { MyTable } from '../../utils';
import { TableCell, Button } from '@material-ui/core';
import { hirSettingStrings, hirSettingActions } from '../../HIRSettings';
import { Done, Close } from '@material-ui/icons';
import { hirUserStrings, hirUserActions } from '../../HIRUsers';
import { hirAppointmentActions } from '../actions';
import { history } from '../../../../helpers';
import { hirRouteNames } from '../../routeNames';
import { appActions } from '../../../../actions';
import { HIRButtonTable } from "../../Includes";

const style = theme => ({
    root: {
    },
    cell : {
        padding : 5,
        fontSize : 11,
    },
    smallBtn : {
        fontSize : 9
    },
    smallBtnRed : {
        fontSize : 9,
        backgroundColor : theme.colors.secondary,
        color : theme.colors.white,
        "&:hover" : {
            backgroundColor : theme.colors.secondary,            
        }
    }
})
class _HIRAppointmentList extends Component {
    componentDidMount() {
        const {
            dispatch, 
            [hirSettingStrings.settings] : settings,
            [hirUserStrings.users] : users,
        } = this.props;
        if(!settings) hirSettingActions.getSettings()(dispatch);
        if(!users) hirUserActions.getUsers()(dispatch);
    }
    approveAppointment = appointment => () => {
        const {dispatch} = this.props;
        hirAppointmentActions.approveAppointment(appointment._id)(dispatch);
    }
    unApproveAppointmentWarning = appointment => () => {
        const {dispatch} = this.props;
        appActions.showSnackDialog(
            "Are sure you want to remove "+appointment.name+"'s visit?",
            [<Button key={"unvisit"+appointment._id} onClick={this.unApproveAppointment(appointment._id)}>Unvisit</Button>]
        )(dispatch);
    }
    unApproveAppointment=(appointId)=>()=>{
        const {dispatch} = this.props;
        appActions.closeSnackDialog()(dispatch);
        hirAppointmentActions.unApproveAppointment(appointId)(dispatch);
    }
    cellMapFormat = ({row, cellMap}) => {
        const {
            classes, 
            [hirSettingStrings.settings] : settings,
            [hirUserStrings.users] : users
        } =this.props;
        switch(cellMap){
            case "date" : return <TableCell className={classes.cell}>
                {new Date(row[cellMap]).toLocaleDateString()}
            </TableCell>
            case "action" : 
                return <TableCell className={classes.cell}>
                    {new Date(row.date).toLocaleDateString() === new Date().toLocaleDateString() ? 
                        (!row.visit ? <HIRButtonTable 
                            onClickCallback={this.approveAppointment(row)}
                            title="Approve"/>
                             :
                            <HIRButtonTable 
                            onClickCallback={this.unApproveAppointmentWarning(row)}
                            type="secondary"
                            title="Unvisit"/>)
                        : null}
                </TableCell> 
            case "by" : 
                if(row[cellMap] === "NaN") return;
                let staff;
                if(users){
                    staff = users.find(item=>item._id === row[cellMap]);
                }
                return <TableCell className={classes.cell}>
                    {staff && staff.myProfile ? 
                        staff.myProfile.lastName + ", "+ staff.myProfile.firstName :
                        null }
            </TableCell>
            case "visit" : 
                const today = new Date();
                const appoint = new Date(row.date);
                const todaySum = Number(today.getFullYear() + String(today.getMonth()).padStart(2, "0") + String(today.getDate()).padStart(2, "0"));
                const appointSum = Number(appoint.getFullYear() + String(appoint.getMonth()).padStart(2, "0") + String(appoint.getDate()).padStart(2, "0"));
                return <TableCell className={classes.cell}>
                {!row[cellMap] ? 
                    (appointSum < todaySum && 
                    <Close color="secondary" fontSize="small"/>)
                    :
                    <Done style={{color : "green"}} fontSize="small"/>
                }
            </TableCell>
            case "patientId" : return <TableCell className={classes.cell}>
                {String(row[cellMap]).padStart(6, "0")}
            </TableCell>
            case "unit" : 
                let unit = row[cellMap];
                if(settings){
                    const units = settings.find(item=>item.name === "units");
                    unit = units.values.find(item=>item.name === row[cellMap]).value;
                }
                return <TableCell className={classes.cell}>
                    {unit}
                </TableCell>
            case "_id" : return <TableCell className={classes.cell}>
                {String(row[cellMap]).substr(0, 6)}...
            </TableCell> 
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    render() {
        const {
            classes,
            [hirAppointmentStrings.appointments] : appointments
        } = this.props;
        return (
            <div className={classes.root}>
                <MyTable
                    header={["ID", "Patient ID", "Name", "Unit", "Date", "Staff", "Visited", "Action"]}
                    dataMap={["_id", "patientId", "name", "unit", "date", "by", "visit", "action"]}
                    CellMap={this.cellMapFormat.bind(this)}
                    rowAction={row=>()=>history.push(hirRouteNames.patientView_+row.patientId)}
                    {...this.props.tableProps}
                    />
            </div>
        );
    }
}


_HIRAppointmentList.propTypes = {
    classes : PropTypes.object.isRequired,
    tableProps : PropTypes.shape(MyTable?.propTypes),
};
const mapStateToProps = ({hirSettingReducer, hirUserReducer}) => ({
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings],
    [hirUserStrings.users] : hirUserReducer[hirUserStrings.users]
})


export const HIRAppointmentList = connect(mapStateToProps)(withStyles(style)(_HIRAppointmentList));
export {HIRAppointmentList as default}