import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyTable, MyDialog, hirUtil } from '../../utils';
import { IconButton, Checkbox, FormControlLabel, Typography, CircularProgress, TableCell } from '@material-ui/core';
import { CalendarToday, CalendarViewDay } from '@material-ui/icons';
import Calendar from 'react-calendar';
import { HIRButton, HIRStartEndDates } from '../../Includes';
import { hirAccountActions } from '../actions';
import { hirAccountStrings } from '../config';
import { hirSettingStrings, hirSettingActions } from '../../HIRSettings';
import { errorNotice, monthSelections, warningNotice } from '../../../../utils';
import { history } from '../../../../helpers';
import { hirRouteNames } from '../../routeNames';
import ReactToPrint from 'react-to-print';
import { Fragment } from 'react';
import { PAYMENT_METHODS } from '..';


const style = theme => ({
    root: {
    },
    header : {
        color : theme.colors.primary,
        fontWeight : "bold",
    },
    progress : {
        width : "30px !important",
        height : "30px !important",
    },
    cell : {
        fontSize : 11, 
        padding : 5,
    },
    headerContainer : {
        display : 'flex',
        marginBottom : 20,
        alignItems : "center",
    },
})
class _HIRRevenueList extends Component {
    constructor(props) {
        super(props);
        this.state = {
            monthOnlyView : false,
            calenderDialog : false,
            dateSearchBtnLoading : false,
            searchDate : new Date(),
            dialogType : "date",
        }
    }
    componentDidMount() {
        this.searchByDate();
        const {dispatch, [hirSettingStrings.settings] : settings} = this.props;
        if(!settings)
            hirSettingActions.getSettings()(dispatch);

    }
    
    onChange(e){
        const value = e.target.checked;
        this.setState({monthOnlyView : value},()=>{
            this.searchByDate();
        });
    }
    searchByDate(fromCalenderDialog){
        const {searchDate, monthOnlyView, dialogType, startDate, endDate} = this.state;
        const {dispatch}=this.props;
        if(fromCalenderDialog){
            this.setState({dateSearchBtnLoading : true});
        }
        if(dialogType === "date"){
            if(!searchDate) return errorNotice("No date Selected", dispatch);            
            const date = new Date(searchDate);
            hirAccountActions.getRevenuePaymentsByDate(
                date.getFullYear(), 
                date.getMonth() + 1,
                fromCalenderDialog ? date.getDate() :
                (monthOnlyView ? null : date.getDate()),
                (done, result, message)=>{
                    this.setState({dateSearchBtnLoading : false});
                    if(done && fromCalenderDialog) 
                        this.setState({calenderDialog : false, monthOnlyView : false});
                }
            )(dispatch);
        }else {
            if(!startDate) return errorNotice("Start date isn't selected", dispatch);
            if(!endDate) return errorNotice("End date isn't selected", dispatch);
            const date1 = new Date(endDate), date2 = new Date(startDate);
            if((date1.getFullYear() * 12 + date1.getMonth()) - (date2.getFullYear()*12 + date2.getMonth()) > 3){
                return warningNotice("Please make your month range within 3 months", dispatch);
            }
            if(fromCalenderDialog){
                this.setState({dateSearchBtnLoading : true});
            } 
            hirAccountActions.getRevenuePaymentsByDateRange(
                startDate, endDate, {}, done => {
                    this.setState({dateSearchBtnLoading : false});
                    if(done && fromCalenderDialog) 
                        this.setState({calenderDialog : false, monthOnlyView : false});
                }
            )(dispatch);
        }
    }
    cellMapFormat = ({row, cellMap})=>{
        const {
            classes,
            [hirSettingStrings.settings] : settings
        } = this.props;
        if(row.lastLine){
            switch(cellMap){
                case "_id" : return <TableCell className={classes.cell}>
                    <strong>Total</strong>
                </TableCell>;
                case "cashPayment" : 
                case "useCredit" : 
                case "addToDebt" : 
                    return <TableCell className={classes.cell}>
                    <strong>{Number(row[cellMap] || 0).toLocaleString()}</strong>
                </TableCell> 
                default : return <TableCell className={classes.cell}>
                    <strong>{row[cellMap]}</strong>
                </TableCell>
            }
        }else{
            switch(cellMap){
                case "_id" : 
                    let value = "";
                    if(settings){
                        const setting = settings.find(item=>item.name === "revenue");
                        if(setting && setting.values){
                            if(!this.revenueCat) this.revenueCat = setting.values;
                            const option = setting.values.find(item=>item.name === row["revenueType"]);
                            if(option) value = option.value;
                        }
                    }
                    return <TableCell className={classes.cell}>
                        {value}
                </TableCell>
                case "cashPayment" : 
                case "useCredit" : 
                case "addToDebt" : 
                    const {paymentMethods} = row;
                    return <TableCell className={classes.cell}>
                    {Number(paymentMethods[cellMap] || 0).toLocaleString()}
                </TableCell>
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }
    }
    rowAction = row=>()=>{ 
        if(row.lastLine) return;
        const {monthOnlyView, searchDate, dialogType, startDate, endDate} = this.state
        history.push(
            hirRouteNames.accountViewPaymentDetail, 
            {
                name : row?.revenueType, 
                type : "revenue",
                monthOnlyView, date : searchDate,
                revenueCats : this.revenueCat,
                dialogType, startDate, endDate
            }
        )
    }
    render() {
        let {
            classes,
            [hirAccountStrings.revenueBasedPayments] : revenuePayments,
        } = this.props;
        let {monthOnlyView, calenderDialog, dateSearchBtnLoading, searchDate : date, dialogType, startDate, endDate} = this.state;
        let searchDate = new Date(date), 
        categorisedPayments = [], paymentTotals = {};
        if(revenuePayments){
            for (let i = 0; i < revenuePayments.length; i++) {
                const {_id : {revenueType, accountAction = "cashPayment"}, total} = revenuePayments[i];
                const catPayIndex = categorisedPayments.findIndex(item=>item.revenueType === revenueType);
                const amount = parseInt(total);
                if(paymentTotals[accountAction]){
                    paymentTotals[accountAction] += amount;
                }else paymentTotals[accountAction] = amount;
                if(catPayIndex === -1){
                    categorisedPayments.push({
                        revenueType, 
                        paymentMethods : {
                            [accountAction] : amount
                        }
                    })
                }else{
                    const cPay = categorisedPayments[catPayIndex];
                    categorisedPayments[catPayIndex] = {
                        ...cPay, paymentMethods : {
                            ...cPay.paymentMethods, 
                            [accountAction] : cPay.paymentMethods[accountAction] ? 
                            cPay.paymentMethods[accountAction] + amount : amount}
                    }
                }
            }
            categorisedPayments = [...categorisedPayments, {lastLine : true, ...paymentTotals}];
        }
        return (
            <div className={classes.root}>
                <div className={classes.headerContainer}>
                    <IconButton onClick={()=>this.setState({calenderDialog : true, dialogType : "date"})}>
                        <CalendarToday color="secondary"/>
                    </IconButton>
                    <FormControlLabel
                            value={monthOnlyView}
                            onChange={this.onChange.bind(this)}
                        control={<Checkbox/>}
                        label={<Typography style={{fontSize : 14}}>Month only view</Typography>}
                        />
                    {hirUtil.isAdmin() && <div><HIRButton
                        type="secondary"
                        onClick={()=>this.setState({calenderDialog : true, dialogType : "dateRange"})}
                        classes={{btn : classes.marginRight}}
                        >
                            <CalendarViewDay fontSize="small"/>
                            Date Range
                    </HIRButton></div>}
                </div>
                <div style={{width : "100%"}} ref={e=>this.printComponent=e}>
                    <MyTable
                        titleProps={{
                            style : {
                                fontSize : 14
                            }
                        }}
                        title={dialogType === "date" ? 
                            (monthOnlyView ? 
                                searchDate.getFullYear()+", "+(monthSelections.find(item=>item.value ==searchDate.getMonth()+1).name) : 
                                searchDate.toDateString()
                            ) : new Date(startDate).toLocaleDateString() + " to " + 
                                new Date(endDate).toLocaleDateString()
                        }
                        header={["Name", "Cash Payment", "Credit Payment", "Debit Payment"]}
                        dataMap={["_id", "cashPayment", "useCredit", "addToDebt"]}
                        rowAction={this.rowAction.bind(this)}
                        data={categorisedPayments}
                        CellMap={this.cellMapFormat.bind(this)}
                        />
                </div>
                <ReactToPrint 
                    trigger={()=><button>Print</button>}
                    content={()=>this.printComponent}
                />
                
                <MyDialog open={calenderDialog}
                 close={()=>this.setState({calenderDialog : false})}>
                     <div style={{
                         display : "flex",
                         flexDirection : "column",
                         alignItems : "center",
                         justifyContent : "center"
                         }}>
                             {dialogType === "date" && <Fragment>
                                <Typography paragraph className={classes.header}>Search Payment by dates</Typography>
                                <Calendar
                                    onChange={date=>this.setState({searchDate : date})}/>
                            </Fragment>}
                            {dialogType === "dateRange" && <Fragment>
                            <Typography paragraph className={classes.header}>Search Payment by dates range</Typography>
                                <HIRStartEndDates
                                    noTitle
                                    containerProps={{
                                        style : {
                                            width : "100%"
                                        }
                                    }}
                                    onDateChange={(startDate, endDate)=>this.setState({startDate, endDate})}/>
                            </Fragment>}
                        <div style={{marginTop : 20}}>
                            <HIRButton type="primary" 
                                disabled={dateSearchBtnLoading}
                                onClick={()=>this.searchByDate(true)}>
                                    {dateSearchBtnLoading && 
                                    <CircularProgress color="secondary" 
                                        className={classes.progress}/>} Get Payments
                                </HIRButton>
                        </div>
                    </div>
                    
                 </MyDialog>            
            </div>
        );
    }
}


_HIRRevenueList.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({hirAccountReducer, hirSettingReducer}) => ({
    [hirAccountStrings.revenueBasedPayments] : hirAccountReducer[hirAccountStrings.revenueBasedPayments],
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings],
})


export const HIRRevenueList = connect(mapStateToProps)(withStyles(style)(_HIRRevenueList));
export {HIRRevenueList as default}