import React, { PureComponent } from 'react'
import PropTypes from 'prop-types'
import classNames from 'classnames';
import { Button } from '@material-ui/core';
import {withStyles} from '@material-ui/core/styles';
import { colors } from '../../utils';

const style = theme => ({
    button : {
        backgroundImage : "linear-gradient(to right, "+ colors.primary + ", " + colors.gray+")",
        color : colors.wheat,
        padding : 5,
        "&:hover" : {
            backgroundColor : colors.wheat,
            color : colors.primary
        }
    },
    cancel : {
        backgroundColor : colors.appRed, 
        "&:hover" : {
            backgroundColor : colors.appRedDark,
            color : "white"
        }
    },
    g_secondary : {
        backgroundImage : "linear-gradient(to right, "+ colors.primary + ", " + colors.secondary+")",
    }
})
class _MyButtonGradient extends PureComponent {
    static propTypes = {
        variant : PropTypes.oneOf([
            "contained", "raised", "text", "extendedFab", "fab", "flat", "outlined"]),
        type : PropTypes.oneOf([
            "ok", "cancel", 
        ]),
        gradient : PropTypes.oneOf(["primary", "secondary"]),
        value : PropTypes.string,
        onClick : PropTypes.func.isRequired,
        style : PropTypes.object,
    }
    getGradientName(gradient){
        return "g_"+gradient;
    }
    render() {
        const {classes, onClick, gradient, variant, type, value, children, className, ...others} = this.props;

        return (
            <Button 
                {...others}
                className={classNames([classes.button, classes[type], classes[this.getGradientName(gradient)], className])}
                variant={variant || "contained"}
                onClick={onClick}>
                    {children || value || type || "Ok"}
            </Button>
        )
    }
}
export const MyButtonGradient = withStyles(style)(_MyButtonGradient);
export default MyButtonGradient;
