import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import Chart from 'chart.js';
import { Paper } from '@material-ui/core';

const style = theme => ({
    root: {
        width: "100%",
        dipslay: "flex",
        justifyContent : "center",
        margin : 10
    },
    root1: {
        width: "100%",
        dipslay: "flex",
        justifyContent : "center",
    }
})
class _LineChart extends Component {
    componentDidUpdate(){
        this.hostChart();
    }
    hostChart(){
        var ctx = document.getElementById(this.props.canvasId).getContext('2d');
        var myChart = new Chart(ctx, {
            type: 'line',
            data: {
                labels: this.props.labels,
                datasets: [{
                    label: this.props.label,
                    data: this.props.data,
                    backgroundColor : "blue",
                    borderColor : "red",
                    /* backgroundColor: [
                        'rgba(255, 99, 132, 0.2)',
                        'rgba(54, 162, 235, 0.2)',
                        'rgba(255, 206, 86, 0.2)',
                        'rgba(75, 192, 192, 0.2)',
                        'rgba(153, 102, 255, 0.2)',
                        'rgba(255, 159, 64, 0.2)'
                    ], 
                    borderColor: [
                        'rgba(255, 99, 132, 1)',
                        'rgba(54, 162, 235, 1)',
                        'rgba(255, 206, 86, 1)',
                        'rgba(75, 192, 192, 1)',
                        'rgba(153, 102, 255, 1)',
                        'rgba(255, 159, 64, 1)'
                    ],*/
                    borderWidth: 1
                }]
            },
            options: {
                scales: {
                    yAxes: [{
                        ticks: {
                            beginAtZero: true
                        }
                    }]
                }
            }
        });
    }
    render() {
        const {classes, canvasId, nested} = this.props;
        const height = this.props.height || 400
        const root = nested ? classes.root1 : classes.root;
        return (
            <Paper className={root}>
                <canvas style={{width: "100%"}} id={canvasId} height={height}></canvas>
            </Paper>
        );
    }
}


_LineChart.propTypes = {
    classes : PropTypes.object.isRequired,
    label : PropTypes.string.isRequired,
    data : PropTypes.array.isRequired,
    labels : PropTypes.array.isRequired,
    canvasId : PropTypes.string.isRequired,
    height: PropTypes.number,
    nested : PropTypes.bool,
};
const mapDispatchToProps = dispatch => {
    return {
        dispatch
    }
}
const mapStateToProps = state => ({
    state
})


export const LineChart = connect(mapStateToProps,mapDispatchToProps)(withStyles(style)(_LineChart));