export const simplePaginationConfig = (
    context, action, dispatch, stateName, 
    rows, sort, max, 
    minMaxIdAction, searchAction, searchMinMaxIdAction)=>{

    if(!context) throw("Context is "+String(context).toString()+", but requred!");
    if(!rows && !context.state.rows) throw("Table rows is not specified");
    function configurePagination(skip, result){ 
        if(result && result.length !== 0){
            const newLastId = result[result.length - 1]._id;
            const newFirstId = result[0]._id;
            context.setState({
                skip, [stateName] : result,  //new additions
                lastId : newLastId, firstId : newFirstId
            })
        }else{
            context.setState({
                skip, [stateName] : result
            })
        }
    }
    function getAction(callback){
        if(!rows) rows = context.state.rows;
        let skip = 0;
        if(action){
            if(minMaxIdAction) minMaxIdAction(sort, (done, result)=>{
                let minId, maxId = null;
                if(result) {
                    minId = result.minId;
                    maxId = result.maxId;
                }
                if(done)context.setState({minId, maxId});
            })(dispatch);
            action(rows, skip, sort, max, (done, result, message)=>{
                if(done){
                    if(callback) callback(done, result, message);
                    configurePagination(skip, result);
                }
            })(dispatch);
        }
    }
    function search(keyword, callback){
        context.setState({keyword});
        if(!rows) rows = context.state.rows;
        let skip = 0;
        if(searchAction){
            if(searchMinMaxIdAction) searchMinMaxIdAction(keyword, sort, (done, {minId, maxId})=>{
                if(done)context.setState({minId, maxId});
            })(dispatch);
            searchAction(keyword, rows, skip, sort, max, (done, result, message)=>{
                if(done){
                    if(callback) callback(done, result, message);
                    configurePagination(skip, result);
                }
            })(dispatch);
        }
    }
    function prevBtnOnClick(callback){
        return function(e){
            let {skip, keyword} = context.state;
            if(!rows) rows = context.state.rows
            skip-=rows;
            if(skip < 0) skip = 0;
            if(keyword && String(keyword).trim() && String(keyword).trim() !== ""){
                if(searchAction){
                    searchAction(keyword, rows, skip, sort, max, (done, result, message)=>{
                        if(done){
                            if(callback) callback(done, result, message);
                            configurePagination(skip, result);
                        }
                    })(dispatch);
                }
            }else{
                if(action){
                    action(rows, skip, sort, max, (done, result, message)=>{
                        if(done){
                            if(callback) callback(done, result, message);
                            configurePagination(skip, result);
                        }
                    })(dispatch);
                }
            }
        }
    }
    function nextBtnOnClick(callback){
        const self = this;
        return function(e){
            let {skip, keyword} = context.state;
            if(!rows) rows = context.state;
            skip+=rows;
            if(skip < 0) skip = 0;
            if(keyword && String(keyword).trim() && String(keyword).trim() !== ""){
                if(searchAction){
                    searchAction(keyword, rows, skip, sort, max, (done, result, message)=>{
                        if(done){
                            if(callback) callback(done, result, message);
                            configurePagination(skip, result);
                        }
                    })(dispatch);
                }
            }else{
                if(action){
                    action(rows, skip, sort, max, (done, result, message)=>{
                        if(done){
                            if(callback) callback(done, result, message);
                            configurePagination(skip, result);
                        }
                    })(dispatch);
                }
            }
        }
    }
    function prevBtnDisabled(){
        const {skip, rows, [stateName] : result} = context.state;
        return !skip || skip === 0 || (result && result.length < rows)
    }
    function nextBtnDisabled(){
        const {[stateName] : result, rows, minId, lastId} = context.state;
        return !result || minId === 0 || result.length < rows || minId === lastId
    }
    return {
        getAction, prevBtnOnClick, nextBtnOnClick, 
        prevBtnDisabled, nextBtnDisabled, search
    }
}