import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import MyArticleDisplayHeader from './MyArticleDisplayHeader/MyArticleDisplayHeader';
import MyArticleDisplayContent from './MyArticleDisplayContent/MyArticleDisplayContent';
import { IconButton, Popover, List, ListItem, ListItemText, Button, FormLabel, FormControlLabel, Checkbox } from '@material-ui/core';
import { Add, Edit, Delete, Cancel, Done } from '@material-ui/icons';
import { MyDialog } from '../../MyDialog';
import MyArticleTextField from '../MyArticleConfig/MyArticleTextField/MyArticleTextField';
import { MyArticleConfig, MyArticleImage } from '../MyArticleConfig';


const style = theme => ({
    root: {
        position : "relative",
    },
    overlayBtnContainer :{
        position : "absolute",
        zIndex : 100,
        top : 10,
        right : 10,
    },
    subContainer : {
        marginTop : 20,
        marginLeft: 20,
    },
    sub_title : {
        fontSize : 14,
    },
    sub_subtitle : {
        fontSize : 12,
    },
    iconBtn : {
        padding : 3,
    },
    imgContainer : {
        justifyContent : "flex-start",
    },
    marginTop : {
        marginTop : 20,
    }
})
class _MyArticleDisplay extends Component {
    state = {
        anchorEl : null,
        openDialog : false,
        newContents : null,
    }
    setAnchorEl = actionName => e =>{
        const anchorEl = e.target;
        this.setState({anchorEl, actionName})
    }
    dialogDisplayHandler = (article, actionName, menuId) => {
        if(actionName === "edit"){
            return this.editComponentSeletor(article, menuId);
        }else if (actionName === "add"){
            return this.addComponentSelector(article, menuId);
        }else if(actionName === "delete"){
            return this.deleteComponentSelector(article, menuId);
        }
    }
    deleteComponentSelector(article, menuId){
        if(menuId === "image") return this.deleteImageComponent(article, menuId);
        else return this.deleteContentComponent(article, menuId);
    }
    deleteContentArray = []
    deleteContentComponent(article, menuId){
        const {data} = article || {};
        const articleId = article && article._id;
        const EditButtonComponent = this.editButtonHandler.bind(this);
        return <div style={{padding : 10}}>
            <FormLabel>New Sub-article</FormLabel>
            <div style={{marginTop : 50}}/>
            {data && data.map((item, index)=>{
                return new RegExp("^"+menuId+"\\d+").test(item.name) && 
                <FormControlLabel
                    key={index}
                    label={<div style={{fontSize : 12}}>{item.value}</div>}
                    control={<Checkbox value={item.name}/>}
                    onChange={e=>{
                        const checked = e.currentTarget.checked;
                        if(checked){
                            this.deleteContentArray.push(item.name);
                        }else this.deleteContentArray.slice(
                            this.deleteContentArray.indexOf(item.name), 1
                        );
                    }}
                />
            })}
            <EditButtonComponent
                onCancel={()=>this.setState({openDialog : false, menuId : null})}
                onContinue={()=>{
                    const {onDeleteArticleContent} = this.props;
                    onDeleteArticleContent && onDeleteArticleContent(
                        articleId, this.deleteContentArray, menuId, this
                    )
                }}
            />                
        </div>
    }
    deleteImageArray = [];
    deleteImageComponent(article, menuId){
        const {data} = article || {};
        const {imageBaseUrl} = this.props;
        const articleId = article && article._id;
        const EditButtonComponent = this.editButtonHandler.bind(this);
        return <div style={{padding : 10}}>
            <FormLabel>New Sub-article</FormLabel>
            <div style={{marginTop : 50}}/>
            {data && data.map((item, index)=>{
                return new RegExp("^"+menuId+"\\d+").test(item.name) && 
                    <FormControlLabel
                        key={index}
                        label={<MyArticleImage
                            profilePictureProps={{
                                title : item.name,
                                src : /^http/.test(item.src) ?
                                    item.src : imageBaseUrl + item.src,
                            }}
                        />}
                        control={<Checkbox value={item.name}/>}
                        onChange={e=>{
                            const checked = e.currentTarget.checked;
                            if(checked){
                                this.deleteImageArray.push(item.name);
                            }else this.deleteImageArray.slice(
                                this.deleteImageArray.indexOf(item.name), 1
                            );
                        }}
                    />
            })}
            <EditButtonComponent
                onCancel={()=>this.setState({openDialog : false, menuId : null})}
                onContinue={()=>{
                    const {onDeleteArticleContent} = this.props;
                    onDeleteArticleContent && onDeleteArticleContent(
                        articleId, this.deleteImageArray, menuId, this
                    )
                }}
            />                
        </div>
    }
    addComponentSelector(article, menuId){
        let highestNumber = 0;
        const articleId = article && article._id;
        const {data} = article || {};
        switch(menuId){
            case "content" : 
                if(data) for (let i = 0; i < data.length; i++) {
                    const {name} = data[i];
                    const nameSearch = /^content\d+/.exec(name);
                    const numberSearch = /\d+/.exec(nameSearch && nameSearch[0]);
                    if(numberSearch && parseInt(numberSearch) > highestNumber)
                        highestNumber = numberSearch && parseInt(numberSearch[0]);
                }
                return this.newContentComponent(articleId, "content"+ ++highestNumber);
                case "sub" : 
                    if(data) for (let i = 0; i < data.length; i++) {
                        const {name} = data[i];
                        const nameSearch = /^sub\d+/.exec(name);
                        const numberSearch = /\d+/.exec(nameSearch && nameSearch[0]);
                        if(numberSearch && parseInt(numberSearch) > highestNumber)
                            highestNumber = numberSearch && parseInt(numberSearch[0]);
                    }
                    return this.newArticleComponent(articleId, "sub"+ ++highestNumber);
                case  "image" : 
                    if(data) for (let i = 0; i < data.length; i++) {
                        const {name} = data[i];
                        const nameSearch = /^image\d+/.exec(name);
                        const numberSearch = /\d+/.exec(nameSearch && nameSearch[0]);
                        if(numberSearch && parseInt(numberSearch) > highestNumber)
                            highestNumber = numberSearch && parseInt(numberSearch[0]);
                    }
                    return this.newImageComponent(articleId, "image" + ++highestNumber)
        }
    }
    newImageComponent(articleId, name){
        const EditButtonComponent = this.editButtonHandler.bind(this);
        return <div style={{padding : 10}}>
            <FormLabel>New Sub-article</FormLabel>
            <div style={{marginTop : 50}}/>
            <MyArticleImage
                profilePictureProps={{
                    editable : true,
                    src : "",
                    uploadImage : imageFile => this.state.imageFile = imageFile
                }}
            />
            <EditButtonComponent
                onCancel={()=>this.setState({openDialog : false, menuId : null})}
                onContinue={()=>{
                    this.setState({loading : true});
                    const {imageFile} = this.state;
                    const {onAddProperty} = this.props;
                    onAddProperty && onAddProperty(
                        "image", articleId, 
                        {imageFile, name}, this
                    );
                }}
            />                
        </div>
    }
    newArticleComponent(articleId, name){
        const EditButtonComponent = this.editButtonHandler.bind(this);
        return <div style={{padding : 10}}>
            <FormLabel>New Sub-article</FormLabel>
            <div style={{marginTop : 50}}/>
            <MyArticleConfig
                getContext={context=>this.newArticleContext=context}
            />
            <EditButtonComponent
                onCancel={()=>this.setState({openDialog : false, menuId : null})}
                onContinue={()=>{
                    const {data} = this.newArticleContext && this.newArticleContext.state || {};
                    const {onAddProperty} = this.props;
                    this.setState({loading : true});
                    onAddProperty && onAddProperty(
                        "article", articleId, 
                        {data, name}, this
                    );
                }}
            />                
        </div>
    }
    newContentComponent(articleId, newName){
        const EditButtonComponent = this.editButtonHandler.bind(this);
        return <div style={{padding : 10}}>
            <FormLabel>New Content</FormLabel>
            <div style={{marginTop : 50}}/>
            <MyArticleTextField
                name={newName}
                getStateData={newContent=>this.state.newContent = newContent}
                textFieldProps={{
                    label : "Content",
                    placeholder : "Content",
                    multiline : true,
                    rows : 6,
                    rowsMax : 6,
                }}/>
            <EditButtonComponent
                onCancel={()=>this.setState({openDialog : false, menuId : null})}
                onContinue={()=>{
                    const {newContent} = this.state;
                    const {onAddProperty} = this.props;
                    onAddProperty && onAddProperty("content", articleId, newContent, this);
                }}
            />                
        </div>
    }
    contentChanges = [];
    editComponentSeletor(article, menuId){
        const {data} = article || {};
        switch(menuId){
            case "image" :
                const images = [];
                if(data) for (let i = 0; i < data.length; i++) {
                    const {name} = data[i];
                    if(/^image\d+/.test(name)){
                        images.push({...data[i]})
                    }
                }
                return this.editCompnent(article && article._id, images, "Image");
            case "title" :
                const titles = [];
                if(data) for (let i = 0; i < data.length; i++) {
                    const {name} = data[i];
                    if(/^title/.test(name)){
                        titles.push({...data[i]})
                    }
                }
                return this.editCompnent(article && article._id, titles, "Title");
            case "subtitle" :
                const subtitles = [];
                if(data) for (let i = 0; i < data.length; i++) {
                    const {name} = data[i];
                    if(/^subtitle/.test(name)){
                        subtitles.push({...data[i]})
                    }
                }
                return this.editCompnent(article && article._id, subtitles, "Subtitle");
            case "content" : 
                const contents = [];
                if(data) for (let i = 0; i < data.length; i++) {
                    const {name} = data[i];
                    if(/^content\d+/.test(name)){
                        contents.push({...data[i]})
                    }
                }
                return this.editCompnent(article && article._id, contents, "Content", true);
        }
    }
    editCompnent(articleId, contents, label, textArea){
        const {imageBaseUrl, onArticleUpdate, article} = this.props;
        const {productId} = article || {};
        const EditButtonComponent = this.editButtonHandler.bind(this);
        if(label === "Image"){
            return <div style={{padding : 20}}>
                <FormLabel>Edit {label}</FormLabel>
                <div style={{marginTop : 50}}/>
                {contents.length > 0 ? contents.map((item, index)=>{
                    const {name, src} = item;
                    return <MyArticleImage
                        key={index}
                        profilePictureProps={{
                            title : item.name,
                            editable : true,
                            src : /^http/.test(src) ? src : imageBaseUrl + src,
                            uploadImage : imageFile => {
                                onArticleUpdate && onArticleUpdate(
                                    articleId, {imageFile, name, src, productId},
                                    "image", this
                                );
                            }
                        }}
                    />
                }) : 
                <div style={{display : "flex", justifyContent : "center"}}>
                    <i>there is no {label} in this article</i>
                </div>}
                <Button
                    color="primary"
                    variant="outlined"
                    onClick={()=>this.setState({openDialog : false, menuId : null})}>
                    <Done fontSize="small"/>
                    Continue
                </Button>
            </div>
        }else return <div style={{padding : 20}}>
            <FormLabel>Edit {label}</FormLabel>
            <div style={{marginTop : 50}}/>
            {contents.length > 0 ? contents.map((item, index)=>{
                return <MyArticleTextField
                    key={index}
                    data={item}
                    getStateData={state=>{
                        const changeIndex = this.contentChanges.findIndex(
                            item=>item.name===state.name
                        );
                        if(changeIndex !== -1)
                            this.contentChanges[changeIndex] = state;
                        else this.contentChanges.push(state);
                    }}
                    textFieldProps={textArea ? {
                        multiline : true,
                        rows : 6,
                        rowsMax : 6,
                        placeholder : label,
                        label
                    } : {
                        placeholder :label, label
                    }}
                    />
            }) : <div style={{display : "flex", justifyContent : "center"}}>
                    <i>there is no {label} in this article</i>
                </div>}
            <EditButtonComponent 
                onCancel={()=>this.setState({openDialog : false, menuId : null})}
                onContinue={()=>contents.length !== 0 && onArticleUpdate && 
                    onArticleUpdate(articleId, this.contentChanges, "content", this)}
            />
        </div>
    }
    editButtonHandler(props){
        return <div style={{marginTop : 20}}>
            <Button 
                variant="outlined"
                onClick={props.onCancel}
                style={{marginRight : 10}}>
                    <Cancel fontSize="small"/>
                    Cancel
                </Button>
            <Button 
                variant="outlined"
                onClick={props.onContinue}
            >
                <Done fontSize="small"/>
                Continue
            </Button>
        </div>
    }
    onDeleteArticle = (parentArticle, subArticles, article) => {
        const {onDeleteArticle} = this.props;
        this.setState({anchorEl : null});
        const articleId = article && article._id;
        let childrenIds = [];
        let parentId = parentArticle && parentArticle._id;
        childrenIds = this.getChildArtile(article, subArticles, childrenIds);
        onDeleteArticle && onDeleteArticle(parentId, articleId, childrenIds, this);
    }
    getChildArtile(article, subArticles, storeArray=[]){
        const {data} = article || {};
        if(data) for (let i = 0; i < data.length; i++) {
            const {subArticleId} = data[i];
            if(subArticleId){
                storeArray.push(subArticleId);
                const subArticle = subArticles && subArticles.find(
                    item=>item._id === subArticleId
                );
                storeArray = this.getChildArtile(
                    subArticle, subArticles, storeArray
                )
            }
        }
        return storeArray;
    }
    render() {
        let {
            classes, article, subArticles : rootSubArticles,
            parentArticle, imageBaseUrl
        } = this.props;
        let {data, subArticles} = article || {};
        if(!subArticles) subArticles = rootSubArticles;
        const imageIndex = data && data.findIndex(
            item=>/^image\d+/.test(item.name)
        );
        const contentIndex = data && data.findIndex(
            item=>/^content\d+/.test(item.name)
        );
        const {anchorEl, actionName, menuId, openDialog} = this.state;
        let menuList = [];
        if(actionName === "delete") menuList.push(
            {id : "article", label : "Article"}
        )
        if (actionName === "edit") menuList.push(
            {id : "title", label : "Title"},
            {id : "subtitle", label : "Subtitle"}
        );
        if(imageIndex !== -1 && actionName !== "add") menuList.push(
            {id : "image", label :"Image"}
        );
        if(contentIndex !== -1 && actionName !== "add") menuList.push(
            {id : "content", label :"Content"}
        );
        if(actionName === "add") menuList.push( 
            {id : "sub", label : "Subarticle"},
            {id : "image", label : "Image"},
            {id : "content", label :"Content"}, 
        );
        return (
            <div className={classes.root}>
                <div className={classes.overlayBtnContainer}>
                    {this.props.onAdd && <IconButton 
                        className={classes.iconBtn}
                        onClick={this.setAnchorEl("add")}>
                        <Add fontSize="small"/>
                    </IconButton>}
                    {this.props.onEdit && <IconButton 
                        onClick={this.setAnchorEl("edit")}
                        className={classes.iconBtn}>
                        <Edit fontSize="small"/>
                    </IconButton>}
                    {this.props.onDelete && <IconButton 
                        onClick={this.setAnchorEl("delete")}
                        className={classes.iconBtn}>
                        <Delete fontSize="small"/>
                    </IconButton>}
                    <Popover
                        open={Boolean(anchorEl)}
                        anchorEl={anchorEl}
                        onClose={()=>this.setState({anchorEl : null})}
                        classes={this.props.popoverClasses}>
                        <List>
                            {menuList.map((item, index)=>
                                <ListItem
                                    key={index} 
                                    button 
                                    onClick={()=>{
                                        if(actionName === "delete" && item.id === "article"){
                                            this.onDeleteArticle(parentArticle, subArticles, article)
                                        }else this.setState({anchorEl : null, menuId : item.id, openDialog : true})
                                    }}>
                                    <ListItemText
                                        primary={item.label}
                                        primaryTypographyProps={{
                                            style:{padding :5, fontSize : 12}
                                        }}
                                        />
                                </ListItem>
                            )}
                        </List>
                    </Popover>
                </div>
                <MyDialog
                    open={openDialog}
                    close={()=>this.setState({openDialog : false, actionName : null, menuId : null})}>
                        {this.dialogDisplayHandler(article, actionName, menuId)}
                </MyDialog>
                {data && data.map((item, index)=>{
                    let {name, value, subArticleId, props} = item;
                    props = props ? {
                        ...props, 
                        style : {
                            ...props.style, 
                            color : props.style.color && props.style.color.hex
                        }
                    } : {};
                    if(/^sub\d+/.test(name)){
                        const _article = subArticles && subArticles.find(item=>item._id===subArticleId);
                       return _article && <div className={classes.subContainer} key={index}>
                            <MyArticleDisplay
                                headerProps={{
                                    classes : {
                                        header : classes.sub_title,
                                        subtitle : classes.sub_subtitle
                                    }
                                }}
                                parentArticle={article}
                                article={_article}
                                subArticles={subArticles}
                                onEdit={this.props.onEdit}
                                onAdd={this.props.onAdd}
                                onDelete={this.props.onDelete}
                                onArticleUpdate={this.props.onArticleUpdate}
                                onDeleteArticle={this.props.onDeleteArticle}
                                onDeleteArticleContent={this.props.onDeleteArticleContent}
                                onAddProperty={this.props.onAddProperty}
                                imageBaseUrl={this.props.imageBaseUrl}
                            />
                        </div>
                    }else if(/^content/.test(name)){
                        return <MyArticleDisplayContent 
                            key={index} 
                            content={value}
                            textProps={props}/>
                    }else if (/^image/.test(name)){
                        return <MyArticleImage
                            key={index}
                            classes={{
                                root : classes.marginTop
                            }}
                            profilePictureProps={{
                                title : item.name,
                                imageContainerProps : {
                                    style : {
                                        justifyContent : "flex-start",
                                    }
                                },
                                src : /^http/.test(item.src) ? item.src : imageBaseUrl + item.src,
                            }}
                        />
                    }else {
                        return <MyArticleDisplayHeader 
                            key={index}
                            name={name} value={value}
                            {...this.props.headerProps}
                            textProps={props}/>
                    }
                })}
            </div>
        );
    }
}


_MyArticleDisplay.propTypes = {
    classes : PropTypes.object.isRequired,
    article : PropTypes.object,
    parentArticle : PropTypes.object,
    subArticles : PropTypes.array,
    headerProps : PropTypes.shape(MyArticleDisplayHeader.propTypes),
    onArticleUpdate : PropTypes.func,
    onDeleteArticle : PropTypes.func,
    onAddProperty : PropTypes.func,
    imageBaseUrl : PropTypes.string,
};
export const MyArticleDisplay = withStyles(style)(_MyArticleDisplay);
export {MyArticleDisplay as default}