import { appConstants } from "../constants";
var initialState = {
    screenProgress : false,
    snackbar: {
        open : false,
        variant: '',
        message: ""
    },
    snackDialog : {
        open : false, 
        message : "",
        actions : null
    },
    userId : null,
    userToken : null,
    userType : 1,
}

export const appReducer = (state = initialState, action)=> {
    const {type , payload} = action;
    switch (type) {
        case appConstants.TOOGLE_SCREEN_PROGRESS : 
            return {...state, screenProgress : payload};
        case appConstants.TOGGLE_SNACK_DIALOG : 
            return {...state, snackDialog: payload}
        case appConstants.SNACKBAR_OPEN : 
            return {...state, snackbar : payload};
        case appConstants.SNACKBAR_CLOSE : 
            return {...state, snackbar : {...state.snackbar, message: '', open: false}};
        default:
            return state;
    }
}