import React, { Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import classNames from 'classnames';
import { Link } from "react-router-dom";
import {withStyles} from '@material-ui/core/styles';
import { AppBar, Toolbar, Typography, IconButton, Hidden, Drawer} from '@material-ui/core';
import { Menu, ArrowBackIos } from '@material-ui/icons';
import { headerStrings } from './strings';
import { MoreOption } from './MoreOption';
import { MyDrawer, drawerWidth } from './Drawer';
import { SubheaderMenu } from './SubheaderMenu';
import { headerActions } from './actions';
import { appActions } from '../../actions';
import { history } from '../../helpers';
const style = theme => ({
    root: {
        backgroundColor : "white",
    },
    root1 : {
        [theme.breakpoints.up("sm")] : {
            marginLeft : drawerWidth
        }
    },
    logo : {
        width : 100,
        height : 100,
        padding : 10,
        margin : 5,
        // boxShadow : "1px 1px 5px " + colors.primary,
    },
    title : {
        // color : colors.primary,
        fontWeight: "bold",
        borderBottom : "dashed"
    }, 
    startButton : {
        [theme.breakpoints.down("xs")] : {
            display : "none",
        }
    },
    menuBottom : {
        display : "none",
        [theme.breakpoints.down("xs")] : {
            display : "block"
        }
    },
    siteMenu : {
        display : "flex",
        justifyContent : "space-around",
        paddingTop : 70,
        fontWeight : "bold"
    },
    linkItem : {
        textDecoration : "none",
        padding : 20,
        "&:hover" : {
            color : "red", 
        }
    },
    paperAnchorDockedLeft : {
        borderRight : "none !important",
    }
})
class _Header extends React.PureComponent{
    constructor(props) {
        super(props);
        this.state = {
            drawerOpen : false
        }
    }
    
    anchoEl = null;
    componentDidMount() {
        if(this.headerContainer) headerActions({
            [headerStrings.offsetHeight] : this.headerContainer.offsetHeight
        })(this.props.dispatch);
    }
    
    handleDrawerToggle(){
        appActions.handleDrawerToggle()(this.props.dispatch);
    }
    handleDrawerToggle = () => {
        this.setState(state => ({...state, drawerOpen: !state.drawerOpen}));
    };
    onMouseLeave(){
        const {
            [headerStrings.subheaderRibbon] : subheaderRibbon
        } = this.props;
        if(subheaderRibbon) headerActions({
            [headerStrings.subheaderRibbon] : false
        })(this.props.dispatch);
    }
    render() { 
        const {
            drawerOpen
        } = this.state;
        let { 
            theme, position, classes, title, logo,
            visible, headerTitle, headerLeft, headerRight, 
            headerRightSecondary, drawer, fullScreen, 
            leftMenuButton, rootProps, useMorePoper,
            site, 
            headerRightComponent : HeaderRightComponent, 
            headerLeftComponent : HeaderLeftComponent,
            [headerStrings.menuItems] : menuItems,
            [headerStrings.drawerHeader] : drawerHeader,
            [headerStrings.headerTitleProps] : headerTitleProps
        } = this.props;
        const {className : rootClassName, ...otherRootProps} = rootProps || {};
        this.menuItems = [menuItems];
        const {backgroundImageDivProps} = this.props.drawerProps || {};
        return (
           <div>
                {visible && 
                <div> 
                    <AppBar
                        ref={e=>this.headerContainer = e}
                        onMouseLeave={this.onMouseLeave.bind(this)}
                        className={classNames(classes.root, rootClassName)} 
                        {...otherRootProps} position={position} color="primary">
                        <Toolbar ref={element => this.anchoEl = element}>
                            {leftMenuButton && drawer && <IconButton 
                            className={!fullScreen || site? classes.menuBottom : ""} onClick={()=>this.handleDrawerToggle()}>
                                <Menu {...this.props.iconProps}/>
                            </IconButton>}
                            {this.props.backButtonAction && <IconButton onClick={()=>{
                                history.goBack();
                                this.props.backButtonAction();
                            }}>
                                <ArrowBackIos 
                                {...headerTitleProps} 
                                {...this.props.iconProps}/>
                            </IconButton>}
                            {HeaderLeftComponent && <HeaderLeftComponent/>}
                            {headerLeft}
                            {logo && <img {...this.props.logoImageProps} className={classes.logo} src={logo}/>}
                            <Typography 
                                className={classes.title} 
                                {...headerTitleProps} 
                                variant="h6">{headerTitle || title}</Typography>
                            <div style={{flexGrow: 1}}/>
                            {headerRightSecondary}
                            {headerRight}
                            {HeaderRightComponent && <HeaderRightComponent/>}
                            {/**if full screen don't hide the menu button (classes.menuBottom) */}
                            {!leftMenuButton && drawer && <IconButton 
                                className={!fullScreen || site? classes.menuBottom : ""} 
                                onClick={()=>this.handleDrawerToggle()}>
                                <Menu {...this.props.iconProps}/>
                            </IconButton>}
                            {useMorePoper && useMorePoper.use && <MoreOption {...useMorePoper}/>}
                        </Toolbar>
                        <SubheaderMenu {...this.props.subheaderMenuProps}/>
                    </AppBar>
                    {drawer && <nav className={classes.drawer} aria-label="mailbox folders">
                        {/* The implementation can be swapped with js to avoid SEO duplication of links. */}
                        <Hidden smUp implementation="css">
                            <Drawer
                                // container={container}
                                PaperProps={{
                                    style :{
                                        background : this.props.drawerProps && this.props.drawerProps.bgColor,
                                        backgroundImage : backgroundImageDivProps && 
                                            `url('${backgroundImageDivProps.imageUrl}') no-repeat center center /cover`
                                    }
                                }}
                                variant="temporary"
                                anchor={theme.direction === 'rtl' ? 'right' : 'left'}
                                open={drawerOpen}
                                onClose={this.handleDrawerToggle.bind(this)}
                                classes={{
                                    paper: classes.drawerPaper,
                                    paperAnchorDockedLeft : classes.paperAnchorDockedLeft,
                                }}
                                ModalProps={{
                                    keepMounted: true, // Better open performance on mobile.
                                }}
                            >
                                <MyDrawer 
                                    drawerHeader={drawerHeader} 
                                    {...this.props.drawerProps} 
                                    lists={this.menuItems}/>
                            </Drawer>
                        </Hidden>
                        {/**if fullscreen then show permanent drawer */}
                        {!fullScreen && <Hidden xsDown implementation="css">
                            <Drawer
                                PaperProps={{
                                    style :{
                                        background : this.props.drawerProps && this.props.drawerProps.bgColor,
                                        backgroundImage : backgroundImageDivProps && 
                                            `url('${backgroundImageDivProps.imageUrl}') no-repeat center center /cover`
                                    }
                                }}
                                classes={{
                                    paper: classes.drawerPaper,
                                    paperAnchorDockedLeft : classes.paperAnchorDockedLeft,
                                }}
                                variant="permanent"
                                open
                            >
                                <MyDrawer 
                                    drawerHeader={drawerHeader}
                                    {...this.props.drawerProps} lists={this.menuItems}/>
                            </Drawer>
                        </Hidden>}
                    </nav>}
                    {site && this.props.showItemMenu && <Fragment>
                        <Hidden xsDown>  
                            <div className={classes.siteMenu} 
                            {...this.props.siteLinkContainerProps}>
                                {this.menuItems && this.menuItems[0] && this.menuItems[0].map((item, index)=>{
                                    return <Link className={classes.linkItem} 
                                        {...this.props.siteLinkProps}
                                        to={item.pathname} key={index}>{item.name}</Link>
                                })}
                            </div>
                        </Hidden>
                        <Hidden smUp>
                            <div style={{
                                height : 50
                            }}/>
                        </Hidden> 
                    </Fragment>
                    }
                </div>}
            </div>
        );
    }
}
_Header.propTypes = {
    classes : PropTypes.object.isRequired,
    visible : PropTypes.bool,
    headerTitle : PropTypes.any,
    headerTitleProps : PropTypes.object,
    headerLeft : PropTypes.any,
    headerRight : PropTypes.any,
    headerRightSecondary : PropTypes.any,
    drawer : PropTypes.bool,
    useMorePoper : PropTypes.object,
    rootProps : PropTypes.object,
    poperList : PropTypes.any,
    siteLinkContainerProps : PropTypes.object,
    siteLinkProps : PropTypes.object,
    title : PropTypes.any,
    site : PropTypes.bool,
    subheaderMenuProps : PropTypes.shape(SubheaderMenu.prototype),
    logoImageProps : PropTypes.object,
};
const mapStateToProps = ({headerReducer}) => ({
    ...headerReducer,
})

export const Header = connect(mapStateToProps)(withStyles(style, {withTheme: true})(_Header));
export {Header as default};