import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { MyTable, MyDialog } from "../../utils";
import { TableCell, IconButton, Popover, FormLabel, Button } from '@material-ui/core';
import { hirSettingStrings, hirSettingActions } from '../../HIRSettings';
import { hirUserStrings } from '../../HIRUsers';
import ReactToPrint from 'react-to-print';
import { HIRReceipt } from '../HIRReceipt/HIRReceipt';
import { HIRReceiptMultiple } from '../HIRReceipt/HIRReceiptMultiple';
import { Edit, Delete } from '@material-ui/icons';
import { appActions, alertAction } from "../../../../actions";
import { hirAccountActions } from '../actions';
import { HIRNewPayment } from '../HIRNewPayment';
import { history } from '../../../../helpers';
import { hirRouteNames } from "../../routeNames";
import exportFromJSON from 'export-from-json';

const style = theme => ({
    root: {
    },
    cell : {
        padding : 5,
        fontSize : 11,
    },
    groupId : {
        fontWeight : "bold",
        "&:hover" :{
            textDecoration : "underline",
        }
    },
    paper : {
        display : 'flex',
        justifyContent : "center",
        alignItems : "center",
    },
    download : {
        fontSize : 12,
        textDecoration : "underline",
        "&:hover" : {
            cursor : "pointer",
        }
    }
})
class _HIRPaymentList extends Component {
    static DELETE = "DELETE";
    state = {
        receiptDialog : false,
        payment : null,
        anchorEl : null,
        editPaymentDialog : false
    }
    componentDidMount() {
        const {
            dispatch, 
            [hirSettingStrings.settings] : settings
        } = this.props
        if(!settings) 
            hirSettingActions.getSettings()(dispatch);
    }
    openMultipleReceiptDialog = payment => e => {
        e.stopPropagation();
        this.setState({receiptDialog : true, multiple : true, payment});
    }
    handleNonPatClick = payment => e => {
        e.stopPropagation();
        const target = e.target;
        this.setState({anchorEl : target, payment})
    }
    deleteNonPatientPayment(e){
        const {payment} = this.state;
        const {dispatch, actionCallback} = this.props;
        this.setState({anchorEl : null});
        appActions.showSnackDialog(
            "Are you sure you want to delete this payment - \nID -"+
            payment._id+" ("+Number(payment.amount).toLocaleString()+")",
            [<Button key="deletePayment" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
                hirAccountActions.deletePayment(payment._id, null, (done, result)=>{
                    if(done){
                        if(actionCallback)
                            actionCallback("delete")
                    }
                })(dispatch);
            }}>Delete</Button>]
        )(dispatch);
    }
    editPayment(data, context){
        const {dispatch, actionCallback} = this.props;
        const {payment} = this.state;
        hirAccountActions.updatePayment(payment._id, {...data, actionDate : payment.actionDate}, (done, result, message)=>{
            context.setState({loading : false});
            if(done){
                this.setState({editPaymentDialog : false});
                if(actionCallback) actionCallback("edit");
            }
        })(dispatch);
    }
    veiwPatient = payment => e => {
        e.stopPropagation();
        history.push(hirRouteNames.patientView_+payment.patientId);
    }
    cellMapFormat = ({row, cellMap}) => {
        const {
            classes, 
            [hirUserStrings.users] : users,
            [hirSettingStrings.settings] : settings,
        } =this.props;
        if(row.lastLine){
            switch(cellMap){
                case "_id" : return <TableCell className={classes.cell}>
                    <strong>Total</strong>
                </TableCell>;
                case "amount" : return <TableCell className={classes.cell}>
                    <strong>{Number(row.total).toLocaleString()}</strong>
                </TableCell> 
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }else{
            switch(cellMap){ 
                case "accountAction" : return <TableCell className={classes.cell}>
                    {row[cellMap] ? (row[cellMap] === "useCredit" ? "Deposit" : "Debt") : "Cash"}
                </TableCell>
                case "by" :  
                    if(row[cellMap] === "NaN") 
                        return <TableCell className={classes.cell}></TableCell>;
                    let staff;
                    if(users){
                        staff = users.find(item=>item._id === row[cellMap]);
                    }
                    return <TableCell className={classes.cell}>
                        {staff && staff.myProfile ? 
                            (staff.myProfile.firstName ? 
                                staff.myProfile.lastName + ", "+ staff.myProfile.firstName :
                                staff.myProfile.lastName) :
                            null }
                </TableCell>
                case "amount" : return <TableCell className={classes.cell}>
                    {Number(row[cellMap]).toLocaleString()}
                </TableCell>
                case "patientId" : return <TableCell className={classes.cell}>
                    {row[cellMap] && String(row[cellMap]).padStart(6, "0")}
                </TableCell>
                case "date" : return <TableCell className={classes.cell}>
                    {new Date(row.actionDate).toLocaleDateString()}
                </TableCell>
                case "_id" : return <TableCell className={classes.cell}>
                    {!row.patientId ? 
                        <u onClick={this.handleNonPatClick(row)}>{String(row[cellMap]).substr(0, 6)}...</u> : 
                        String(row[cellMap]).substr(0, 6)+"..."}
                </TableCell> 
                case "revenueType" : 
                    let value;
                    if(settings){
                        const revenue = settings.find(item=>item.name==="revenue");
                        if(revenue && revenue.values){
                            const revenueObject = revenue.values.find(item=>item.name === row[cellMap]);
                            value = revenueObject && revenueObject.value;
                        }
                    }
                    return <TableCell className={classes.cell}>
                        {value}
                    </TableCell> 
                case "groupId" : return <TableCell className={classes.cell} title={row[cellMap]}>
                    {row[cellMap] && <strong className={classes.groupId} onClick={this.openMultipleReceiptDialog(row)}>
                        {String(row[cellMap]).substr(0, 3)}
                        ...
                        {String(row[cellMap]).substr(row[cellMap].length - 4, 4)}
                    </strong>}
                </TableCell>
                case "name" : return <TableCell className={classes.cell}>
                    {!row.patientId ? 
                        <strong>{row.description}</strong> :
                        <u className={classes.cellName}
                            onClick={this.veiwPatient(row)}>{row[cellMap]}</u>
                    }
                </TableCell>
                default : return <TableCell className={classes.cell}>
                    {row[cellMap]}
                </TableCell>
            }
        }
    }
    tableHeader = ["ID", "PID", "Name", "Amount", "Purpose", "Date", "Method", "Staff", "Group ID"];
    tableDataMap = ["_id", "patientId", "name", "amount","revenueType", "date", "accountAction", "by", "groupId"];
    downloadCVS(data){
        const {
            dispatch, classes,
            [hirUserStrings.users] : users,
            [hirSettingStrings.settings] : settings,
        } = this.props,
        fileName = 'payments',
        exportType = 'csv',
        mainData = []
        if(data) for (let i = 0; i < data.length; i++) {
            const dataObject = data[i],
            mainD = {},
            {myProfile} = dataObject || {}; 
            for (let j = 0; j < this.tableDataMap.length; j++) {
                const mapper = this.tableDataMap[j];
                let value = dataObject[mapper],
                header = this.tableHeader[j];
                if(dataObject.lastLine){
                    switch(mapper){
                        case "_id" : 
                            mainD[header] = "Total"; 
                            break;
                        case "amount" : 
                            mainD[header] = Number(dataObject.total).toLocaleString(); 
                            break;
                        default : 
                            mainD[header] = value
                            break;
                    }
                }else switch(mapper){
                    case "date" : 
                        mainD[header] = value && new Date(value).toLocaleDateString(); 
                        break;
                    case "accountAction" : 
                        mainD[header] = value ? (value === "useCredit" ? "Deposit" : "Debt") : "Cash";
                        break;
                    case "patientId" : 
                        mainD[header] = value && String(value).padStart(6, "0"); 
                        break;
                    // case "groupId" : 
                    //     mainD[header] = 
                    //         value ? String(value).substr(0, 3) + "..." + String(value).substr(value.length - 4, 4) : "";
                    //     braak;
                    case "by" : 
                        if(value === "NaN") 
                            mainD[header] = "";
                        let staff;
                        if(users){
                            staff = users.find(item=>item._id === value);
                        }
                        mainD[header] = staff && staff.myProfile ? 
                                (staff.myProfile.firstName ? 
                                    staff.myProfile.lastName + ", "+ staff.myProfile.firstName :
                                    staff.myProfile.lastName) :
                                null 
                        break;
                    case "revenueType" : 
                        mainD[header] = null;
                        if(settings){
                            const revenue = settings.find(item=>item.name==="revenue");
                            if(revenue && revenue.values){
                                const revenueObject = revenue.values.find(item=>item.name === value);
                                mainD[header] = revenueObject && revenueObject.value;
                            }
                        }
                        break;
                    case "_id" : 
                        mainD[header] = String(value).substr(0, 6)+"..."
                        break;
                    case "amount" : 
                        mainD[header] = new Date(value).toLocaleDateString();
                        break;
                    case "name" : 
                        mainD[header] = !dataObject.patientId ? 
                            dataObject.description : value;
                        break;
                    default: mainD[header] = value; break;
                }
            }
            mainData.push(mainD);
        }
        appActions.showSnackDialog(
            "You are about to download a CSV file. Do you want to continue?",
            [<Button key="downloadCSV" onClick={()=>{
                appActions.closeSnackDialog()(dispatch);
                exportFromJSON({ data : mainData, fileName, exportType })
            }}>Continue</Button>]
        )(dispatch);
    }
    render() {
        const {classes} = this.props;
        const {receiptDialog, payment, multiple, anchorEl, editPaymentDialog} = this.state;
        return (
            <Fragment>
                <div className={classes.root} ref={e=>this.printComponent=e}>
                    <MyTable
                        header={this.tableHeader}
                        dataMap={this.tableDataMap}
                        CellMap={this.cellMapFormat}
                        rowAction={!this.props.parent ? payment=>()=>this.setState({payment, receiptDialog : true}) : null}
                        {...this.props.tableProps}
                        />
                </div>
                <div style={{display : "flex", justifyContent : "space-between"}}>
                    <ReactToPrint 
                        trigger={()=><button>Print</button>}
                        content={()=>this.printComponent}
                    />

                    <a onClick={()=>this.downloadCVS(this.props.tableProps?.data)} className={classes.download}>
                        Download CSV file
                    </a>
                </div>
                <MyDialog 
                    classes={{
                        dialogPaper : classes.paper
                    }}
                    open={receiptDialog}
                    close={()=>this.setState({receiptDialog : false, multiple : false})}>
                        {multiple ? 
                            <HIRReceiptMultiple
                                payment={payment}/> :
                            <HIRReceipt
                                payment={payment}/>}
                </MyDialog>
                {anchorEl && <Popover 
                    open={Boolean(anchorEl)}
                    anchorEl={anchorEl}
                    onClose={()=>this.setState({anchorEl : null})}
                    >
                        <div><FormLabel>{Number(payment.amount).toLocaleString()}</FormLabel></div>
                        <IconButton onClick={()=>this.setState({editPaymentDialog : true, anchorEl : null})} >
                            <Edit fontSize="small"/>
                        </IconButton>
                        <IconButton onClick={this.deleteNonPatientPayment.bind(this)}>
                            <Delete color="secondary" fontSize="small"/>
                        </IconButton>
                    </Popover>}
                <MyDialog
                    open={editPaymentDialog}
                    close={()=>this.setState({editPaymentDialog : false, anchorEl : null})}>
                        <HIRNewPayment
                            editMode={true}
                            editPayment={this.editPayment.bind(this)}
                            paymentData={payment}/>
                    </MyDialog>
            </Fragment>
        );
    }
}


_HIRPaymentList.propTypes = {
    classes : PropTypes.object.isRequired,
    tableProps : PropTypes.shape(MyTable?.propTypes),
    actionCallback : PropTypes.func,
    parent : PropTypes.oneOf(["unit"]),
};

const mapStateToProps = ({hirUserReducer, hirSettingReducer}) => ({
    [hirUserStrings.users] : hirUserReducer[hirUserStrings.users],
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings],
})


export const HIRPaymentList = connect(mapStateToProps)(withStyles(style)(_HIRPaymentList));
export {HIRPaymentList as default}