import { alertConstant, appConstants } from "../constants";

const error = message => ({
    variant : alertConstant.ERROR,
    message
});
const warning = message => ({
    variant : alertConstant.WARNING,
    message
});
const success = message => ({
    variant: alertConstant.SUCCESS,
    message : String(message) ? message : "Back-end/Db error"
})
export const alertAction = {
    error, success, warning,
    toggleSnackDialog : (open, message, actions, callback, displayProps) => dispatch => dispatch({
        type : appConstants.TOGGLE_SNACK_DIALOG,
        payload : {
            open,
            message, 
            actions,
            callback,
            displayProps
        }
    }),
}