import React, { Component } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import { SocialMedia } from './SocialMedia';
const style = theme => ({
    root: {
        marginTop : 15,
        height : "2cm",
        display : "flex",
        justifyContent : "center",
        alignItems : "center",
    }
})
class _Footer extends Component {
    render() {
        const {classes, footerProps} = this.props;
        const {className : rootClassName, ...otherFooterProps} = footerProps;
        return (
            <div 
                className={classNames(classes.root, rootClassName)}
                {...otherFooterProps}>
                <SocialMedia
                    {...this.props.socialMediaProps}/>
            </div>
        );
    }
}
_Footer.propTypes = {
    classes : PropTypes.object.isRequired,
    footerProps : PropTypes.object,
    socialMediaProps : PropTypes.shape(
        SocialMedia.propTypes
    ),
};
export const Footer = withStyles(style)(_Footer);