import { hirUserConstant, hirUserStrings } from "./config";
import { hirUserServices } from "./services";
import { errorNotice, successNotice } from "../../../utils";
import { store } from "../../../helpers";

export const hirUserActions = {
    getDebtors : (filter, rows, skip, sort, max, callback) => dispatch => {
        hirUserServices.getDebtors(filter, rows, skip, sort, max, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getDebtorMinMaxIds : (filter, sort, callback) => dispatch => {
        hirUserServices.getDebtorMinMaxIds(filter, sort, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    searchDebtors : (filter, keyword, rows, skip, sort, max, callback) => dispatch => {
        hirUserServices.searchDebtors(filter, keyword, rows, skip, sort, max, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getSearchDebtorMinMaxIds : (filter, keyword, sort, callback) => dispatch => {
        hirUserServices.getSearchDebtorMinMaxIds(filter, keyword, sort, (done, result, message)=>{
            if(!done) errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    searchUser : (keyword, callback) => dispatch => {
        hirUserServices.searchUser(keyword, (done, result, message)=>{
            if(done){
                hirUserActions.payload({
                    [hirUserStrings.users] : result
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    updateProfile : (userId, profile, callback) => dispatch => {
        hirUserServices.updateProfile(userId, profile, (done, result, message)=>{
            if(done){
                hirUserActions.getUsers()(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    activateUser : (id, callback) => dispatch =>{
        hirUserServices.activateUser(id, (done, result, message)=>{
            if(done){
                successNotice(message, dispatch);
                const users = store.getState().hirUserReducer[hirUserStrings.users];
                if(users){
                    hirUserActions.payload({
                        [hirUserStrings.users] : users.map(item=>{
                            if(item._id === result._id) return result;
                            return item;
                        })
                    })(dispatch);
                }
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        });
    },
    suspendUser : (id, callback) => dispatch =>{
        hirUserServices.suspendUser(id, (done, result, message)=>{
            if(done){
                successNotice(message, dispatch);
                const users = store.getState().hirUserReducer[hirUserStrings.users];
                if(users){
                    hirUserActions.payload({
                        [hirUserStrings.users] : users.map(item=>{
                            if(item._id === result._id) return result;
                            return item;
                        })
                    })(dispatch);
                }
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        });
    },
    archiveUser : (id, callback)=> dispatch =>{
        hirUserServices.archiveUser(id, (done, result, message)=>{
            if(done){
                successNotice(message, dispatch);
                const users = store.getState().hirUserReducer[hirUserStrings.users];
                if(users){
                    const userIndex = users.findIndex(item => item._id === id);
                    users.splice(userIndex, 1);
                    hirUserActions.payload({
                        [hirUserStrings.users] : users
                    })(dispatch);
                }
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        });
    },
    createUser : (data, callback) =>dispatch => {
        /**
         * general admin = 00
         * hir adming = 10
         * hir manager = 11
         * hir users = 12
         */
        hirUserServices.createUser(data, (done, result, message)=>{
            if(done){
                hirUserActions.payload({
                    [hirUserStrings.users] : result
                })(dispatch);
                successNotice(message, dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    getUsers : callback => dispatch => {
        hirUserServices.getUsers((done, result, message)=>{
            if(done){
                result.push({_id : 1, myProfile : {lastName : "Record", firstName : "Admin"}})
                hirUserActions.payload({
                    [hirUserStrings.users] : result
                })(dispatch);
            }else errorNotice(message, dispatch);
            if(callback) callback(done, result, message);
        })
    },
    payload : payload => dispatch =>dispatch({
        type : hirUserConstant.SET_HIR_USER,
        payload
    })
}