import { mainStageHeaderStrings, mainStageHeaderConstants } from "./constants";

export const initialState = {
    [mainStageHeaderStrings.buttons] : null,
    [mainStageHeaderStrings.searchActions] : null,
    [mainStageHeaderStrings.components] : null
}
export const mainStageHeaderReducer = (state=initialState, action) =>{
    const {type, payload} = action;
    switch(type){
        case mainStageHeaderConstants.SET_MAIN_STAGE_HEADER : 
            return {...state, ...payload};
        default : return {...state};
    }
}