export const hirSettingStrings = {
    settings : "settings",
}
export const hirSettingConstants = {
    SET_SETTING : "SET_SETTING",
}
export const hirSettingReducer = (state={}, action)=>{
    const {type, payload} = action;
    switch(type){
        case hirSettingConstants.SET_SETTING : 
            return {...state, ...payload};
        default : return state;
    }
}