import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import { withStyles } from '@material-ui/core';

const style = theme => ({

})
class _ReduxValue extends Component {
    render() {
        const {state, reducerString, reducer, preAction} = this.props;
        if(!reducer) throw("Use must specify a reducer");
        return preAction ? 
            preAction(state[reducer] && state[reducer][reducerString]) : 
            state[reducer] && state[reducer][reducerString];
    }
}


_ReduxValue.propTypes = {
    classes : PropTypes.object.isRequired,
    reducer : PropTypes.string,
    reducerString : PropTypes.string,
    preAction : PropTypes.func,
};
const mapStateToProps = state => ({
    state
})


export const ReduxValue = connect(mapStateToProps)(withStyles(style)(_ReduxValue));
export {ReduxValue as default}