import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import classNames from 'classnames';
import { Button, colors, CircularProgress } from '@material-ui/core';
import { hirUtil } from '../../../utils';
const style = theme => ({
    root: {
        
    }, 
    btn : {
        backgroundColor : hirUtil.getTheme().primaryDark,
        borderRadius : 20,
        color : hirUtil.getTheme().white,
        textTransform : "capitalize",
        "&:hover" : {
            backgroundColor : hirUtil.getTheme().primaryDark,
        }
    },
    primary : {
        backgroundColor : hirUtil.getTheme().primaryDark,
        "&:hover" : {
            backgroundColor : hirUtil.getTheme().primaryDark,
        }
    },
    secondary : {
        backgroundColor : hirUtil.getTheme().secondary,
        "&:hover" : {
            backgroundColor : hirUtil.getTheme().secondary,
        }
    },
    highlight : {
        backgroundColor : hirUtil.getTheme().highlight,
        "&:hover" : {
            backgroundColor : hirUtil.getTheme().highlight,            
        }
    },
    cancel : {
        backgroundColor : hirUtil.getTheme().appGray,
        "&:hover" : {
            backgroundColor : hirUtil.getTheme().appGray,
        }
    },
    progress : {
        height : 20,
        width : 20,
        color : "white",
    }
})
class _HIRButton extends Component {
    render() {
        const {classes, type, loading, children, ...props} = this.props;
        return <Button disabled={loading} className={classNames(classes.btn, classes[type])} {...props}>
            {loading && <CircularProgress style={{
                width : 20,
                height : 20
            }} className={classes.progress}/>}
            {children}
        </Button>
    }
}
_HIRButton.propTypes = {
    classes : PropTypes.object.isRequired,
    loading : PropTypes.bool,
    type : PropTypes.oneOf(["primary", "secondary", "cancel", "highlight"]),
};
export const HIRButton = withStyles(style)(_HIRButton);