import { useDispatch, useSelector } from 'react-redux'
import { FormLabel, Grid, makeStyles } from '@material-ui/core'
import { hirDashboardStrings } from '../config'
import { hirUtil, monthLabels, MyChart } from '../../utils'
import { CountBox } from '../CountBox'
import ReactToPrint from 'react-to-print'
import { HIRDashboardCountBox } from '../HIRDashboardCountBox'
import { useEffect, useState } from 'react'
import { hirAccountActions } from '../../HIRAccounts'
const style = makeStyles(theme => ({
    root : {
    }, 
    gridContainer : {
        marginTop : 20,
        marginBottom : 10,
    },
}))
function HIRDashboardRevenue(props) {
    let printComponentRevenue;
    const classes = style(),
    dispatch = useDispatch(),
    hirDashboardReducer = useSelector(state => state["hirDashboardReducer"]),
    {
        [hirDashboardStrings.paymentMonthDayData] : paymentMonthDay,
        [hirDashboardStrings.paymentYearMonthData] : paymentYearMonth,

        [hirDashboardStrings.paymentDayTotalAmount] : paymentDayTotalAmount,
        [hirDashboardStrings.paymentMonthTotalAmount] : paymentMonthTotalAmount,
        [hirDashboardStrings.paymentYearTotalAmount] : paymentYearTotalAmount,

    } = hirDashboardReducer,
    date = new Date();
    const [state, _setState] = useState({
        depositToday : 0, depositMonth : 0, depositYear : 0
    }),
    {depositToday, depositMonth, depositYear} = state,
    setState = _state => _setState(state=>({...state, ..._state}));
    useEffect(() => {
        (async () => {
            const result = await Promise.all([
                getDepositGroup({date}),
                getDepositGroup({date, monthOnly : true}),
                getDepositGroup({date,yearOnly : true}),
            ]);
            const depositToday = result[0]?.[0]?.amount || 0;
            const depositMonth = result[1]?.[0]?.amount || 0;
            const depositYear = result[2]?.[0]?.amount || 0;
            setState({depositToday, depositMonth, depositYear});
        })();
    }, []);
    const getDepositGroup = (filter) => {
        return new Promise((resolve, reject) => {
            hirAccountActions.getDepositGroup(filter, null, (done, result, message)=>done ? resolve(result) : reject(message))(dispatch)
        });
    },
    deriveMonthlyData = (data, valueName) => {
        const returnData = [];
        if(data) for (let i = 0; i < monthLabels.length; i++) {
            const value = data.find(item=>item._id.month==i+1);
            if(value){
                returnData.push(value[valueName]);
            }else returnData.push(0);
        }
        return returnData;
    },
    generateSequence = (end) => {
        const returnData =[];
        for (let i = 0; i < end; i++) {
            returnData.push(i+1)
        }
        return returnData;
    },
    deriveDay = (data, valueName) => {
        const returnData = [];
        if(data) for (let i = 0; i < 31; i++) {
            const value = data.find(item=>item._id.day === i+1)
            if(value) returnData.push(value[valueName]);
            else returnData.push(0);
        }
        return returnData;
    },
    filterActions = (paymentsArray) => {
        let cashPayments = [], debitPayments = [], creditPayments = [];
        if(paymentsArray) for (let i = 0; i < paymentsArray.length; i++) {
            const {_id : {accountAction}} = paymentsArray[i];
            switch(accountAction){
                case "addToDebt" : debitPayments.push(paymentsArray[i]); break;
                case "useCredit" : creditPayments.push(paymentsArray[i]); break;
                default : cashPayments.push(paymentsArray[i]); break;
            }
        }
        return [
            {
                label : 'Cash', data : cashPayments, 
                backgroundColor : hirUtil.getTheme().successTrans,
                borderColor : hirUtil.getTheme().success,
            },
            {
                label : 'Credit', data : creditPayments,
                backgroundColor : hirUtil.getTheme().primaryTrans, 
                borderColor : hirUtil.getTheme().primary
            },
            {
                label : 'Debit', data : debitPayments,
                backgroundColor : hirUtil.getTheme().secondaryTrans,
                borderColor : hirUtil.getTheme().secondary,
            },
        ]
    }
    return (
        <div>
            <div className={classes.gridContainer} ref={e=>printComponentRevenue=e}>
                <FormLabel className={classes.label}>Revenue</FormLabel>
                <Grid container spacing={4}>
                    {hirUtil.isAdmin() && <Grid item xs={6} sm={6} md={4} lg={4} xl={4}>
                        <HIRDashboardCountBox
                            color="#9e9e9e"
                            header={"This Year - ("+new Date().getFullYear()+")"}
                            data={ paymentYearTotalAmount}
                            deposit={depositYear}
                        />
                    </Grid>}
                    <Grid item xs={6} sm={6} md={4} lg={4} xl={4}>
                        <HIRDashboardCountBox
                            header={monthLabels[new Date().getMonth()]+", "+new Date().getFullYear()}
                            data={ paymentMonthTotalAmount }
                            deposit={depositMonth}
                        />
                    </Grid>
                    <Grid item xs={6} sm={6} md={4} lg={4} xl={4}>
                        <HIRDashboardCountBox
                            color="#607d8b"
                            header="Today"
                            data={ paymentDayTotalAmount }
                            deposit={depositToday}
                        />
                    </Grid>
                </Grid>
                <Grid container spacing={2}>
                    <Grid item xs={12} sm={12} md={12} lg={12} xl={12}>
                        <MyChart
                            canvasId="paymentMonthDay"
                            title={"Revenue for " + monthLabels[date.getMonth()] + " ("+date.getFullYear()+")"}
                            labels={generateSequence(31)}
                            datasets={[...filterActions(paymentMonthDay).map(item=>({...item, data : deriveDay(item.data, "amount")}))]}
                        />
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <MyChart
                            canvasId="paymentYearMonth"
                            title={"Monthly Revenue " + new Date().getFullYear()+" (line)"}
                            labels={monthLabels}
                            datasets={[...filterActions(paymentYearMonth).map(item=>({...item, data : deriveMonthlyData(item.data, "amount")}))
                                /* {
                                label: 'Total amount :',
                                data : deriveMonthlyData(paymentYearMonth, "amount"),                                
                                backgroundColor : hirUtil.getTheme().primaryTrans,
                                borderColor : hirUtil.getTheme().primary,
                            } */]}
                        />
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <MyChart
                            canvasId="paymentYearMonth2"
                            type="pie"
                            title={"Monthly Revenue " + new Date().getFullYear()+" (pie)"}
                            labels={monthLabels}
                            datasets={[...filterActions(paymentYearMonth).map(item=>({
                                    ...item, data : deriveMonthlyData(item.data, "amount"),
                                    backgroundColor : [
                                        "red", "#673AB7", "blue", "orange", "lightblue", "orange",
                                        "gold", "black", "brown", "pink", "red", "coral"
                                    ],
                                    borderColor : [
                                        "red", "#673AB7", "blue", "orange", "lightblue", "orange",
                                        "gold", "black", "brown", "pink", "red", "coral"
                                    ]
                                }))]}
                        />
                    </Grid>
                </Grid>
            </div>
            <ReactToPrint 
                trigger={()=><button>Print</button>}
                content={()=>printComponentRevenue}
            />
        </div>
                
    )
}
HIRDashboardRevenue.propTypes = {
    
}
export default HIRDashboardRevenue;
export {HIRDashboardRevenue};