import { hirUtil } from "../utils"

const {post, fetchGet} = hirUtil || {};
const owner = "1";
export const hirAppointmentServices = {
    getMultiplePatientYearlyAppointments : (patientIds, year, callback) =>{
        post({patientIds, year}, owner, "getMultiplePatientYearlyAppointments", ({getMultiplePatientYearlyAppointments, result, message})=>{
            callback(getMultiplePatientYearlyAppointments, result, message);
        })
    },
    getPatientYearlyAppointments : (patientId, year, callback) => {
        fetchGet(owner, "getPatientYearlyAppointments", {patientId, year}, ({getPatientYearlyAppointments, result, message})=>{
            callback(getPatientYearlyAppointments, result, message);
        })
    },
    deleteAppointment : (appointId, callback) => {
        fetchGet(owner, "deleteAppointment", {appointId}, ({deleteAppointment, result, message})=>{
            callback(deleteAppointment, result, message);
        })
    },
    getAnAppointment : (appointId, callback ) => {
        fetchGet(owner, "getAnAppointment", {appointId}, ({getAnAppointment, result, message})=>{
            callback(getAnAppointment, result, message);
        })
    },
    unApproveAppointment : (appointId, callback) => {
        fetchGet(owner, "unApproveAppointment", {appointId}, ({unApproveAppointment, result, message})=>{
            callback(unApproveAppointment, result, message);
        })
    },
    approveAppointment : (appointId, callback) => {
        fetchGet(owner, "approveAppointment", {appointId}, ({approveAppointment, result, message})=>{
            callback(approveAppointment, result, message);
        })
    },
    searchAppointmentsByDate : (date, callback)=>{
        fetchGet(owner, "searchAppointmentsByDate", {date}, ({searchAppointmentsByDate, result, message})=>{
            callback(searchAppointmentsByDate, result, message);
        })
    }, 
    searchAppointments : (keyword, callback) => {
        fetchGet(owner, "searchAppointments", {keyword}, ({searchAppointments, result, message})=>{
            callback(searchAppointments, result, message);
        })
    },
    bookAppointment : (data, callback) => {
        data.date = new Date(data.date);
        post(data, owner, "bookAppointment", ({bookAppointment, result, message})=>{
            callback(bookAppointment, result, message);
        });
    },
    getTodayAppointments : callback => {
        fetchGet(owner, "getTodayAppointments", {}, ({getTodayAppointments, result, message})=>{
            callback(getTodayAppointments, result, message);
        })
    }, 
    getAppointments : (lastId, rows, skip, callback) => {
        fetchGet(owner, "getAppointments", {lastId, rows, skip}, ({getAppointments, result, message})=>{
            callback(getAppointments, result, message);
        })
    },
    getMaxMinAppointmentIds : callback => {
        fetchGet(owner, "getMaxMinAppointmentIds", {}, ({getMaxMinAppointmentIds, minId, maxId, message})=>{
            callback(getMaxMinAppointmentIds, minId, maxId, message);
        })
    }
}