import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { 
    FormGroup, Grid, Typography, FormLabel,
} from '@material-ui/core';
import { hookStateVisibility } from './functions';
import InputFields from './InputFields/InputFields';
import { InfoText } from '../../MyText';
import { formStrings } from '../config';

const style = theme => ({
    root: {
        padding : 10
    },
    texfField : {

    },
    header : {
        marginBottom : 50,
    }
})
class _FormDisplay extends Component {
    constructor(props) {
        super(props);
        this.state = {
            dataUnusable : {},
            data : {},
            loading : false
        }
        this.inputFieldContexes = {};

        if(this.props.getContext) 
            this.props.getContext(this);
    }
    static collectedData = false;
    static getDerivedStateFromProps(nextProps, prevState) {
        if(nextProps.formData){
            if(JSON.stringify(nextProps.formData) !==
            JSON.stringify(prevState.dataUnusable)){
                prevState.data = nextProps.formData;
                prevState.dataUnusable = prevState.data;
            }
        }else if(nextProps.formConfig && !prevState.data){
            prevState.data = {};
            for (const i in nextProps.formConfig) {
                if (nextProps.formConfig.hasOwnProperty(i)) {
                    const data = nextProps.formConfig[i];
                    if(data.category){
                        for (let j = 0; j < data.details.length; j++) {
                            const item = data.details[j];
                            prevState.data[item.name] = "";
                        }
                    }
                    else prevState.data[data.name] = "";
                }
            }
            prevState.dataUnusable = prevState.data;
        }
        return prevState;
    }
    componentWillUnmount(){
        FormDisplay.collectedData = false;
    }
    onTextChange = name => e => {
        // const data = {...this.state.data};
        // data[name] = e.target.value;
        // this.setState({data});
    }
    handleChecked = name => e => {
        /** having value in checkbox and switch give error */
        // const data = {...this.state.data};
        // data[name] = e.target.checked;
        // this.setState({data});
    }
    getFieldContext = (name, context) => {
        this.inputFieldContexes[name] = context;
    }
    render() {
        const {
            classes, header, footer : Footer, 
            formConfig, data : notUsedData, 
            [formStrings.forms] : forms,
            ...otherProps
        } = this.props;

        const {data} = this.state;
        return (
            <div className={classes.root}>
                {header && <Typography 
                    paragraph 
                    className={classes.header}
                    {...this.props.headerTypographyProps}
                    >{header}</Typography>}                
                {this.props.controller && <InfoText>Spacing is not allowed for field name</InfoText>}
                {this.props.useGrid ? 
                    <Grid container {...this.props.containerProps}>
                        {formConfig && formConfig.map((element, index)=>{
                            if(
                                this.props.inputFieldProps &&
                                this.props.inputFieldProps.data
                            ) throw("Invalid prop passed to InputField ---DATA, data is set by state");
                            if(this.props.hooks && this.props.hooks[element.name] && 
                                this.props.hooks[element.name].visibility){
                                    const visibility = this.props.hooks[element.name].visibility;
                                if(!hookStateVisibility(
                                    visibility,
                                    forms && forms[this.props.formName]
                                )) return;
                            }
                            //others = type, label, placeholder, value, 
                            if(element.category){
                                return <Grid item key={index}>
                                    <FormLabel style={{fontSize : 14, margin : "20px 0px"}}>{element.category}</FormLabel>
                                    <div style={{marginTop : 20}}/>
                                    <Grid container spacing={2}>
                                        {element.details && element.details.map((field, index)=>{
                                            let hook;
                                            const hookOptions = {};
                                            //emcapsulate this in a function
                                            if(this.props.hooks && this.props.hooks[field.name]){
                                                hook = this.props.hooks[field.name];
                                                if(hook.foreignOnChangeMap){
                                                    const {name} = hook.foreignOnChangeMap && 
                                                    hook.foreignOnChangeMap.variables &&
                                                    hook.foreignOnChangeMap.variables.state || {}
                                                    if(name){
                                                        const foreignItem = element.details.find(item=>item.name===name);
                                                        hookOptions.foreignItem = foreignItem;
                                                    }
                                                }
                                            }
                                            return <Grid item {...this.props.gridItemProps} key={index}>
                                                <InputFields 
                                                    value={this.props.formData ? this.props.formData[field.name] : ""}
                                                    getContext={this.getFieldContext.bind(this)}
                                                    key={index}
                                                    {...this.props.inputFieldProps}
                                                    data={data}
                                                    element={field}
                                                    hooks={hook}
                                                    hookOptions={hookOptions}
                                                    formName={this.props.formName}
                                                    controller={this.props.controller}
                                                />
                                            </Grid>
                                        })}
                                    </Grid>
                                </Grid>
                            }else {
                                let hook;
                                const hookOptions = {};
                                if(this.props.hooks && this.props.hooks[element.name]){
                                    hook = this.props.hooks[element.name];
                                    if(hook.foreignOnChangeMap){
                                        const {name} = hook.foreignOnChangeMap && 
                                        hook.foreignOnChangeMap.variables &&
                                        hook.foreignOnChangeMap.variables.state || {}
                                        if(name){
                                            const foreignItem = formConfig.find(item=>item.name===name);
                                            hookOptions.foreignItem = foreignItem;
                                        }
                                    }
                                }
                                return <Grid item key={index} {...this.props.gridItemProps}>
                                    <InputFields 
                                        getContext={this.getFieldContext.bind(this)}
                                        value={this.props.formData ? this.props.formData[element.name] : ""}
                                        {...this.props.inputFieldProps}
                                        data={data}
                                        element={element}
                                        hooks={hook}
                                        formName={this.props.formName}
                                        controller={this.props.controller}
                                        />
                                    </Grid>
                            }
                        })}
                    </Grid>                
                : <FormGroup {...this.props.containerProps}>
                    {formConfig && formConfig.map((element, index)=>{
                        if(
                            this.props.inputFieldProps &&
                            this.props.inputFieldProps.data
                        ) throw("Invalid prop passed to InputField ---DATA, data is set by state");
                        if(this.props.hooks && this.props.hooks[element.name] && 
                            this.props.hooks[element.name].visibility){
                                const visibility = this.props.hooks[element.name].visibility;
                            if(!hookStateVisibility(
                                visibility,
                                forms && forms[this.props.formName]
                            )) return;
                        }
                        //others = type, label, placeholder, value, 
                        if(element.category){
                            return <Fragment
                                key={index}>
                                <FormLabel style={{margin : "20px 0px"}}>{element.category}</FormLabel>
                                {element.details && element.details.map((field, index)=>{
                                    let hook;
                                    const hookOptions = {};
                                    //emcapsulate this in a function
                                    if(this.props.hooks && this.props.hooks[field.name]){
                                        hook = this.props.hooks[field.name];
                                        if(hook.foreignOnChangeMap){
                                            const {name} = hook.foreignOnChangeMap && 
                                            hook.foreignOnChangeMap.variables &&
                                            hook.foreignOnChangeMap.variables.state || {}
                                            if(name){
                                                const foreignItem = element.details.find(item=>item.name===name);
                                                hookOptions.foreignItem = foreignItem;
                                            }
                                        }
                                    }
                                    return <InputFields 
                                        value={this.props.formData ? this.props.formData[field.name] : ""}
                                        getContext={this.getFieldContext.bind(this)}
                                        key={index}
                                        {...this.props.inputFieldProps}
                                        data={data}
                                        element={field}
                                        hooks={hook}
                                        hookOptions={hookOptions}
                                        formName={this.props.formName}
                                        controller={this.props.controller}
                                        />
                                })}
                            </Fragment>
                        }else {
                            let hook;
                            const hookOptions = {};
                            if(this.props.hooks && this.props.hooks[element.name]){
                                hook = this.props.hooks[element.name];
                                if(hook.foreignOnChangeMap){
                                    const {name} = hook.foreignOnChangeMap && 
                                    hook.foreignOnChangeMap.variables &&
                                    hook.foreignOnChangeMap.variables.state || {}
                                    if(name){
                                        const foreignItem = formConfig.find(item=>item.name===name);
                                        hookOptions.foreignItem = foreignItem;
                                    }
                                }
                            }
                            return <InputFields 
                            getContext={this.getFieldContext.bind(this)}
                            value={this.props.formData ? this.props.formData[element.name] : ""}
                            key={index}
                            {...this.props.inputFieldProps}
                            data={data}
                            hookOptions={hookOptions}
                            element={element}
                            hooks={hook}
                            formName={this.props.formName}
                            controller={this.props.controller}
                            />
                        }
                    })}
                </FormGroup>}
                {Footer && <Footer context={this}/>}
            </div>
        );
    }
}
_FormDisplay.propTypes = {
    classes : PropTypes.object.isRequired,

    formName : PropTypes.string.isRequired,

    header : PropTypes.string,
    headerTypographyProps : PropTypes.object,
    footer : PropTypes.any,

    inputFieldProps : PropTypes.shape(
        InputFields.propTypes
    ), 
    fieldDescriptionProps : PropTypes.object,
    containerProps : PropTypes.object,

    formConfig : PropTypes.array,
    formData : PropTypes.object,
    getContext : PropTypes.func,

    useGrid : PropTypes.bool,
    gridItemProps : PropTypes.object,

    mergeDescriptions : PropTypes.bool,
    descriptionPosition : PropTypes.oneOf(["top", "bottom"]),

    hooks : PropTypes.object,
    controller : PropTypes.bool,
};
const mapStateToProps = ({formReducer}) => ({
    [formStrings.forms] : formReducer[formStrings.forms],
})
export const FormDisplay = connect(mapStateToProps)(withStyles(style)(_FormDisplay));