import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';

import { headerActions, headerStrings, StageHeaderPlane, MyDialog, breadCrumbActions, SimplePagination, MyTable } from '../utils';
import { IconButton, CircularProgress, TableCell } from '@material-ui/core';
import { HIRButton } from '../Includes/Buttons';
import { hirRouteNames } from '../routeNames';
import { Refresh, Edit } from '@material-ui/icons';
import { hirUtil } from '../utils';
import { hirFamilyActions } from './actions';
import { hirFamilyStrings } from './config';
import { HIRNewFamily } from './HIRNewFamily';


const style = () => ({
    root: {
    },
    pageBtn : {
        textTransform : "lowercase",
        fontSize : 11,
        padding : 10,
        borderRadius : 20,
    },
    pagePrevBtn : {
        backgroundColor : hirUtil.getTheme().secondary
    },
    pageNextBtn : {
        backgroundColor : hirUtil.getTheme().primary,
    },
    cell : {
        padding : 5,
        fontSize : 11,
    },
    editIcon : {
        color : "white", 
        borderRadius : "100%", 
        background : "gray",
        boxShadow : "1px 1px 5px grey",
        "&:hover" : {
            boxShadow : "1px 1px 5px white",
        }
    }
})
class _HIRFamilies extends Component {
    constructor(props) {
        super(props);
        this.state = {
            refreshing : false,
            loading : false,
            newFamilyDialog : false,
            rows : 1, 
            skip : 0,
            maxId : null,
            minId : null,
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "FAMILY RECORDS",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", pathname : hirRouteNames.dashboard},
            {name : "Family Records", pathname : hirRouteNames.families},
        ])(dispatch);
    }
    componentDidMount() {
        this.getMinMaxIds();
        this.getFamilies(true);
    }
    getMinMaxIds(){
        hirFamilyActions.getFamilyMinMaxIds_NO_DISPATCH((done, {minId, maxId})=>{
            if(done) this.setState({minId, maxId});
        })
    }
    getFamilies(start, nav){
        const {dispatch} = this.props;
        const {rows, skip} = this.state;
        let newSkip;
        if(start){
            newSkip = 0;
        }else{
            const prevSkip = skip - rows;
            const nextSkip = skip + rows;
            newSkip = nav === "backward" ? prevSkip : nextSkip
        }
        hirFamilyActions.getFamilies(
            rows, 
            newSkip, 
            (done, result)=>{
                if(done){
                    this.setState({skip : newSkip, refreshing : false})
                    this.configurePagination(result);
                }
        })(dispatch);
    }
    configurePagination(result){
        if(result.length !== 0){
            const newLastId = result[result.length - 1]._id;
            const newFirstId = result[0]._id;
            this.setState({lastId : newLastId, firstId : newFirstId})
        }
    }
    newButton = () => {
        return <HIRButton
            type="primary" 
            onClick={()=>this.setState({newFamilyDialog : true})}>
                New family
            </HIRButton>
    }
    refreshButton = () => {
        const {refreshing} = this.state;
        return <IconButton 
            disabled={refreshing}
            onClick={this.refresh.bind(this)}>
            {refreshing ? <CircularProgress style={{width : 25, height : 25}}/> : <Refresh/>}
        </IconButton>
    }
    searchOnChangeCallback=keyword=>{
        if(!String(keyword).trim()){
            this.refresh();
        }
    }
    searchAction = () => {

    }
    refresh(){
        this.setState({refreshing : true, search : false});
        this.getMinMaxIds();
        this.getFamilies(true, null, ()=>this.setState({refreshing : false}));
    }
    editDialogOpen = family => e => {
        e.stopPropagation();
        this.setState({newFamilyDialog : true, family, editMode : true});
    }
    cellMapFormat = ({row, cellMap}) => {
        const {classes} = this.props;
        switch(cellMap){
            case "action" : return <TableCell className={classes.cell}>
                <Edit fontSize="small" className={classes.editIcon} onClick={this.editDialogOpen(row)}/>
            </TableCell>
            case "members" : return <TableCell className={classes.cell}>
                {row[cellMap] && row[cellMap].length}
            </TableCell>
            case "createdDate" : return <TableCell className={classes.cell}>
                {row[cellMap] && new Date(row[cellMap]).toDateString()}
            </TableCell>
            case "_id" : return <TableCell className={classes.cell}>
                {String(row[cellMap]).padStart(6, "0")}
            </TableCell>
            default : return <TableCell className={classes.cell}>
                {row[cellMap]}
            </TableCell>
        }
    }
    createFamilyRecord(data, context){
        const {dispatch} = this.props;
        hirFamilyActions.createFamilyRecord(data, (done, result)=>{
            context.setState({loading :false})
            if(done){
                this.props.history.push({pathname : hirRouteNames.familiesView_+result._id, state : result});
            }
        })(dispatch);
    }
    editFamilyRecord(data, context){
        const {dispatch} = this.props;
        const {family} = this.state;
        hirFamilyActions.editFamilyRecord(family._id, data, (done)=>{
            if(done){
                this.setState({newFamilyDialog : false, family : null, editMode : false});
                this.refresh();
            }else context.setState({loading : false});
        })(dispatch);
    }
    pageNextBtnClick(){
        this.getFamilies(false);
    }
    pagePrevBtnClick(){
        this.getFamilies(false, "backward");
    }
    rowAction = row => ()=> {
        this.props.history.push({pathname : hirRouteNames.familiesView_+row._id, state : row});
    }
    render() {
        const {classes, [hirFamilyStrings.families] : families} = this.props;
        const {newFamilyDialog, lastId, minId, skip, rows} = this.state;
        return (
            <div className={classes.root}>
                <div style={{marginBottom : 20}}>
                    <StageHeaderPlane
                        isRequired={false}
                        visible={true}
                        onChangeCallback={this.searchOnChangeCallback.bind(this)}
                        searchActions={this.searchAction.bind(this)}
                        components={[
                            this.refreshButton.bind(this),
                            this.newButton.bind(this)
                        ]}
                        />
                </div>
                <MyTable
                    header={["ID", "Family Name", "Members", "Date", "Action"]}
                    dataMap={["_id", "name", "members", "createdDate", "action"]}
                    CellMap={this.cellMapFormat.bind(this)}
                    rowAction={this.rowAction.bind(this)}
                    data={families}
                    />
                <SimplePagination
                        classes={{
                            btn : classes.pageBtn,
                            prevBtn : classes.pagePrevBtn,
                            nextBtn : classes.pageNextBtn,
                            root : classes.pageRoot
                        }}
                        prevBtnProps={{
                            disabled : skip === 0
                        }}
                        nextBtnProps={{
                            disabled : !families || families.length < rows || minId === lastId
                        }}
                        prevBtnClick={this.pagePrevBtnClick.bind(this)}
                        nextBtnClick={this.pageNextBtnClick.bind(this)}/>
                <MyDialog
                    open={newFamilyDialog}
                    close={()=>this.setState({
                        newFamilyDialog : false, loading : false,
                        editMode : false, family : null
                        })}>
                        <HIRNewFamily
                            editMode={this.state.editMode}
                            data={this.state.family}
                            editRecord={this.editFamilyRecord.bind(this)}
                            createRecord={this.createFamilyRecord.bind(this)}/>
                    </MyDialog>
            </div>
        );
    }
}


_HIRFamilies.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({hirFamilyReducer}) => ({
    [hirFamilyStrings.families] : hirFamilyReducer[hirFamilyStrings.families],
})


export const HIRFamilies = connect(mapStateToProps)(withStyles(style)(_HIRFamilies));
export {HIRFamilies as default}