import React, { PureComponent, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {Button, Snackbar} from '@material-ui/core';
import SnackbarContent from '@material-ui/core/SnackbarContent';
import {withStyles} from '@material-ui/core/styles';
import { colors } from '../../utils';
import { appActions } from '../../actions';
const dialogStyle = theme=>({
    root : {
        backgroundColor : colors.appRed,
        color : "white",
    },
    closeButton : {
        color : "white",
        border : "solid 1px white",
    },
    overlay : {
        position : "fixed",
        zIndex : 1,
        width : "100vw",
        backgroundColor : colors.grayTrans,
        height :"100vh",
        top :0
    }
})
class _SnackDialog extends PureComponent{
    constructor(props) {
        super(props);
        this.closeDialog = this.closeDialog.bind(this);
    }
    
    closeDialog(){
        appActions.closeSnackDialog()(this.props.dispatch);
    }
    defaultButton = props =>{
        const {className, callback} = props;
        return <Button 
            key={"454xfres"}
            className={className} 
            variant="outlined"
            onClick={()=>{
                this.closeDialog();
                if(callback) callback();
            }}>Close</Button>;
    }
    render(){
        const {classes, snackDialog} = this.props;
        const {open, message, actions, callback, displayProps} = snackDialog;
        const {snackbarProps={}, snackbarContentProps={}} = displayProps || {};
        const DefaultButton = this.defaultButton;
        return (
            <Fragment>
                <Snackbar 
                    className={classes.root}
                    anchorOrigin={{
                        vertical: 'top',
                        horizontal: 'center'
                    }}
                    open={open}
                    {...snackbarProps}>
                        <SnackbarContent
                            className={classes.root}
                            message={message}                            
                            action={actions ? 
                                [...actions, <DefaultButton callback={callback} className={classes.closeButton} key={0}/>] :
                                <DefaultButton callback={callback} className={classes.closeButton} key={0}/>}
                            {...snackbarContentProps}
                        />
                </Snackbar> 
                {open && <div className={classes.overlay}/>}
            </Fragment>
            
        )
    }
}
_SnackDialog.propsTypes = {
    message : PropTypes.any,
    actions : PropTypes.array,
}
const mapStateToProps = ({appReducer}) => ({
    snackDialog : appReducer.snackDialog
})
export const SnackDialog = connect(mapStateToProps)(withStyles(dialogStyle)(_SnackDialog));
export {SnackDialog as default};
