import { hirUtil } from "../utils"
const owner = "1";
const {post, fetchGet, fetchPost} = hirUtil || {}
export const hirSettingServices = {
    editSettingValue : (data, callback) => {
        post(data, owner, "editSettingValue", ({editSettingValue, result, message})=>{
            callback(editSettingValue, result, message);
        })
    },
    deleteSettingValue : (settingId, valueName, callback) => {
        fetchGet(owner, "deleteSettingValue", {settingId, valueName}, ({deleteSettingValue, result, message})=>{
            callback(deleteSettingValue, result, message);
        })
    },
    addSettingValue : (data, callback) => {
        post(data, owner, "addSettingValue", ({addSettingValue, result, message})=>{
            callback(addSettingValue, result, message);
        })
    },
    getSettings : callback => {
        fetchGet(owner, "getSettings", {}, ({getSettings, result, message})=>{
            callback(getSettings, result, message);
        })
    }
}