import React from 'react';
import PropTypes from 'prop-types';
import { withStyles } from '@material-ui/core/styles';
import classNames from 'classnames';
import Table from '@material-ui/core/Table';
import TableBody from '@material-ui/core/TableBody';
import TableCell from '@material-ui/core/TableCell';
import TableFooter from '@material-ui/core/TableFooter';
import TablePagination from '@material-ui/core/TablePagination';
import TableRow from '@material-ui/core/TableRow';
import Typography from '@material-ui/core/Typography';
import Paper from '@material-ui/core/Paper';
import IconButton from '@material-ui/core/IconButton';
import FirstPageIcon from '@material-ui/icons/FirstPage';
import KeyboardArrowLeft from '@material-ui/icons/KeyboardArrowLeft';
import KeyboardArrowRight from '@material-ui/icons/KeyboardArrowRight';
import LastPageIcon from '@material-ui/icons/LastPage';
import { TableHead } from '@material-ui/core';

const colors = {
    
}

const actionsStyles = theme => ({
  root: {
    flexShrink: 0,
    color: theme.palette.text.secondary,
    marginLeft: theme.spacing.unit * 2.5,
  },
});

class TablePaginationActions extends React.Component {
  handleFirstPageButtonClick = event => {
    this.props.onChangePage(event, 0);
  };

  handleBackButtonClick = event => {
    this.props.onChangePage(event, this.props.page - 1);
  };

  handleNextButtonClick = event => {
    this.props.onChangePage(event, this.props.page + 1);
  };

  handleLastPageButtonClick = event => {
    this.props.onChangePage(
      event,
      Math.max(0, Math.ceil(this.props.count / this.props.rowsPerPage) - 1),
    );
  };

  render() {
    const { classes, count, page, rowsPerPage, theme } = this.props;

    return (
      <div className={classes.root}>
        <IconButton
          onClick={this.handleFirstPageButtonClick}
          disabled={page === 0}
          aria-label="First Page"
        >
          {theme.direction === 'rtl' ? <LastPageIcon /> : <FirstPageIcon />}
        </IconButton>
        <IconButton
          onClick={this.handleBackButtonClick}
          disabled={page === 0}
          aria-label="Previous Page"
        >
          {theme.direction === 'rtl' ? <KeyboardArrowRight /> : <KeyboardArrowLeft />}
        </IconButton>
        <IconButton
          onClick={this.handleNextButtonClick}
          disabled={page >= Math.ceil(count / rowsPerPage) - 1}
          aria-label="Next Page"
        >
          {theme.direction === 'rtl' ? <KeyboardArrowLeft /> : <KeyboardArrowRight />}
        </IconButton>
        <IconButton
          onClick={this.handleLastPageButtonClick}
          disabled={page >= Math.ceil(count / rowsPerPage) - 1}
          aria-label="Last Page"
        >
          {theme.direction === 'rtl' ? <FirstPageIcon /> : <LastPageIcon />}
        </IconButton>
      </div>
    );
  }
}

TablePaginationActions.propTypes = {
  classes: PropTypes.object.isRequired,
  count: PropTypes.number.isRequired,
  onChangePage: PropTypes.func.isRequired,
  page: PropTypes.number.isRequired,
  rowsPerPage: PropTypes.number.isRequired,
  theme: PropTypes.object.isRequired,
};

const TablePaginationActionsWrapped = withStyles(actionsStyles, { withTheme: true })(
  TablePaginationActions,
);


const styles = theme => ({
  root: {
    width: '100%',
    // marginTop: theme.spacing.unit * 3,
    height : "100%"
  },
  table: {
    minWidth: "100%",
  },
  tableRow : {
    height : "auto",
    "&:hover" : {
       backgroundColor : theme.colors.gainsboro,
       cursor : "pointer"
    }
  },
  tableHeader : {

  },
  tableWrapper: {
    overflow: 'auto',
    width: "100%",
  },
  tableCell_root : {
    padding : 5,
    fontSize : 11,
  }
});

class _MyTable extends React.Component {
  constructor(props) {
    super(props);
    if(props.getContext){
      props.getContext(this);
    }
  }
  
  state = {
    page: 0,
    rowsPerPage: 5,
  };

  handleChangePage = (event, page) => {
    this.setState({ page });
  };

  handleChangeRowsPerPage = event => {
    this.setState({ page: 0, rowsPerPage: event.target.value });
  };
  defaultCellMap = ({row, cellMapItem}) => <TableCell 
        style={{padding: 5, /* paddingLeft : 10, fontWeight : 12 */ fontSize : 11}} 
        component="td" 
        scope="column"><div>{row[cellMapItem]}</div></TableCell>
  render() {
    const DefaultCellMap = this.defaultCellMap;
    let { 
      classes, header, multiRowHeader,subheaderIndicator, dataMapIndicator,
      headerName, groupSubheaders, subHeaderMap,
      dataMap, data = [], rowAction, CellMap,
      rowStyle, pagination, title, CustomHeader, noBottomPadding,
      getCellMapContext, addButtonHandler, editBtnHandler, deleteBtnHandler,
      editFinishBtnHandler, cancelEditBtnHandler,
      footer : PaperFooter
    } = this.props;
    const rows = data;
    const {rowsPerPage, page } = this.state;
    const emptyRows = rowsPerPage - Math.min(rowsPerPage, rows.length - page * rowsPerPage);
    if(multiRowHeader){
      // - the header that has subs must have _id
      if(header) 
        throw("Using both multiRowHeader and header is not allowed");
      if(!subHeaderMap) 
        throw("subHeaderMap not defined --- must be used while using multiRowHeader")
    }
    let dataMapTracker = [];
    return (
      <Paper elevation={this.props.elevation} className={classes.root}>
        {title && <Typography align="center" {...this.props.titleProps}>{title}</Typography>}
        <div className={classes.tableWrapper}>
          <Table className={classes.table} stickyHeader size="small">
            <TableHead>
              <TableRow>
                {multiRowHeader && multiRowHeader.map(
                  (mHead, index)=>{
                    if(mHead[subheaderIndicator]){
                      if(groupSubheaders && !mHead._id) throw("Header with subs mush have _ID prop - (to attach to the subs via dataMapTracker)");
                      if(header){ 
                        groupSubheaders ? 
                          header.push(...mHead[subheaderIndicator].map(item=>mHead._id+"_"+item)) :
                          header.push(...mHead[subheaderIndicator]);
                      }else{
                        header = groupSubheaders ? mHead[subheaderIndicator].map(item=>mHead._id+"_"+item) : 
                          mHead[subheaderIndicator];
                      }
                      if(groupSubheaders)
                        dataMapTracker.push(...mHead[subheaderIndicator].map(item=>""+mHead._id+"_"+item));
                      else dataMapTracker.push(...mHead[subheaderIndicator]);
                    }else {
                      if(header){ 
                        header.push("");
                      }else header = [""];
                      dataMapTracker.push(dataMapIndicator ? mHead[dataMapIndicator] : (headerName ? mHead[headerName] : mHead.name));
                    }
                    return <TableCell 
                      style={{border : "solid 1px "+colors.gainsboro}}
                      colSpan={mHead[subheaderIndicator] && mHead[subheaderIndicator].length}
                      classes={{root : classes.tableCell_root}} 
                      key={index} 
                      component="th" 
                      scope="column">
                        <Typography style={{textAlign:"center"}}>{headerName ? mHead[headerName] : mHead.name}</Typography>
                      </TableCell>  
                })}
              </TableRow>
              <TableRow>
                {header && header.map((head, index) => 
                    CustomHeader ? <CustomHeader 
                        defaultProps={{
                            scope : "column",
                            classes : {root : classes.tableCell_root},
                            className : classes.tableHeader
                        }}
                        key={index} 
                        item={head}
                        
                    /> :
                    <TableCell
                      className={classes.tableHeader}
                      style={this.props.headerBorder && ({border : "solid 1px "+colors.gainsboro})}
                      classes={{root : classes.tableCell_root}} 
                      key={index} component="th" 
                      scope="column">{multiRowHeader ? subHeaderMap(head, index) : head}</TableCell>  
                )}
              </TableRow>
            </TableHead>
            <TableBody className={classes.tableBody}>
              {data && data.map( (row, index) => {
                if(multiRowHeader) dataMap = dataMapTracker;
                return <TableRow classes={rowStyle} 
                    onClick={rowAction && rowAction(row, index)} 
                    className={classNames(
                        classes.tableRow, 
                        this.props.rowClassName, 
                        this.props.rowStyleCondition && this.props.rowStyleCondition(row)
                    )} 
                    key={index}>
                    {dataMap.map((item, i) => 
                        CellMap ? 
                            <CellMap 
                              listLength={data.length}
                              editBtnHandler={editBtnHandler}
                              deleteBtnHandler={deleteBtnHandler}
                              addButtonHandler={addButtonHandler} 
                              getContext={getCellMapContext} 
                              cancelEditBtnHandler={cancelEditBtnHandler}
                              editFinishBtnHandler={editFinishBtnHandler}
                              key={i} row={row} cellMap={item} index={index}/> :
                            <DefaultCellMap key={i} row={row} cellMapItem={item}/>)}
                </TableRow>
              })}
              {!noBottomPadding && emptyRows > 0 && (
                <TableRow style={{ height: 48 * emptyRows }}>
                  <TableCell colSpan={6} />
                </TableRow>
              )}
            </TableBody>
            {pagination && <TableFooter>
              <TableRow>
                <TablePagination
                  rowsPerPageOptions={[5, 10, 25]}
                  colSpan={3}
                  count={rows.length}
                  rowsPerPage={rowsPerPage}
                  page={page}
                  SelectProps={{
                    native: true,
                  }}
                  onChangePage={this.handleChangePage}
                  onChangeRowsPerPage={this.handleChangeRowsPerPage}
                  ActionsComponent={TablePaginationActionsWrapped}
                />
              </TableRow>
            </TableFooter>}
          </Table>
        </div>
        {PaperFooter && <PaperFooter/>}
      </Paper>
    );
  }
}

_MyTable.propTypes = {
  classes: PropTypes.object.isRequired,
  getContext : PropTypes.func,

  title : PropTypes.any,
  titleProps : PropTypes.object,
  multiRowHeader : PropTypes.array,
  headerName : PropTypes.string,
  subheaderIndicator : PropTypes.string,
  dataMapIndicator : PropTypes.string,
  subHeaderMap : PropTypes.func,
  groupSubheaders : PropTypes.bool, //use when the data for the subheader is more than one, to show category


  header : PropTypes.array,
  headerBorder : PropTypes.bool,
  dataMap : PropTypes.array,
  data : PropTypes.array,
  CellMap : PropTypes.any,

  footer: PropTypes.func,

  getCellMapContext : PropTypes.func,
  addButtonHandler : PropTypes.func,
  editBtnHandler : PropTypes.func,
  deleteBtnHandler : PropTypes.func,
  editFinishBtnHandler : PropTypes.func,
  cancelEditBtnHandler : PropTypes.func,

  CustomHeader: PropTypes.func,
  rowAction : PropTypes.func,
  rowStyleCondition : PropTypes.func,
  
  rowClassName : PropTypes.object,
  rowStyle : PropTypes.object,
  pagination : PropTypes.bool,
  noBottomPadding : PropTypes.bool,
  elevation : PropTypes.number,
};

export const MyTable = withStyles(styles)(_MyTable);