import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Popper, IconButton, Paper, ListItem, ListItemText } from '@material-ui/core';
import More from '@material-ui/icons/MoreVert';
const style = theme => ({
    root: {
        // position : "relative",
    }
})
/**
 * WARNING 
 * POPER gives error if it is not closed first before navigating to another screen, 
 * as it will lose its anchor, hencing giving you problem
 * look at the school.js where headerLeft component, 
 * where I have to remove the MoreOption properly first before going back
 */
class _MoreOption extends Component {
    constructor(props) {
        super(props);
        this.state = {
            open : false,
            anchorEl : null,
            placement : "bottom-end"
        }
    }
    toggleMoreOptions = placement => e => {
        const currentTarget = e.currentTarget;
        this.setState(state => ({open : !state.open, anchorEl : currentTarget, placement}));
    }
    handleItemClick = click => () => {
        if(click) click();
        this.setState({open: false});
    }
    render() {

        const {classes, use, list, arrow} = this.props;
        return (
            <div className={classes.root}>
                <IconButton onClick={this.toggleMoreOptions("bottom-end")}><More color="secondary"/></IconButton>
                {use && <Popper 
                    style={{
                        zIndex : 2000
                    }}
                    anchorEl={this.state.anchorEl}
                    placeholder={this.state.placement}
                    open={this.state.open}
                    placement="bottom"
                    disablePortal={false}
                    modifiers={{
                      flip: {
                        enabled: true,
                      },
                      preventOverflow: {
                        enabled: true,
                        boundariesElement: 'scrollParent',
                      },
                    //   arrow: {
                    //     enabled: true,
                    //     element: arrow,
                    //   },
                    }}
                  >
                    <Paper style={{
                        display : "flex",
                        flexDirection: "column",
                        width : "100%"
                    }}>{list && list.map((item, index)=>
                        <ListItem key={index} button onClick={this.handleItemClick(item.onClick)}>
                                <ListItemText>{item.name}</ListItemText>
                        </ListItem>)}
                    </Paper>
                </Popper>}
            </div>
        );
    }
}
_MoreOption.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({headerReducer}) => ({
    poperList : headerReducer.poperList
})
export const MoreOption = withStyles(style)(_MoreOption);
