import React, { Component } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import { TextField, Button, IconButton, CircularProgress, Card, CardHeader, CardContent, CardActionArea, CardActions, Typography } from '@material-ui/core';
import { Cancel } from '@material-ui/icons';
const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "column",
        margin : 10,
    },
    title : {},
    inputItemContainer : {
        display : "flex",
    },
    textField : {
        margin : 5,
        flex : 1
    },
    btnContainer : {

    },
    btn : {
        margin : 5,
    },
    addBtn : {

    },
    cancelBtn : {},
    updateBtn : {},
})
class _TextParagraphEditableCard extends Component {
    constructor(props) {
        super(props);
        this.state = {
            valueUnusable : props.value,
            value : props.value,
            loading : false,
            editing : false,
        }
    }
    onChange = index => e => {
        let value = [...this.state.value];
        value[index]=e.target.value;
        this.setState({value});
    }
    onUpdateClick(){
        this.setState({loading :true})
        const {value} = this.state;
        const {onUpdateClick } = this.props;
        if(onUpdateClick) onUpdateClick(value, this);
    }
    addNewInput(){
        let value = [...this.state.value];
        value.push("");
        this.setState({value});
    }
    delete = index => () => {
        let value = [...this.state.value];
        value.splice(index, 1);
        this.setState({value});
    }
    onCancelClick(){
        const { valueUnusable} = this.state;
        this.setState({value : valueUnusable, editing : false});
    }
    render() {
        const {classes, header} = this.props;
        const {value, loading, editing} = this.state;
        return (
            <Card className={classes.root}>
                <CardHeader className={classes.title} title={header} titleTypographyProps={{
                    style : {
                        fontWeight : "bold",
                    }  
                }}/>
                <CardContent className={classes.cardContent}>
                    {value && value.map((item, index)=>{

                        return !editing ? 
                        <Typography key={index} paragraph>{item}</Typography> : 
                        <div 
                            key={index}
                            className={classes.inputItemContainer}>
                            <IconButton onClick={this.delete(index)}>
                                    <Cancel color="secondary"/>
                                </IconButton>
                            <TextField
                                className={classes.textField}
                                placeholder={"Paragraph " + (index + 1)}
                                margin="normal"
                                value={item}
                                onChange={this.onChange(index)}
                                multiline
                                rows={4}
                                rowsMax={4}/>
                        </div>
                    })}
                </CardContent>
                {!editing ? 
                <CardActions className={classes.btnContainer}>
                    <Button
                        variant="contained"
                        color="primary"
                        className={classNames(classes.btn, classes.updateBtn)}
                        onClick={()=>this.setState({editing : true})}>
                            Edit
                        </Button>
                </CardActions> : 
                <CardActions className={classes.btnContainer}>
                    <Button
                        variant="contained"
                        color="secondary"
                        className={classNames(classes.btn, classes.cancelBtn)}
                        onClick={()=>this.onCancelClick()}>
                            Cancel
                        </Button>
                    <Button
                        variant="contained"
                        className={classNames(classes.btn, classes.addBtn)}
                        onClick={()=>this.addNewInput()}>
                            Add Paragraph
                        </Button>
                    <Button
                        variant="contained"
                        color="primary"
                        disabled={loading}
                        className={classNames(classes.btn, classes.updateBtn)}
                        onClick={e=>this.onUpdateClick(e)}>
                            {loading && <CircularProgress size={20}/>} Update
                        </Button>
                </CardActions>}
            
            </Card>
        );
    }
}
_TextParagraphEditableCard.propTypes = {
    classes : PropTypes.object.isRequired,
    value : PropTypes.array,
    onUpdateClick : PropTypes.func,
    onCancelClick : PropTypes.func,
};
export const TextParagraphEditableCard = withStyles(style)(_TextParagraphEditableCard);