import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { HIRPaymentList } from '../HIRPaymentList';
import { hirAccountStrings } from '../config';
import { IconButton, FormControlLabel, Checkbox, Typography, CircularProgress, Grid, colors } from '@material-ui/core';
import { CalendarToday, CalendarViewDay } from '@material-ui/icons';
import { MyDialog, errorNotice, monthSelections, hirUtil, warningNotice } from '../../utils';
import Calendar from 'react-calendar';
import { HIRButton } from '../../Includes';
import { hirAccountActions } from '../actions';
import { HIRStartEndDates } from '../../Includes/HIRStartEndDates/HIRStartEndDates'
import { HIRPaymentTotalBox } from '../HIRPaymentList/HIRPaymentTotalBox';


const style = theme => ({
    root: {
    },
    headerContainer : {
        display : 'flex',
        marginBottom : 20,
        alignItems : "center",
    },
    header : {
        color : theme.colors.primary,
        fontWeight : "bold",
    },
    progress : {
        width : "30px !important",
        height : "30px !important",
    },
    total : {
        display : "flex", 
        justifyContent : "center", 
        alignItems : "center",
        color : "white",
        backgroundColor : theme.colors.primary1,
        borderRadius : 20,
        fontSize : 14,
        fontWeight : "bold",
        padding : 10
    },
    dialogContainer : {
        display : "flex",
        flexDirection : "column",
        alignItems : "center",
        justifyContent : "center"
    },
    cashPayment : {
        backgroundColor : theme.colors.primary1,
        color: theme.colors.white,
    },
    totalPayment : {
        backgroundColor : theme.colors.secondary,
        color: theme.colors.white,
    },
})
class _HIRAllPaymentList extends Component {
    constructor(props) {
        super(props);
        this.state = {
            monthOnlyView : false,
            calenderDialog : false,
            dateSearchBtnLoading : false,
            searchDate : new Date(),
            dialogType : "date"
        }
        const {getContext} = props;
        if(getContext) getContext(this);
    }
    componentDidMount() {
        const {dispatch} = this.props;
        this.searchByDate();
    }
    
    onChange(e){
        const value = e.target.checked;
        this.setState({monthOnlyView : value},()=>{
            this.searchByDate();
        });
    }
    searchByDate(fromCalenderDialog){
        const {searchDate, monthOnlyView, dialogType, startDate, endDate} = this.state;
        const {dispatch}=this.props;
        if(dialogType === "date"){
            if(!searchDate) return errorNotice("No date Selected", dispatch);            
            const date = new Date(searchDate);
            if(fromCalenderDialog){
                this.setState({dateSearchBtnLoading : true});
            }            
            hirAccountActions.searchPaymentsByDate(
                date.getFullYear(), 
                date.getMonth() + 1,
                fromCalenderDialog ? date.getDate() :
                (monthOnlyView ? null : date.getDate()),
                done =>{
                    this.setState({dateSearchBtnLoading : false});
                    if(done && fromCalenderDialog) 
                        this.setState({calenderDialog : false, monthOnlyView : false});
                }
            )(dispatch);
        }else {
            if(!startDate) return errorNotice("Start date isn't selected", dispatch);
            if(!endDate) return errorNotice("End date isn't selected", dispatch);
            const date1 = new Date(endDate), date2 = new Date(startDate);
            if((date1.getFullYear() * 12 + date1.getMonth()) - (date2.getFullYear()*12 + date2.getMonth()) > 3){
                return warningNotice("Please make your month range within 3 months", dispatch);
            }
            if(fromCalenderDialog){
                this.setState({dateSearchBtnLoading : true});
            } 
            hirAccountActions.searchPaymentsByDateRange(
                startDate, endDate, {}, done => {
                    this.setState({dateSearchBtnLoading : false});
                    if(done && fromCalenderDialog) 
                        this.setState({calenderDialog : false, monthOnlyView : false});
                }
            )(dispatch);
        }
    }
    render() {
        let {
            classes,
            [hirAccountStrings.payments] : payments
        } = this.props;
        const {monthOnlyView, calenderDialog, dateSearchBtnLoading, 
            searchDate : date, dialogType, endDate, startDate,
        } = this.state;
        let searchDate = new Date(date);
        let total = 0, cashPayment = 0, creditPayment = 0, debitPayment = 0;
        if(payments){
            for (let i = 0; i < payments.length; i++) {
                const {amount, accountAction} = payments[i];
                if(!isNaN(parseInt(amount))) {
                    total += amount;
                    if(accountAction === "useCredit")
                        creditPayment += amount;
                    else if(accountAction === "addToDebt")
                        debitPayment += amount;
                    else cashPayment += amount;
                }
            }
            payments = [...payments, {lastLine : true, total}]
        }
        return (
            <div className={classes.root}>
                <div className={classes.headerContainer}>
                    <IconButton onClick={()=>this.setState({calenderDialog : true, dialogType : "date"})}>
                        <CalendarToday color="secondary"/>
                    </IconButton>
                    <FormControlLabel
                            value={monthOnlyView}
                            onChange={this.onChange.bind(this)}
                        control={<Checkbox/>}
                        label={<Typography style={{fontSize : 14}}>Month only view</Typography>}
                        />
                    {hirUtil.isAdmin() && <div><HIRButton
                        type="secondary"
                        onClick={()=>this.setState({calenderDialog : true, dialogType : "dateRange"})}
                        classes={{btn : classes.marginRight}}
                        >
                            <CalendarViewDay fontSize="small"/>
                            Date Range
                    </HIRButton></div>}
                </div>
                <Grid container style={{margin : "20px 0px"}}>
                    <Grid item xs={12} sm={4} md={3} lg={3} xl={3}>
                        <HIRPaymentTotalBox
                            classes={{
                                root : classes.cashPayment
                            }}
                            title="Cash Payments"
                            amount={cashPayment}
                            description="Amount paid cash"
                        />
                    </Grid>
                    <Grid item xs={12} sm={4} md={3} lg={3} xl={3}>
                        <HIRPaymentTotalBox
                            title="Debit Payments"
                            amount={debitPayment}
                            description="Debt owed by patients"
                        />
                    </Grid>
                    <Grid item xs={12} sm={4} md={3} lg={3} xl={3}>
                        <HIRPaymentTotalBox
                            title="Credit Payments"
                            amount={creditPayment}
                            description="Payment from patient credit/deposit"
                        />
                    </Grid>
                    <Grid item xs={12} sm={4} md={3} lg={3} xl={3}>
                        <HIRPaymentTotalBox
                            classes={{
                                root : classes.totalPayment
                            }}
                            title="Total Payments"
                            amount={total}
                            description="Total payments (credit, debit and cash payments)"
                        />
                    </Grid>
                </Grid>
                <HIRPaymentList
                    tableProps={{
                        data : payments,
                        title : dialogType === "date" ? 
                            (monthOnlyView ? 
                                searchDate.getFullYear()+", "+(monthSelections.find(item=>item.value ==searchDate.getMonth()+1).name) : 
                                searchDate.toDateString()
                            )  : new Date(startDate).toLocaleDateString() + " to " + 
                            new Date(endDate).toLocaleDateString(),
                        titleProps:{
                            style : {
                                fontSize : 14
                            }
                        }
                    }}
                    actionCallback={type=>this.searchByDate()}
                    {...this.props.paymentListProps}
                        />
                <MyDialog open={calenderDialog} within
                 close={()=>this.setState({calenderDialog : false, endDate : null, startDate : null})}>
                     <div className={classes.dialogContainer}>
                        {dialogType === "date" && <Fragment>
                                <Typography paragraph className={classes.header}>Search Payment by dates</Typography>
                            <Calendar
                                value={searchDate}
                                onChange={date=>this.setState({searchDate : date})}/>
                        </Fragment>}
                        {dialogType === "dateRange" && <Fragment>
                            <Typography paragraph className={classes.header}>Search Payment by dates range</Typography>
                            <HIRStartEndDates
                                noTitle
                                containerProps={{
                                    style : {
                                        width : "100%"
                                    }
                                }}
                                onDateChange={(startDate, endDate)=>this.setState({startDate, endDate})}/>
                        </Fragment>}
                        <div style={{marginTop : 20}}>
                            <HIRButton type="primary" 
                                disabled={dateSearchBtnLoading}
                                onClick={()=>this.searchByDate(true)}>
                                    {dateSearchBtnLoading && 
                                    <CircularProgress color="secondary" 
                                        className={classes.progress}/>} Get Payments
                                </HIRButton>
                        </div>
                    </div>
                 </MyDialog>            
            
            </div>
        );
    }
}


_HIRAllPaymentList.propTypes = {
    classes : PropTypes.object.isRequired,
    paymentListProps : PropTypes.shape(HIRPaymentList.propTypes),
    getContext : PropTypes.func,
};
const mapStateToProps = ({hirAccountReducer}) => ({    
    [hirAccountStrings.payments] : hirAccountReducer[hirAccountStrings.payments],
})


export const HIRAllPaymentList = connect(mapStateToProps)(withStyles(style)(_HIRAllPaymentList));
export {HIRAllPaymentList as default}