import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Grid, Typography } from '@material-ui/core';
import { hirUtil } from '../../utils';
const style = theme => ({
    root: {
        backgroundColor : hirUtil.getTheme().highlight,
        color : hirUtil.getTheme().white, 
        borderRadius : 10,
        flexDirection : "column",
        padding : 10,
        display : "flex",
        justifyContent : "center",
    }, 
    container : {
        fontWeight : "bold",
        fontSize : 12,
    },
    header : {
        padding : 10,
        fontWeight : "bold"
    },
    item : {
        display : "flex",
        flexDirection : "column",
        padding :5,
    },
    totalCash : {
        margin : 10, 
        background : theme.colors.secondary,
        borderRadius : 10,
        width : "fit-content",
        padding : 10,
        color : theme.colors.yellow,
        display : "flex",
        flexDirection : "column"
    },
    title : {
        color : theme.colors.secondary,
    }
})
class _HIRDashboardCountBox extends Component {
    render() {
        const {classes, color, data, deposit} = this.props;
        const paymentTotals = {};
        if(data) for (let i = 0; i < data.length; i++) {
            const {_id : {accountAction = "cashPayment"}, amount} = data[i];
            paymentTotals[accountAction] = amount;
        }
        return (
            <div className={classes.root} style={{
                backgroundColor : color
            }}>
                <Typography className={classes.header}>{this.props.header}</Typography>
                <div className={classes.totalCash}>
                    <i style={{fontSize : 10}}>Cash in</i>
                    N {Number((paymentTotals["cashPayment"] || 0) + deposit).toLocaleString()}
                </div>
                <Grid container className={classes.container}>
                    <Grid item xs={6} sm={6} md={6} lg={6} xl={6}>
                        <div className={classes.item}>
                            <strong className={classes.title}>Cash</strong>
                            <span className={classes.amount}>N {Number(paymentTotals["cashPayment"] || 0).toLocaleString()}</span> 
                        </div>
                    </Grid>
                    <Grid item xs={6} sm={6} md={6} lg={6} xl={6}>
                        <div className={classes.item}>
                            <strong className={classes.title}>Deposit</strong>
                            <span className={classes.amount}>N {Number(deposit || 0).toLocaleString()}</span> 
                        </div>
                    </Grid>
                    <Grid item xs={6} sm={6} md={6} lg={6} xl={6}>
                        <div className={classes.item}>
                            <strong className={classes.title}>Credit</strong>
                            <span className={classes.amount}>N {Number(paymentTotals["useCredit"] || 0).toLocaleString()}</span> 
                        </div>
                    </Grid>
                    <Grid item xs={6} sm={6} md={6} lg={6} xl={6}>
                        <div className={classes.item}>
                            <strong className={classes.title}>Debit</strong>
                            <span className={classes.amount}>N {Number(paymentTotals["addToDebt"] || 0).toLocaleString()}</span> 
                        </div>
                    </Grid>
                </Grid>
            </div>
        );
    }
}
_HIRDashboardCountBox.propTypes = {
    classes : PropTypes.object.isRequired,
    data : PropTypes.array,
    header : PropTypes.string,
    color : PropTypes.string,
    deposit : PropTypes.number,
};
export const HIRDashboardCountBox = withStyles(style)(_HIRDashboardCountBox);