import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, StageHeaderPlane, MyDialog, SimplePagination } from "../utils";
import { hirRouteNames } from '../routeNames';
import { HIRButton } from '../Includes/Buttons';
import { HIRNewAppointment } from './HIRNewAppointment';
import { HIRFindPatient } from '../HIRPatients';
import { hirAppointmentStrings } from './config';
import { hirAppointmentActions } from './actions';
import { appActions, alertAction } from '../../../actions';
import { HIRAppointmentList } from './HIRAppointmentList';
import { IconButton, Typography, CircularProgress } from '@material-ui/core';
import Calendar from 'react-calendar';
import { CalendarToday } from '@material-ui/icons';


const style = theme => ({
    root: {
    },
    menuBtn : {
        margin : "0px 5px",
    },
    header : {
        color : theme.colors.primary,
        fontWeight : "bold",
    },
    progress : {
        width : "30px !important",
        height : "30px !important",
    },
    pageRoot : {
        justifyContent : "flex-start",
    },
    pageBtn : {
        textTransform : "lowercase",
        fontSize : 11,
        padding : 10,
        borderRadius : 20,
    },
    pagePrevBtn : {
        backgroundColor : theme.colors.secondary
    },
    pageNextBtn : {
        backgroundColor : theme.colors.primary,
    },
})
class _HIRAppointments extends Component {
    constructor(props) {
        super(props);
        this.state = {
            newAptDialog : false, 
            searchPatientDialog : false,
            calenderDialog : false,
            lastId : null,
            rows : 100,
            firstId : null,
            maxId : null,
            minId : null,
            searchDate : null,
            dateSearchBtnLoading : false,

            skip : 0,
        }
        const {dispatch } = props;        
        headerActions({
            [headerStrings.headerTitle] : "APPOINTMENTS",
            [headerStrings.backButtonAction] : null,
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", pathname : hirRouteNames.dashboard },
            {name : "Appointments", pathname : hirRouteNames.appointments}
        ])(dispatch);
    }
    componentDidMount() {
        this.getAppointments(true);
        hirAppointmentActions.getMaxMinAppointmentIds((done, minId, maxId)=>{
            if(done){
                this.setState({minId, maxId})
            }
        })
    }
    getAppointments(start, nav){
        const {dispatch} = this.props;
        const {lastId, rows, skip} = this.state;
        let newSkip;
        if(start){
            newSkip = 0;
        }else{
            const prevSkip = skip - rows;
            const nextSkip = skip + rows;
            newSkip = nav === "backward" ? prevSkip : nextSkip
        }
        hirAppointmentActions.getAppointments(
            lastId, rows, 
            newSkip, 
            (done, result, message)=>{
                if(done){
                    this.setState({skip : newSkip})
                    this.configurePagination(result);
                }
        })(dispatch);
    }
    configurePagination(result){
        if(result.length !== 0){
            const newLastId = result[result.length - 1]._id;
            const newFirstId = result[0]._id;
            this.setState({lastId : newLastId, firstId : newFirstId})
        }
    }
    pageNextBtnClick(){
        this.getAppointments(false);
    }
    pagePrevBtnClick(){
        this.getAppointments(false, "backward");
    }
    getTodayAppointments(){
        const {dispatch} = this.props;
        hirAppointmentActions.getTodayAppointments()(dispatch);
    }
    componentWillUnmount(){
        const {dispatch} = this.props;
        hirAppointmentActions.payload({
            [hirAppointmentStrings.newAptSearchPatients] : null
        })(dispatch);
    }
    searchAppointments = (text) => {
        const {dispatch} = this.props;
        if(!String(text).trim()){
            appActions.showSnackbar(
                alertAction.error("Can not search with an empty string")
            )(dispatch);
            return false;
        }
        hirAppointmentActions.searchAppointments(text)(dispatch);
    }
    searchPatientSelect = row => () => {
        this.setState({patient : row, searchPatientDialog : false, newAptDialog : true});
    }
    calender = () => {
        const {classes} = this.props;
        return <IconButton onClick={()=>this.setState({calenderDialog: true})}>
                <CalendarToday style={{color : "white"}}/>
            </IconButton>
    }
    newButton = () => {
        const {classes} = this.props;
        return <HIRButton
            classes={{btn : classes.menuBtn}}
            type="primary" 
            onClick={()=>this.setState({searchPatientDialog : true})}>
                New
            </HIRButton>
    }
    allButton = () => {
        const {classes} = this.props;
        return <HIRButton
            type="highlight"
            classes={{btn : classes.menuBtn}} 
            onClick={this.getAppointments.bind(this)}>
                All
            </HIRButton>
    }
    todayButton = () => {
        const {classes} = this.props;
        return <HIRButton
            classes={{btn : classes.menuBtn}}
            type="secondary" 
            onClick={this.getTodayAppointments.bind(this)}>
                Today
            </HIRButton>
    }
    createAppointment(data, context){
        const {dispatch} = this.props;
        const {patient, lastId, rows} = this.state;
        hirAppointmentActions.bookAppointment(
            lastId, rows, {...data, patientId : patient._id},
            done => {
                if(context) context.setState({loading: false});
                if(done){
                    this.setState({newAptDialog : false});
                }
            }
        )(dispatch);
    }
    formartDate(date){
        date = new Date(date);
        return date.getFullYear()+"-"+(String(date.getMonth()+1).padStart(2, "0"))+"-"+String(date.getDate()).padStart(2, "0");
    }
    searchByDate(){
        this.setState({dateSearchBtnLoading : true});
        const {searchDate} = this.state;
        const {dispatch} = this.props;
        hirAppointmentActions.searchAppointmentsByDate(this.formartDate(searchDate), done=>{
            this.setState({dateSearchBtnLoading : false});
            if(done){
                this.setState({calenderDialog : false});
            }
        })(dispatch);
    }
    render() {
        const {
            classes,
            [hirAppointmentStrings.appointments] : appointments
        } = this.props;
        const {
            newAptDialog, patient, searchPatientDialog, 
            dateSearchBtnLoading, calenderDialog,
            lastId, firstId, maxId, minId, skip, rows
        } = this.state;
        return (
            <div className={classes.root}>
                <div style={{marginBottom : 20}}>
                    <StageHeaderPlane
                        isRequired={false}
                        visible={true}
                        searchActions={this.searchAppointments.bind(this)}
                        components={[
                            this.calender.bind(this),
                            this.todayButton.bind(this),
                            this.allButton.bind(this),
                            this.newButton.bind(this),
                        ]}
                        />
                </div>
                <div>
                    <HIRAppointmentList
                        tableProps={{
                            data : appointments
                        }}/>
                    <SimplePagination
                        classes={{
                            btn : classes.pageBtn,
                            prevBtn : classes.pagePrevBtn,
                            nextBtn : classes.pageNextBtn,
                            root : classes.pageRoot
                        }}
                        prevBtnProps={{
                            disabled : skip === 0
                        }}
                        nextBtnProps={{
                            disabled : !appointments || appointments.length < rows || minId === lastId
                        }}
                        prevBtnClick={this.pagePrevBtnClick.bind(this)}
                        nextBtnClick={this.pageNextBtnClick.bind(this)}/>
                </div>
                <MyDialog 
                    open={newAptDialog}
                    close={()=>this.setState({newAptDialog : false})}>
                        <HIRNewAppointment 
                            patient={patient}
                            createAppointment={this.createAppointment.bind(this)}/>
                    </MyDialog>
                <MyDialog
                    open={searchPatientDialog}
                    close={()=>this.setState({searchPatientDialog : false})}>
                        <HIRFindPatient
                            patientListProps={{
                                tableProps : {
                                    rowAction : this.searchPatientSelect.bind(this)
                                }
                            }}/>
                    </MyDialog>
                <MyDialog open={calenderDialog}
                 close={()=>this.setState({calenderDialog : false})}>
                     <div style={{
                         display : "flex",
                         flexDirection : "column",
                         alignItems : "center",
                         justifyContent : "center"
                         }}>
                             <Typography paragraph className={classes.header}>Search Appointments by dates</Typography>
                            <Calendar
                                onChange={date=>this.setState({searchDate : date})}/>
                        <div style={{marginTop : 20}}>
                            <HIRButton type="primary" 
                                disabled={dateSearchBtnLoading}
                                onClick={this.searchByDate.bind(this)}>
                                    {dateSearchBtnLoading && 
                                    <CircularProgress color="secondary" 
                                        className={classes.progress}/>} Get Appointments
                                </HIRButton>
                        </div>
                    </div>
                    
                 </MyDialog>
            </div>
        );
    }
}


_HIRAppointments.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({hirAppointmentReducer}) => ({
    [hirAppointmentStrings.newAptSearchPatients] : hirAppointmentReducer[hirAppointmentStrings.newAptSearchPatients],
    [hirAppointmentStrings.appointments] : hirAppointmentReducer[hirAppointmentStrings.appointments]
})


export const HIRAppointments = connect(mapStateToProps)(withStyles(style)(_HIRAppointments));
export {HIRAppointments as default}