import React, { Component } from 'react';
import PropTypes from 'prop-types';
import classNames from 'classnames';
import {withStyles} from '@material-ui/core/styles';
import { Paper, Grid, Typography, IconButton, CircularProgress, FormLabel } from '@material-ui/core';
import { Edit, Delete } from '@material-ui/icons';
const style = theme => ({
    root: {
        padding : 10,
        position : "relative",
        minHeight : 50,
        marginTop : 10,
        marginBottom : 10,
        display : "flex",
        flexDirection : "column",
        alignItems : 'center',
    },
    padBottom : {
        paddingBottom : 50,
    },
    header : {
        fontWeight : "bold"
    },
    value : {
    },
    text : {
        fontSize : 12,
    },
    editOverlay : {
        position : "absolute",
        bottom : 10,
        right : 10,
    },
    editBtn : {
        margin : 1,
    },
    icon : {},
    deleteIcon : {
        
    },
    cell : {
        display : 'flex',
        flexDirection : "column",
        [theme.breakpoints.down("sm")] : {
            flexDirection : "column"
        }
    },
    titleContainer : {
        display : "flex",
        marginBottom : 20,
        justifyContent : "center",
        alignItems : "center",
    }
})
class _ObjectHighlightBoard extends Component {
    render() {
        const {
            classes, objectData, component : Component, 
            separator, nameMapper, valueMapper, skip, include,
            onEdit, editing, onDelete
        } = this.props;
        if(skip && include) throw("You can't declared skip and include at the same time");
        return (
            <Paper className={classNames(classes.root, (onEdit || onDelete) && classes.padBottom)} {...this.props.paperProps}>
                {this.props.title && <div className={classes.titleContainer}>
                    <FormLabel>{this.props.title}</FormLabel>
                </div>}
                <Grid container spacing={2}>
                    {objectData && Object.entries(objectData).map((keyValue, index)=>{
                        const name = keyValue[0];
                        const value = keyValue[1];
                        if(skip && skip.indexOf(name) !== -1) return  null;
                        if(include && include.indexOf(name) === -1) return null;
                        return <Grid key={index} item xs={12} sm={12} md={12} lg={12} xl={12} 
                            {...this.props.gridItemProps}>
                            {Component ? <Component name={name} value={value}/> : 
                            <div className={classes.cell}>
                                <Typography className={classNames(classes.text, classes.header)}>
                                    {nameMapper ? nameMapper(name) : name} {separator || ": "}
                                </Typography>
                                <Typography className={classNames(classes.text, classes.value)}>
                                    {valueMapper ? valueMapper(name, value, objectData) : value}</Typography>
                            </div>}
                        </Grid>
                    })}
                </Grid>
                {<div className={classes.editOverlay}>
                    
                </div>}
                <div className={classes.editOverlay}>
                    {this.props.onDelete && <IconButton disabled={editing} onClick={this.props.onDelete} className={classes.editBtn}>
                        {editing ? 
                            <CircularProgress size={25} className={classes.icon}/> :
                            <Delete fontSize="small" color="secondary" className={classNames(classes.icon, classes.deleteIcon)}/>}
                    </IconButton>}
                    {onEdit && <IconButton disabled={editing} onClick={onEdit} className={classes.editBtn}>
                        {editing ? 
                            <CircularProgress size={25} className={classes.icon}/> :
                            <Edit fontSize="small" className={classes.icon}/>}
                    </IconButton>}
                </div>
            </Paper>
        );
    }
}
_ObjectHighlightBoard.propTypes = {
    classes : PropTypes.object.isRequired,
    title: PropTypes.string,
    objectData : PropTypes.object,
    paperProps : PropTypes.object,
    gridItemProps : PropTypes.object,
    separator : PropTypes.string,
    nameMapper : PropTypes.func,
    valueMapper : PropTypes.func,
    skip : PropTypes.array,
    include : PropTypes.array,
    editable : PropTypes.bool,
    onEdit : PropTypes.func,
    editing : PropTypes.bool,
    onDelete : PropTypes.func,
};
export const ObjectHighlightBoard = withStyles(style)(_ObjectHighlightBoard);