import React, { PureComponent } from 'react'
import PropTypes from 'prop-types'
import classNames from 'classnames';
import { Button, CircularProgress } from '@material-ui/core';
import {withStyles} from '@material-ui/core/styles';
import { colors } from '../../utils';

const style = theme => ({
    button : {
        backgroundColor : colors.primary,
        color : colors.wheat,
        padding : 5,
        "&:hover" : {
            backgroundColor : colors.primary,
            color : colors.white
        }
    },
    cancel : {
        backgroundColor : colors.appRed, 
        "&:hover" : {
            backgroundColor : colors.appRedDark, 
            color : "white"
        }
    },
    secondary : {
        backgroundColor : colors.secondary, 
        "&:hover" : {
            backgroundColor : colors.secondary,
            color : "white"
        }
    },
    progress : {
        color : colors.white,
        marginRight : 10
    }
})
class _MyButton extends PureComponent {
    static propTypes = {
        variant : PropTypes.oneOf([
            "contained", "raised", "text", "extendedFab", "fab", "flat", "outlined"]),
        type : PropTypes.oneOf([
            "ok", "cancel", "secondary"
        ]),
        value : PropTypes.string,
        onClick : PropTypes.func.isRequired,
        style : PropTypes.object,
        loading : PropTypes.bool,
        className : PropTypes.string,
    }
    
    render() {
        const { loading, classes, onClick, variant, type, value, children, className, ...others} = this.props;

        return (
            <Button 
                {...others}
                disabled={loading}
                className={classNames([classes.button, classes[type], className])}
                variant={variant || "contained"}
                onClick={onClick}>
                    {loading && <CircularProgress className={classes.progress} size={30}/>}
                    {children || value || type || "Ok"}
            </Button>
        )
    }
}
export const MyButton = withStyles(style)(_MyButton);
export default MyButton;
