export const hirAppointmentStrings = {
    appointments : "appointments",
}
export const hirAppointmentConstants = {
    SET_APPOINTMENT : "SET_APPOINTMENT",
}
export const hirAppointmentReducer = (state={}, action) => {
    const {type, payload} = action;
    switch(type){
        case hirAppointmentConstants.SET_APPOINTMENT : 
            return {...state, ...payload};
        default : return state;
    }
}