import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, StageHeaderPlane, MyDialog, breadCrumbActions, SimplePagination } from '../utils';
import { hirPatientActions } from './actions';
import { ExpansionPanel, ExpansionPanelSummary, ExpansionPanelDetails, IconButton, CircularProgress } from '@material-ui/core';
import { HIRButton } from '../Includes/Buttons';
import { HIRNewPatient } from "./HIRNewPatient";
import { hirRouteNames } from '../routeNames';
import HIRPatientList from './HIRPatientList/HIRPatientList';
import { hirPatientStrings } from './config';
import { hirUtil, hirUtilStrings } from '../utils';
import { HIRImportRecords } from './HIRImportRecords';
import { Refresh } from '@material-ui/icons';
import { history } from '../../../helpers';
import { appActions, alertAction } from '../../../actions';

const style = theme => ({
    root: {
    },
    summary : {
        backgroundColor : theme.colors.primary1,
        color : theme.colors.white,
    },
    details : {
        padding : 5,
    },
    container : {
        width : "100%"
    }, 
    pageRoot : {
        justifyContent : "flex-start",
    },
    pageBtn : {
        textTransform : "lowercase",
        fontSize : 11,
        padding : 10,
        borderRadius : 20,
    },
    pagePrevBtn : {
        backgroundColor : hirUtil.getTheme().secondary
    },
    pageNextBtn : {
        backgroundColor : hirUtil.getTheme().primary,
    },
    importBtn : {
        marginRight : 5
    }
})
class _HIRPatients extends Component {
    constructor(props) {
        super(props);
        this.state = {
            lastId : null,
            rows : 100,
            skip : null,
            firstId : null,
            maxId : null,
            minId : null,
            searchLastId : null, searchFirstId : null, searchSkip : null,
            newPatientDialog : false,
            importRecordsDialog : false,
            excel : false,
            refreshing : false,
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "PATIENTS",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", pathname : hirRouteNames.dashboard},
            {name : "Patients", pathname : hirRouteNames.patients}
        ])(dispatch);
    }
    componentDidMount() {
        const {dispatch} = this.props;
        hirPatientActions.getMaxMinPatientIds((done, minId, maxId)=>{
            if(done){
                this.setState({minId, maxId});
            }
        })
        this.getPatients(true);
        const date = new Date();
        hirPatientActions.getRecentVisitedPatientByDate(
            date.getFullYear(),
            date.getMonth() + 1,
            null,
            30
        )(dispatch);
    }
    getPatients(start, nav, callback){
        const {dispatch} = this.props;
        const {rows, skip} = this.state;
        let newSkip;
        if(start){
            newSkip = 0;
        }else{
            const prevSkip = skip - rows;
            const nextSkip = skip + rows;
            newSkip = nav === "backward" ? prevSkip : nextSkip
        }
        hirPatientActions.getPatients(rows, newSkip, 
            (done, result, message)=>{
                if(done){
                    this.setState({skip : newSkip})
                    this.configurePagination(result);
                }
                if(callback) callback(done);
        })(dispatch);
    }
    configurePagination(result){
        if(result.length !== 0){
            const newLastId = result[result.length - 1]._id;
            const newFirstId = result[0]._id;
            this.setState({lastId : newLastId, firstId : newFirstId})
        }
    }
    searchAction = keyword => {
        const{dispatch}=this.props;
        if(!String(keyword).trim()) {
            appActions.showSnackbar(
                alertAction.error("Can't search with empty string")
            )(dispatch);
            return;
        }
        hirPatientActions.getSearchMinMaxPatientId(keyword, (done, {maxId, minId}, message)=>{
            if(done)
                this.setState({searchMinId : minId, searchMaxId : maxId});
        })
        this.setState({keyword});
        this.searchPatients(keyword, true);
    }
    searchPatients(keyword, start, nav){
        this.setState({search : true});
        const {dispatch} = this.props;
        const {rows, searchSkip : skip} = this.state;
        let newSkip;
        if(start){
            newSkip = 0;
        }else{
            const prevSkip = skip - rows;
            const nextSkip = skip + rows;
            newSkip = nav === "backward" ? prevSkip : nextSkip
        }
        hirPatientActions.searchPatient(
            keyword, rows, newSkip, 
            (done, result, message)=>{
                if(done){
                    this.setState({searchSkip : newSkip, searchPatients : result})
                    if(result.length !== 0){
                        const newLastId = result[result.length - 1]._id;
                        const newFirstId = result[0]._id;
                        this.setState({searchLastId : newLastId, searchFirstId : newFirstId})
                    }
                }
        })(dispatch);
    }
    newButton = () => {
        return <HIRButton
            type="primary" 
            onClick={()=>this.setState({newPatientDialog : true})}>
                New
            </HIRButton>
    }
    importButton = () => {
        const {classes} = this.props;
        return <HIRButton
            classes={{btn : classes.importBtn}}
            type="secondary" 
            onClick={()=>this.setState({importRecordsDialog : true})}>
                Import Records (CSV)
            </HIRButton>
    }
    importExcel = () => {
        const {classes} = this.props;
        return <HIRButton
            classes={{btn : classes.importBtn}}
            type="secondary" 
            onClick={()=>this.setState({importRecordsDialog : true, excel : true})}>
                Import Records (EXCEL)
            </HIRButton>
    }
    refreshButton = () => {
        const {refreshing} = this.state;
        return <IconButton 
            disabled={refreshing}
            onClick={this.refresh.bind(this)}>
            {refreshing ? <CircularProgress style={{width : 25, height : 25}}/> : <Refresh/>}
        </IconButton>
    }
    refresh(){
        this.setState({refreshing : true, search : false});
        this.getPatients(true, null, done=>this.setState({refreshing : false}));
    }
    createRecord(data, context){
        const {dispatch} = this.props;
        hirPatientActions.createRecord(data, (done, result)=>{
            context.setState({loading : false});
            if(done){
                this.setState({newPatientDialog : false});
                this.getPatients(true);
                history.push({pathname :  hirRouteNames.patientView_ + result._id, state : result});
            }
        })(dispatch);
    }
    pageNextBtnClick(){
        const {search, keyword} = this.state;
        if(search) this.searchPatients(keyword, false);
        else this.getPatients(false);
    }
    backward = "backward"
    pagePrevBtnClick(){
        const {search, keyword} = this.state;
        if(search) this.searchPatients(keyword, false, this.backward);
        else this.getPatients(false, this.backward);
    }
    searchOnChangeCallback=keyword=>{
        if(!String(keyword).trim()){
            this.refresh();
        }
    }
    render() {
        const {
            classes,
            [hirPatientStrings.patients] : patients,
            [hirPatientStrings.recentVisitPatients] : recentVisitPatients,
            [hirUtilStrings.myProfile] : profile,
        } = this.props;
        const {
            lastId, firstId, maxId, minId, rows, skip,
            search, searchPatients, searchLastId, searchMinId, searchSkip,
        } = this.state;
        let actionButtons = [
            this.refreshButton.bind(this),
            // this.importExcel.bind(this),
            this.newButton.bind(this)
        ]
        if(profile && [0,11].indexOf(profile.privilege) !== -1)
            actionButtons.push(this.importButton.bind(this));
        return (
            <div className={classes.root}>
                <div style={{marginBottom : 20}}>
                    <StageHeaderPlane
                        isRequired={false}
                        visible={true}
                        onChangeCallback={this.searchOnChangeCallback.bind(this)}
                        searchActions={this.searchAction.bind(this)}
                        components={actionButtons}
                        />
                </div>
                <ExpansionPanel>
                    <ExpansionPanelSummary className={classes.summary}>
                        Recently Visited Patients
                    </ExpansionPanelSummary>
                    <ExpansionPanelDetails className={classes.details}>
                        <div className={classes.container}>
                            <HIRPatientList
                                patients={recentVisitPatients}/>
                        </div>
                    </ExpansionPanelDetails>
                </ExpansionPanel>
                <ExpansionPanel defaultExpanded>
                    <ExpansionPanelSummary className={classes.summary}>
                        Patients
                    </ExpansionPanelSummary>
                    <ExpansionPanelDetails className={classes.details}>
                        <div className={classes.container}>
                            <HIRPatientList
                                patients={search ? searchPatients :  patients}/>
                            <SimplePagination
                                classes={{
                                    btn : classes.pageBtn,
                                    prevBtn : classes.pagePrevBtn,
                                    nextBtn : classes.pageNextBtn,
                                    root : classes.pageRoot
                                }}
                                prevBtnProps={{
                                    disabled : search ? 
                                        searchSkip === 0 : 
                                        skip === 0
                                }}
                                nextBtnProps={{
                                    disabled : search ? 
                                    !searchPatients || searchPatients.length < rows || searchMinId === searchLastId : 
                                    !patients || patients.length < rows || minId === lastId
                                }}
                                prevBtnClick={this.pagePrevBtnClick.bind(this)}
                                nextBtnClick={this.pageNextBtnClick.bind(this)}/>
                        </div>
                    </ExpansionPanelDetails>
                </ExpansionPanel>
                <MyDialog 
                    close={()=>this.setState({newPatientDialog : false})}
                    open={this.state.newPatientDialog}>
                        <HIRNewPatient
                            createRecord={this.createRecord.bind(this)}/>
                </MyDialog>
                <MyDialog 
                    close={()=>this.setState({importRecordsDialog : false, excel : false})}
                    open={this.state.importRecordsDialog}>
                        <HIRImportRecords
                            excel={this.state.excel}
                            completeMigCallback={()=>{
                                this.refresh();
                                this.setState({importRecordsDialog : false})
                            }}/>
                </MyDialog>
            </div>
        );
    }
}


_HIRPatients.propTypes = {
    classes : PropTypes.object.isRequired
};

const mapStateToProps = ({hirPatientReducer, hirUtilReducer}) => ({
    [hirPatientStrings.patients] : hirPatientReducer[hirPatientStrings.patients],
    [hirPatientStrings.recentVisitPatients] : hirPatientReducer[hirPatientStrings.recentVisitPatients],
    [hirUtilStrings.myProfile] : hirUtilReducer[hirUtilStrings.myProfile],
})


export const HIRPatients = connect(mapStateToProps)(withStyles(style)(_HIRPatients));
export {HIRPatients as default}