import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import classNames from 'classnames';
import { Badge, IconButton } from '@material-ui/core';
import { CameraEnhance } from '@material-ui/icons';
const style = theme => ({
    root: {
        
    },
    imgContainer :{
        display : "flex",
        justifyContent : 'center',
        alignItems : "center",
        position : "relative",
    },
    img : {
        borderRadius : "100%",
        width : 200,
        height : 200
    },
    inline : {
        width : 30,
        height : 30,
    },
    small : {
        width : 100,
        height : 100        
    },
    medium : {
        width : 150,
        height : 150        
    },
    badge : {
        top : 50,
        right : 12,
        fontSize : 70,
    }
})
class _ProfilePicture extends Component {
    openFileLoader = () => {
        if(this.uploader)
            this.uploader.click();
    }
    fileUpload(e){
        const self = this;
        if(e.target && e.target.files){
            const newImage = e.target.files[0];
            var reader = new FileReader();
            reader.onload = function(e){
                const data = e.target.result;
                self.avatar.src = data;
                const {uploadImage, src : oldPath} = self.props;
                if(uploadImage) uploadImage(newImage, oldPath);
            }
            reader.readAsDataURL(newImage);
        }
    }
    render() {
        const {
            classes, src, title, baseUrl, inline, small, medium, 
            imageContainerProps, imageProps, editable, uploadImage
        } = this.props;
        if(editable && !uploadImage)
            throw("editable require you set -- uploadImage");
        const allClasses = classNames(
            classes.img, inline && classes.inline,
            small && classes.small, medium && classes.medium,
        );
        return (
            <div className={classes.imgContainer} {...imageContainerProps}>
                {editable ? 
                    <Badge                        
                        classes={{badge : classes.badge}} 
                        badgeContent={
                            <IconButton
                                onClick={()=>this.openFileLoader()}>
                                    <CameraEnhance fontSize="large" style={{color : "red"}}/>
                            </IconButton>
                        }>
                        <img 
                            ref={e=>this.avatar = e} 
                            src={baseUrl ? baseUrl+src : src} 
                            title={title} 
                            className={allClasses} 
                            {...imageProps}/>
                    </Badge> :
                    <img 
                        src={baseUrl ? baseUrl+src : src} 
                        title={title} 
                        className={allClasses}
                        {...imageProps}/>
                }
                <input 
                    accept="image/*"
                    onChange={e=>this.fileUpload(e)} 
                    style={{display : "none"}} 
                    ref={e=>this.uploader = e} 
                    type="file" name="avatar"/>
            </div>
        );
    }
}
_ProfilePicture.propTypes = {
    classes : PropTypes.object.isRequired,
    src : PropTypes.string.isRequired,
    baseUrl : PropTypes.string,
    title : PropTypes.string.isRequired,
    imageProps : PropTypes.object,
    imageContainerProps : PropTypes.object,
    editable : PropTypes.bool,
    uploadImage : PropTypes.func,
    inline : PropTypes.bool,
    small : PropTypes.bool,
    medium : PropTypes.bool,
    large : PropTypes.bool,
    xlarge : PropTypes.bool,
};
export const ProfilePicture = withStyles(style)(_ProfilePicture);
