import React, { PureComponent } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import BreadCrumb from '../BreadCrumb/BreadCrumb'
import { withStyles, withTheme } from '@material-ui/core';
import { StageHeader } from '../MainStageHeader';
import { mainStageStrings } from './constants';
import { ThemeProvider } from '@material-ui/styles';

const styles = theme => ({
    root : {
        padding : 20,
        paddingLeft : 40,
    }
});

class MainStage extends PureComponent {
    constructor(props) {
        super(props);
        
        this.stageHeaderStyle = {
            ...props.theme, colors : props.appTheme
        }
    }
    
    render() {
        const {
            classes, 
            [mainStageStrings.containerProps]: containerProps,
        } = this.props;
        const {children} = this.props;
        return (
            <div className={classes.root} {...containerProps}>
                <BreadCrumb/>
                <ThemeProvider theme={this.stageHeaderStyle}>
                    <StageHeader/>
                </ThemeProvider>
                    {children}
            </div>
        )
    }
}
MainStage.propTypes = {
    classes : PropTypes.object,
    appTheme : PropTypes.object,
}
const mapStateToProps = ({mainStageReducer}) => ({
    ...mainStageReducer
})
export default connect(mapStateToProps)(withStyles(styles)(withTheme(MainStage)));