import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { TextField } from '@material-ui/core';
import {connect} from 'react-redux';
const style = theme => ({
    root: {
        
    },
    field : {
        margin : 0,
    }
})
class _TextFieldComponent extends Component {
    constructor(props) {
        super(props);
        this.state = {
            value : props.value || ""
        }
        const {getContext} = props;
        if(getContext) getContext(this);
    }
    onChange(e){
        const value = e.target.value;
        this.setState({value});
        const {onChangeCallback} = this.props;
        if(onChangeCallback) onChangeCallback(value, this);
    }
    render() {
        const {classes, state, reducer, reducerString, generateValue} = this.props;
        let value;
        if(state) {
            if(!reducer) throw("You must specify reducer");
            value = generateValue ? generateValue(state[reducer][reducerString]) : state[reducer][reducerString];
        }else value = this.state.value;
        return (
            <TextField
                className={classes.field}
                margin="normal"
                value={String(value)}
                variant="outlined"
                inputProps={this.props.small && {
                    style : {
                        padding : 10,
                        fontSize : 14,
                    }
                }}
                onChange={this.onChange.bind(this)}
                {...this.props.fieldProps}
                />
        );
    }
}
_TextFieldComponent.propTypes = {
    classes : PropTypes.object.isRequired,
    fieldProps : PropTypes.shape(TextField.propTypes),
    value : PropTypes.any,
    getContext : PropTypes.func,
    onChangeCallback : PropTypes.func,
    small : PropTypes.bool,

    reducer : PropTypes.string,
    reducerString : PropTypes.string,
    generateValue : PropTypes.func,
};
const mapStateToProps = state => ({
    state
})
export const TextFieldComponent = withStyles(style)(_TextFieldComponent);
export const TextFieldComponentRedux = connect(mapStateToProps)(withStyles(style)(_TextFieldComponent))