import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { Button, Popover, ListItemText, ListItem, List, IconButton } from '@material-ui/core';
import { Add } from '@material-ui/icons';
import MyArticleTextField from './MyArticleTextField/MyArticleTextField';
import {ProfilePicture} from "../../ProfilePicture"

const style = theme => ({
    root : {

    },
    subArticleContainer : {
        marginTop : 20, 
        marginLeft : 50, 
        marginBottom : 20,
    }
})
class _MyArticleConfig extends Component {
    constructor(props) {
        super(props);
        this.state = {
            anchorEl : null,
            articleInfo : [
                {id : "", name : "title", label : "Title"},
                {id : "", name : "subtitle", label : "Subtitle"},
            ],
            data : []
        }
        const {data, getContext} = props;
        if(data) this.state.data = [...data];
        getContext && getContext(this);
    }
    addArticleComponent = id => () => {
        const {articleInfo} = this.state;
        let dataId = 0;
        switch(id){
            case "content" : 
                for (let i = 0; i < articleInfo.length; i++) {
                    const {name, id} = articleInfo[i];
                    if(name==="content")dataId=id;
                }
                articleInfo.push({
                    name : "content", id : ++dataId, label : "Content", type : "area"
                }); break;
            case "image" : 
                for (let i = 0; i < articleInfo.length; i++) {
                    const {name, id} = articleInfo[i];
                    if(name==="image")dataId=id;
                }
                articleInfo.push({
                name : "image", id : ++dataId, label : "Image"
            }); break;
            case "sub" : 
                for (let i = 0; i < articleInfo.length; i++) {
                    const {name, id} = articleInfo[i];
                    if(name==="sub")dataId=id;
                }
                articleInfo.push({
                name : "sub", id : ++dataId, label : "Sub-article"
            }); break;
        }
        this.setState({
            openDialog : true,
            anchorEl : null,
        }); 
    }
    updateData = name => state => {
        const {data} = this.state;
        const {getStateData} = this.props;
        if(Array.isArray(state)){
            const datumIndex = data && data.findIndex(item=>item.name===name);
            if(datumIndex === -1) this.state.data.push({name, data : state});
            else this.state.data[datumIndex].data = state;
        }else{
            const datumIndex = data && data.findIndex(item=>item.name===name);
            if(datumIndex === -1) this.state.data.push(state);
            else this.state.data[datumIndex] = state;
        }
        if(getStateData) getStateData(data);
    }
    render() {
        const {classes} = this.props;
        const {data : dataArray, anchorEl, articleInfo, editMode} = this.state;
        const menuList = [
            {id : "content", label :"Content"}, 
            {id : "sub", label : "Subarticle"}
        ];
        if(editMode) menuList.push({id : "image", label :"Image"})
        return (
            <div className={classes.root}>
                {articleInfo.map((item, index)=>{
                    const {name, label, type, id} = item;
                    const data = dataArray && dataArray.find(i=>i.name===name+id);
                    switch(name){
                        case "sub" : return <div key={index} 
                            className={classes.subArticleContainer}>
                                <MyArticleConfig
                                    getStateData={this.updateData(name+id)}
                                    data={data && data[name+id] && data[name+id].data}
                                />
                            </div>;
                        case "image" : return <div key={index}>
                            <ProfilePicture
                                editable
                                uploadImage={file=>{}}
                            />
                        </div>
                        default : return <MyArticleTextField
                            key={index}
                            name={name+id}
                            getContext={context=>this.getFieldContexes[name]=context}
                            getStateData={this.updateData(name+id)}
                            data={data && data[name+id]}
                            textFieldProps={type === "area" ? {
                                label,
                                placeholder : label,
                                multiline : true,
                                rows : 6,
                                rowsMax : 6,
                            } : {
                                label,
                                placeholder : label,
                                type : type || "text"
                            }}/>
                    }
                })}
                <div>
                    <IconButton
                        variant="outlined"
                        color="primary"
                        onClick={(e)=>{
                            const anchorEl = e.target;
                            this.setState({anchorEl});
                        }}>
                            <Add fontSize="small" color="primary"/>
                    </IconButton>
                    <Popover
                        open={Boolean(anchorEl)}
                        anchorEl={anchorEl}
                        onClose={()=>this.setState({anchorEl : null})}
                        classes={this.props.popoverClasses}>
                        <List>
                            {menuList.map((item, index)=>
                                <ListItem 
                                    key={index} 
                                    button 
                                    onClick={this.addArticleComponent(item.id)}>
                                    <ListItemText
                                        primary={item.label}
                                        primaryTypographyProps={{
                                            style:{padding :5, fontSize : 12}
                                        }}
                                        />
                                </ListItem>
                            )}
                        </List>
                    </Popover>
                </div>
            </div>
        );
    }
}


_MyArticleConfig.propTypes = {
    classes : PropTypes.object.isRequired,
    popoverClasses : PropTypes.object,
    getStateData : PropTypes.func,
    getContext : PropTypes.func,
    editMode : PropTypes.bool,
};
export const MyArticleConfig = withStyles(style)(_MyArticleConfig);
export {MyArticleConfig as default}