import React, {Fragment} from 'react';
import {Redirect, Route} from 'react-router-dom';
import {hirUtil, hirActions, Screen} from  './utils';
import { hirRouteNames } from './routeNames';
import { FormLabel, LinearProgress, makeStyles } from '@material-ui/core';
const style = makeStyles(theme => ({
    fetching : {
        width : "100%",
        minHeight : "100vh",
        display : "flex",
        flexDirection : "column",
        justifyContent : "center",
        alignItems : "center",
    }
}))
export const PrivateRoutePlane = ({loadingProfile, theme : appTheme, component : Component, ...props}) => {
    const classes = style();
    return <Route {...props} render={props => { 
        return (
            hirUtil.isLogedIn()
            ? <Fragment>
                {loadingProfile ? 
                <div className={classes.fetching}>
                    <FormLabel>Fetching Profile...</FormLabel>
                    <div style={{marginTop : 20}}/>
                    <LinearProgress style={{width : "80%"}} variant="indeterminate"/>
                </div> :
                <Screen appTheme={appTheme} {...props} component={Component}/>}
            </Fragment>
            : <Redirect to={{ pathname: hirRouteNames.login, state: { from: props.location } }} />
        )}
    } />
};
export const LogoutRoute = rest =>(
    <Route {...rest} render={props=>{
        hirActions.logout();
        return <Redirect to={{ pathname: hirRouteNames.login, state: { from: props.location } }}/> 
    }}/>
)