import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import { TableCell, TextField, IconButton, withStyles, Typography, FormControl } from '@material-ui/core';
import { Add as AddIcon, Edit as EditIcon, Delete as DeleteIcon, Done as DoneIcon, 
    Cancel as CancelIcon, RemoveRedEye as RemoveRedEyeIcon} from '@material-ui/icons';
const colors = {

}
const styles = theme => ({
    icon : {
        padding : 0
    },
    cell : {
        padding : 5,
        fontSize : 11,
    }
})
class _EditableCellMapFormat extends Component{
    constructor(props) {
        super(props);
        this.state = {
            data : {
                name : props.cellMap,
                value : props.row[props.cellMap]
            }
        }
        //get the context for editing / and adding new row
        //new row goes directory to the parent component, editing one using the row attachment
        if(props.row.new && props.getContext) props.getContext(this, props.cellMap);
        
    }
    handleChange = e => {   
        let data = {...this.state.data};
        data.value = e.target.value;
        this.setState({data});
    }
    render(){
        if(this.props.row.editing){
            if(this.props.row.context) this.props.row.context[this.props.cellMap] = this;
            else this.props.row.context = {[this.props.cellMap] : this};
        } 
        const {data} = this.state;
        const {
            classes, listLength,
            row, cellMap, addButtonHandler, 
            editBtnHandler, deleteBtnHandler, 
            editFinishBtnHandler, cancelEditBtnHandler,
            viewBtnHandler, 

            //higher component props
            skipEdit, tableCellContentView, 
            inputTypeMap
        } = this.props;
        if(row.new || row.editing){
            switch(cellMap){
                case "action" : return <TableCell className={classes.cell}>
                    <FormControl style={{flexDirection: "row"}}>
                    {!row.editing ?
                        <IconButton 
                            className={classes.icon}
                            onClick={addButtonHandler && addButtonHandler(listLength)} 
                            style={{backgroundColor: colors.secondary, color :colors.white}}>
                            <AddIcon/>
                        </IconButton> :
                        <Fragment>
                            <IconButton
                                className={classes.icon} onClick={editFinishBtnHandler && editFinishBtnHandler(row, cellMap)}>
                                <DoneIcon fontSize="small"  style={{color : colors.secondary}}/>
                            </IconButton>
                            <IconButton
                                className={classes.icon} onClick={cancelEditBtnHandler && cancelEditBtnHandler(row)}>
                                <CancelIcon fontSize="small" color="secondary"/>
                            </IconButton>
                        </Fragment>
                    }</FormControl>
                </TableCell>
                default : 
                    if(tableCellContentView){
                        return <TableCell className={classes.cell}>
                                    {skipEdit && skipEdit.indexOf(cellMap) !== -1 ?
                                        (<Typography style={{minWidth : 100}}>{row[cellMap]}</Typography>) :
                                        (tableCellContentView(true, {row, cellMap}))}
                                </TableCell>
                    }else return <TableCell className={classes.cell}>
                        {skipEdit && skipEdit.indexOf(cellMap) !== -1 ?
                            <Typography style={{minWidth : 100}}>{row[cellMap]}</Typography> :
                        <TextField
                            fullWidth
                            style={{minWidth : 100}}
                            value={data.value || ""}
                            margin="dense"
                            variant="outlined"
                            type={(inputTypeMap && inputTypeMap[cellMap]) || "text"}
                            // label={String(cellMap).toUpperCase()}
                            // placeholder={String(cellMap)}
                            onChange={this.handleChange.bind(this)}/>}
                    </TableCell>
            }
        }else{
            switch(cellMap){
                case "action" : return <TableCell className={classes.cell}>
                        {row.editable && <FormControl>
                                <IconButton
                                    className={classes.icon} onClick={editBtnHandler && editBtnHandler(row)}>
                                    <EditIcon fontSize="small"/>
                                </IconButton>
                            </FormControl>}
                        {row.delible && <FormControl>
                                <IconButton
                                    className={classes.icon} onClick={deleteBtnHandler && deleteBtnHandler(row)}>
                                    <DeleteIcon fontSize="small" color="secondary"/>
                                </IconButton>
                            </FormControl>}
                        {row.view && <FormControl>
                                <IconButton
                                    className={classes.icon} onClick={viewBtnHandler && viewBtnHandler(row)}>
                                    <RemoveRedEyeIcon fontSize="small"/>
                                </IconButton>
                            </FormControl>}
                    </TableCell>;
                default : 
                    if(tableCellContentView){
                            return <TableCell className={classes.cell}>
                                <div>{tableCellContentView(false, {row, cellMap})}</div>
                            </TableCell>
                    }else return <TableCell className={classes.cell}>
                        <div>{row[cellMap]}</div>
                    </TableCell>
            }
        }
    }
}
_EditableCellMapFormat.propTypes = {
    classes : PropTypes.object,
    listLength : PropTypes.number,
    deleteBtnHandler : PropTypes.func,
    editBtnHandler : PropTypes.func,
    addButtonHandler : PropTypes.func,
    editFinishBtnHandler : PropTypes.func,
    cancelEditBtnHandler : PropTypes.func,
    viewBtnHandler : PropTypes.func,

    skipEdit : PropTypes.array,
    inputTypeMap : PropTypes.object,

    tableCellContentView : PropTypes.func,
}
export const EditableCellMapFormat = withStyles(styles)(_EditableCellMapFormat);