import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { FormControl, TextField, Typography, Button } from '@material-ui/core';
const style = theme => ({
    root: {
        display : "flex",
        flexDirection : "column",
        padding : "0px 20px",
    },
    title : {

    },
    textField : {

    },
    send : {

    },
    btnContainer : {

    }
})
class _ContactUsForm extends Component {
    constructor(props) {
        super(props);
        this.state = {
            data : {
                name : "",
                email : "",
                message : "",
            },
            loading : false
        }
    }
    onChange = name => e => {
        const value = e.target.value;
        this.setState(({data})=>({data : {...data, [name] : value}}));
    }
    btnClick(e){
        this.setState({loading: true});
        const {name, email, message} = this.state.data;
        this.props.onSendClick(name, email, message, done=>{
            if(done) this.setState({
                loading: false, 
                data : {
                    name : "", email :"", message :""
                }
            });
        });
    }
    render() {
        const {classes, title} = this.props;
        const {name, email, message} = this.state.data;
        return (
            <div className={classes.root}>
                <Typography 
                    className={classes.title} 
                    {...this.props.titleProps}
                    paragraph>{title || "SEND US A MESSAGE"}</Typography>
                    <TextField
                        value={name}
                        variant="outlined"
                        label="Name"
                        placeholder="Name"
                        className={classes.textField}
                        margin="normal"
                        {...this.props.textProps}
                        onChange={this.onChange("name")}/>
                    <TextField
                        value={email}
                        variant="outlined"
                        label="Email"
                        placeholder="Email"
                        className={classes.textField}
                        margin="normal"
                        {...this.props.textProps}
                        onChange={this.onChange("email")}/>                
                    <TextField
                        value={message}
                        variant="outlined"
                        label="Message"
                        placeholder="Message"
                        className={classes.textField}
                        margin="normal"
                        {...this.props.textProps}
                        multiline
                        rowsMax={10}
                        rows={10}
                        onChange={this.onChange("message")}/>
                    <div className={classes.btnContainer}>
                        <Button
                            variant="contained"
                            disabled={this.state.loading}
                            className={classes.send}
                            onClick={e=>this.btnClick(e)}>
                                Send
                            </Button>
                    </div>
            </div>
        );
    }
}
_ContactUsForm.propTypes = {
    classes : PropTypes.object.isRequired,
    title : PropTypes.string,
    onSendClick : PropTypes.func,
    titleProps : PropTypes.object,
    textProps : PropTypes.object,
};
export const ContactUsForm = withStyles(style)(_ContactUsForm);