import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import CSVReader from 'react-csv-reader';
import { appActions, alertAction } from '../../../../actions';
import { LinearProgress, Typography, TableCell } from '@material-ui/core';
import { HIRButton } from '../../Includes';
import { hirUtil } from '../../utils';
import { MyTable, HighlightedInfo } from '../../utils';
import { hirPatientActions } from '../actions';
import HIRPatientList from '../HIRPatientList/HIRPatientList';
import { Done, Close } from '@material-ui/icons';
import readXlsxFile from 'read-excel-file'

const style = theme => ({
    root: {

    },
    phaseOneBtn : {
        marginTop : 20
    },
    cell : {
        padding : 5,
        fontSize : 11
    }
})
class _HIRImportRecords extends Component {
    constructor(props) {
        super(props);
        this.state = {
            phase : 1,
            verificationStatus : "",
            verificationError : "success",
            loadedFile : null,
            patients : null,
            tableHeader : null,
            existingPatients : null
        }
    }
    phaseOneContinueClick(){
        this.setState({phase : 2});
        const {loadedFile} = this.state;
        this.handleLoadedFile(loadedFile);
    }
    handleLoadedFile(data){
        if(data && data[0]){
            const dataNames = this.generateObjectNames(data[0]);
            const body = [...data];
            body.splice(0, 1);
            if(dataNames){
                this.setState({verificationStatus : "data headers correct!", verificationError : "success"})
                const patients = this.generatePatientInfo(dataNames, body);
                if(patients)this.setState({tableHeader:dataNames, patients, phase : 3})
                else this.setState({phase : "error"})
            }else this.setState({phase : "error"})
        }
    }
    generatePatientInfo(names, data){
        this.setState({verificationStatus : "Verifying patient ids!", verificationError : "success"});
        const {dispatch} = this.props;
        const patients = [];
        for (let i = 0; i < data.length; i++) {
            const info = data[i];
            const patient = {};
            for (let j = 0; j < info.length; j++) {
                const patientData = info[j];
                if(names[j] === "oldId"){
                    if(!isNaN(parseInt(patientData))){
                        patient.oldId = parseInt(patientData);
                        this.setState({verificationStatus : patientData + " verified!", verificationError : "success"});
                    }else{
                        // this.setState({
                        //     verificationStatus: "'"+patientData + 
                        //     "' is not a valid patient number.\nThis error occured at row "+
                        //     (i+1)+" under "+names[j]+" column",
                        //     verificationError : "error"
                        // });
                        // appActions.showSnackbar(
                        //     alertAction.error("'"+patientData + "' is not a valid patient number")
                        // )(dispatch);
                        continue;
                        // return false;
                    }
                }else if(names[j] === "dob"){ 
                    if(String(new Date(patientData)).indexOf("Invalid") === -1)
                        patient[names[j]] = patientData
                    else {
                        this.setState({
                            verificationStatus: "'"+patientData + 
                            "' is not a valid date.\nThis error occured at row "+
                            (i+1)+" under "+names[j]+" column",
                            verificationError : "error"
                        });
                        appActions.showSnackbar(
                            alertAction.error(patientData+" is not a valid date!")
                        )(dispatch);
                        return false;
                    }
                }else if (names[j]){
                    patient[names[j]] = patientData;
                }else {
                    this.setState({
                        verificationStatus: "'"+patientData + 
                        "' fell into unknown columns.\nThis error occured at row "+
                        (i+1)+" under "+names[j]+" column",
                        verificationError : "error"
                    });
                    appActions.showSnackbar(
                        alertAction.error(patientData+" fell into unknown columns!")
                    )(dispatch);
                    return false;
                }  
            }
            //new standard to ignore those without hospital number
            if(patient.oldId)
                patients.push({myProfile : patient}); 
        }
        return patients;
    }
    generateObjectNames(dataArray){
        const {dispatch} = this.props;
        let header = null;
        if(dataArray){
            if(this.verifyContent(dataArray)){
                dataArray.map((item, index)=>{
                    if(header) 
                        header[index] = item;
                    else header = {[index] : item};
                })
            }this.setState({phase : "error"})
        }else{
            this.setState({
                verificationStatus: "Document has no content",
                verificationError : "error"
            });
            appActions.showSnackbar(
                alertAction.error("Document has no content!")
            )(dispatch);
        }
        return header;
    }
    verifyContent(firstRow){
        const {dispatch} = this.props;
        const needed = ["oldId", "lastName", "firstName", "address", "gender"];
        for (let i = 0; i < needed.length; i++) {
            const name = needed[i];
            if(firstRow.indexOf(name) === -1){
                this.setState({
                    verificationStatus: name+" column is missing in the file",
                    verificationError : "error"
                });
                appActions.showSnackbar(
                    alertAction.error(name+" column is missing in the file")
                )(dispatch);
                return false;
            }
        }
        return true;
    }
    generateHeader(data){
        const header = [];
        if(data){
            for (const i in data) {
                if (data.hasOwnProperty(i)) {
                    const head = data[i];
                    header.push(head)
                }
            }
        }
        return header;
    }
    checkPatientIdUniqueness(chunk, callback){
        this.setState({phase : 4});
        const {dispatch} = this.props;
        const patientIds = this.getAllPatientIds(chunk);
        if(patientIds.length > 0){
            this.setState({
                verificationStatus : "Contacting database with "+patientIds.length+" ids"
            });
            hirPatientActions.getPatientsByIdsForVerification(patientIds, callback)(dispatch);
        }else{
            this.setState({verificationStatus : "0 id collected!", verificationError : "error"})
        }
    }
    chuckArray(array, size, start){
        var tempArray = [];
        for (let index = start; index < array.length; index+=size) {
            const myChunk = array.slice(index, index + size);
            tempArray.push(myChunk);            
        }
        return tempArray;
    }
    sendData(){
        const {dispatch} = this.props;
        let {chunkIndex} = this.state;
        if(!chunkIndex) chunkIndex = 0;
        if(this.chunks[chunkIndex]){
            hirPatientActions.migratePatientData(this.chunks[chunkIndex], (done, result)=>{
                if(done){
                    this.setState({
                        chunkIndex: chunkIndex + 1,
                        verificationError : "success", 
                        verificationStatus : (chunkIndex+1)+"/"+this.chunks.length + " : sending ..."
                    });
                }
            })(dispatch);
        }
    }
    migratePatientData(){
        const {dispatch} = this.props;
        const {patients} = this.state;
        const chunks = this.chuckArray(patients, 200, 0);
        this.chunks = chunks;
        this.setState({phase : 6, verificationStatus : "0/"+chunks.length + " : sending ..."});
        // chunks.forEach((element, index) => {
            
        // });
        // const chunk = patients.slice(stage, patients.length > patients.length - stage ? count : patients.length - stage);
        // stage +=count;
        // this.checkPatientIdUniqueness(chunk, (done, result, message)=>{
        //     if(!done)this.setState({verificationStatus : message, verificationError : "error"});
        //     else{
        //         if(result.length === 0){
        //             this.setState({verificationError : "success", verificationStatus : "Pushing data..."})
        //             hirPatientActions.migratePatientData(chunk, (done, result, message) => {
        //                 if(done){
        //                     if(chunk.length !== 0)
        //                         this.migratePatientData(stage, count);
                            
        //                 } else this.setState({verificationError : "error", verificationStatus : message})
        //             })(dispatch);
        //         }else{
        //             this.setState({phase : 5, existingPatients : result});
        //         }
        //     }
        // })        
    }
    getAllPatientIds(data){
        const ids = [];
        if(data) for (let i = 0; i < data.length; i++) {
            const patient = data[i];
            if(patient.myProfile && patient.myProfile.oldId) ids.push(patient.myProfile.oldId);
        }
        return ids;
    }
    cellMapFormat = ({row, cellMap}) => {
        const {classes} = this.props;
        const {myProfile} = row;
        switch(cellMap){
            default : return <TableCell className={classes.cell}>
                {myProfile[cellMap]}
            </TableCell>
        }
    }
    handleExcelUpload = ()=>{
        this.setState({excelProgress :true})
        readXlsxFile(this.excelInput.files[0]).then((loadedFile) => {
            // `rows` is an array of rows
            // each row being an array of cells.
            this.setState({loadedFile, excelProgress : false})
        })
    }
    render() {
        const {classes, excel} = this.props;
        const {phase, verificationStatus, verificationError, loadedFile, patients, tableHeader, existingPatients}= this.state;

        return (
            <div className={classes.root}>
                {phase === 1 && <div>
                    <Typography paragraph>Select a {excel ? "excel" : "csv"} file containing patient information</Typography>
                    <HighlightedInfo>Please import data is several small portions to avoid overloading the system and crashing</HighlightedInfo>
                    {excel ? 
                        <div>
                            <input 
                                accept=".xls, .xlsx"
                                ref={e=>this.excelInput = e} 
                                onChange={this.handleExcelUpload.bind(this)} type="file" id="input" />
                                {this.state.excelProgress && <div>
                                    <LinearProgress/>
                                </div>}
                            {loadedFile && <div>
                                <HIRButton 
                                classes={{btn : classes.phaseOneBtn}}
                                onClick={this.phaseOneContinueClick.bind(this)}>Continue</HIRButton>
                            </div>}
                                
                        </div>:
                        <div>
                            <CSVReader 
                                onFileLoaded={loadedFile=>this.setState({loadedFile})}/>
                            {loadedFile && <HIRButton 
                                classes={{btn : classes.phaseOneBtn}}
                                onClick={this.phaseOneContinueClick.bind(this)}>Continue</HIRButton>}
                        </div>
                }
                </div>}
                {phase === 2 && <div>
                    <Typography paragraph>Verifying Patient Ids</Typography>
                    <LinearProgress/>
                    <Typography style={{
                        fontSize : 11,
                        marginTop : 5,
                        color : verificationError === "error" ? hirUtil.getTheme().secondary : "green",
                    }}>{verificationStatus}</Typography>
                </div>}
                {phase === 3 && <div>
                    {tableHeader ? <div>
                        <HighlightedInfo>This data will be uploaded into the patient database</HighlightedInfo>
                        <MyTable
                            elevation={0}
                            header={this.generateHeader(tableHeader)}
                            dataMap={this.generateHeader(tableHeader)}
                            data={patients}
                            CellMap={this.cellMapFormat.bind(this)}
                        />
                        <HIRButton 
                            classes={{btn : classes.phaseOneBtn}}
                            onClick={this.migratePatientData.bind(this)}>Continue</HIRButton>
                    </div>
                         : null}
                    </div>
                }
                {phase === 4 && <div>
                    <Typography paragraph>Contacting database for patient id uniqueness...(wait)</Typography>
                    <LinearProgress/>
                    <Typography style={{
                        fontSize : 11,
                        marginTop : 5,
                        color : verificationError === "error" ? hirUtil.getTheme().secondary : "green",
                    }}>{verificationStatus}</Typography>
                </div>}
                {phase === 5 && <div>
                    <HighlightedInfo type="secondary">
                        The following patients (patient ids) already exist... check your data
                    </HighlightedInfo>
                    <HIRButton type="secondary" onClick={()=>this.setState({phase : 3})}>Back</HIRButton>
                    <HIRPatientList
                        patients={existingPatients}
                        />
                </div>}
                
                {phase === 6 && <div>
                    <Typography paragraph>Migrating...</Typography>
                    <LinearProgress/>
                    <Typography style={{
                        fontSize : 11,
                        marginTop : 5,
                        color : verificationError === "error" ? hirUtil.getTheme().secondary : "green",
                    }}>{verificationStatus}</Typography>
                    <HIRButton onClick={this.sendData.bind(this)}>Continue</HIRButton>
                </div>}
                {phase === "final" && <div>
                        <div style={{display : "flex"}}>
                            <Done style={{
                                color : "green"
                            }}/><Typography paragraph>Success!</Typography>
                        </div>
                        <Typography style={{
                            fontSize : 11,
                            marginTop : 5,
                            color : verificationError === "error" ? hirUtil.getTheme().secondary : "green",
                        }}>{verificationStatus}</Typography>
                        <HIRButton 
                        classes={{btn : classes.phaseOneBtn}}
                        onClick={this.props.completeMigCallback}>Close</HIRButton>
                </div>}

                {phase === "error" && <div>
                    <div style={{display : "flex"}}>
                            <Close style={{
                                color : hirUtil.getTheme().secondary
                            }}/><Typography paragraph>Error!</Typography>
                        </div>
                        <Typography style={{
                            fontSize : 11,
                            marginTop : 5,
                            color : verificationError === "error" ? hirUtil.getTheme().secondary : "green",
                        }}>{verificationStatus}</Typography>
                </div>}
            </div>
        );
    }
}


_HIRImportRecords.propTypes = {
    classes : PropTypes.object.isRequired,
    completeMigCallback : PropTypes.func,
};
export const HIRImportRecords = connect()(withStyles(style)(_HIRImportRecords));
export {HIRImportRecords as default}