import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { headerActions, headerStrings, breadCrumbActions, StageHeaderPlane, MyDialog } from '../utils';
import { hirRouteNames } from '../routeNames';
import { HIRButton } from '../Includes/Buttons';
import { HIRUserList } from './HIRUserList';
import { HIRUserForm } from './HIRUserForm';
import { hirUserActions } from './actions';
import { hirUserStrings } from './config';
import { hirUtilStrings } from '../utils';
import { history } from '../../../helpers';
import { IconButton } from '@material-ui/core';
import { Refresh } from '@material-ui/icons';


const style = theme => ({
    root: {
    }
})
class _HIRUsers extends Component {
    constructor(props) {
        super(props);
        this.state = {
            newUserDialog : false
        }
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "USERS",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", pathname : hirRouteNames.dashboard},
            {name : "Users", pathname : hirRouteNames.users}
        ])(dispatch);
    }
    componentWillMount(){
        const {
            [hirUtilStrings.myProfile] : profile
        } = this.props;
        if(!profile || [0, 11].indexOf(profile.privilege) === -1)
            history.replace(hirRouteNames.dashboard);
    }
    componentDidMount() {
        this.getUsers();
    }
    getUsers(){
        const {dispatch} = this.props;
        hirUserActions.getUsers()(dispatch);
    }
    
    searchAppointments(text){
        const {dispatch} = this.props;
        hirUserActions.searchUser(text)(dispatch);
    }
    newButton = () => {
        const {classes} = this.props;
        return <HIRButton
            classes={{btn : classes.menuBtn}}
            type="primary" 
            onClick={()=>this.setState({newUserDialog : true})}>
                New
            </HIRButton>
    }
    refreshButton = () => {
        const {classes} = this.props;
        return <IconButton
            classes={{btn : classes.menuBtn}}
            type="secondary" 
            onClick={()=>this.getUsers()}>
                <Refresh/>
            </IconButton>
    }
    createUser(data, context){
        const {dispatch} = this.props;
        hirUserActions.createUser(data, done=>{
            if(context) context.setState({loading : false});
            if(done){
                this.setState({newUserDialog : false});
                this.getUsers();
            }
        })(dispatch);
    }
    render() {
        const {classes, [hirUserStrings.users] : users_} = this.props;
        const {newUserDialog} = this.state;
        //admin was manually added actions to show staff in payment
        //remove this hear to avoid admin being deleted or archived
        const users = users_ ? [...users_] : [];
        if(users){
            const userIndex = users.findIndex(item => item._id === 1);
            if(userIndex) users.splice(userIndex, 1);
        }
        return (
            <div className={classes.root}>
                <div style={{marginBottom : 20}}>
                    <StageHeaderPlane
                        isRequired={false}
                        visible={true}
                        searchActions={this.searchAppointments.bind(this)}
                        components={[
                            this.refreshButton.bind(this),
                            this.newButton.bind(this),
                        ]}
                        />
                </div>
                <HIRUserList 
                    tableProps={{
                        data : users,                        
                    }}
                    actionCallback={this.getUsers.bind(this)}
                    />
                <MyDialog
                    open={newUserDialog}
                    close={()=>this.setState({newUserDialog : false})}>
                        <HIRUserForm
                            createUser={this.createUser.bind(this)}/>
                    </MyDialog>
            </div>
        );
    }
}


_HIRUsers.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({hirUserReducer, hirUtilReducer}) => ({
    [hirUserStrings.users] : hirUserReducer[hirUserStrings.users],
    [hirUtilStrings.myProfile] : hirUtilReducer[hirUtilStrings.myProfile],
})


export const HIRUsers = connect(mapStateToProps)(withStyles(style)(_HIRUsers));
export {HIRUsers as default}