import React, { Component, Fragment } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirSettingActions, hirSettingStrings } from '../../HIRSettings';
import { FormDisplay, getFormDisplayData, alertAction, appActions, hirUtil, errorNotice } from '../../utils';
import { HIRButton } from '../../Includes/Buttons';
import { CircularProgress, FormControl, FormControlLabel, FormHelperText, FormLabel, Grid, Radio, RadioGroup } from '@material-ui/core';
import { AccountBalance, AccountBalanceWallet, Cancel } from '@material-ui/icons';


const style = theme => ({
    root: {
    },
    creditWallet : {
        display : "flex",
    }
})
class _HIRNewPayment extends Component {
    constructor(props) {
        super(props);
        this.formConfig = [
            {name : "amount", label : "Amount", type : "number", placeholder : "Amount"},
            {name : "revenueType", label : "Revenue Type", type : "select", options : [
        
            ]},
        ]
        if(props.showDescription)
            this.formConfig.push({name : "description", label : "Description", placeholder : "Description"})
        if(hirUtil.isAdmin())
            this.formConfig.push({name : "actionDate", label : "Payment Date", type: "date", description : "Leave payment date empty to use today's date!"})

        this.state = {
            loading : false
        }
        const {editMode, paymentData} = props;
        if(editMode && paymentData){
            if(paymentData && paymentData.accountAction)
                this.state.accountAction = paymentData.accountAction
        }
    }
    componentDidMount() {
        const {
            dispatch,
            [hirSettingStrings.settings] : settings
        } = this.props;
        if(!settings) hirSettingActions.getSettings()(dispatch);
    }
    nameMap(name){
        switch(name){
            case "amount" : return "Amount";
            case "revenueType" : return "Revenue type";
            default : return name;
        }
    }
    onClick(){
        const {dispatch, paymentData, postPayment, editMode, editPayment, patient} = this.props,
        {accountAction} = this.state;
        const data = getFormDisplayData(
            this.newPaymentFormContext, 
            (name, value) => {
                if(["amount", "revenueType"].indexOf(name) !== -1 && 
                (!value || String(value).trim() === "")){
                    errorNotice(this.nameMap(name) + " can not have null value", dispatch);
                    return false;
                }
                return true;
            }
        )();
        if(data){
            if(accountAction){
                const {credit} = patient;
                if(accountAction === "useCredit" && !editMode && (!credit || parseInt(data.amount) > credit)) 
                    return errorNotice("Insuffient credit!", dispatch);
                else if(accountAction === "addToDebt" && !editMode && credit && credit > data.amount)
                    return errorNotice("You can't use debt record with sufficient credit", dispatch);
                else if(editMode){
                    const {amount : oldAmount} = paymentData || {};
                    if(!oldAmount) return errorNotice("Something went wrong!", dispatch);
                    if(data.amount > oldAmount){
                        const diffAmount = data.amount - oldAmount;
                        if(credit < diffAmount)
                            return errorNotice("Insufficient Credit", dispatch)
                    }

                }
                data.accountAction = accountAction
            }
            if(editMode && editPayment){
                this.setState({loading : true});
                editPayment(data, this);
            }
            else if(postPayment){
                this.setState({loading : true});
                postPayment(data, this);
            }
        }else this.setState({loading : false});
    }
    createAptButton = ({loading}) => {
        const {editMode, onCancel} = this.props;
        return <div style={{marginTop : 20}}>
            {onCancel && <HIRButton 
                disabled={loading}
                type={editMode ? "secondary" : "primary"} onClick={onCancel}>
                <Cancel fontSize="small"/>
            </HIRButton>}
            <HIRButton 
                disabled={loading}
                type={editMode ? "secondary" : "primary"} onClick={this.onClick.bind(this)}>
                {loading && <CircularProgress style={{
                    width : 30, height : 30
                }} color="secondary"/>}
                {editMode ? "Edit" : "Post"} Payment
            </HIRButton>
        </div>
    }
    calendarFormat(date = new Date().toLocaleDateString()){
        date = date.split("/");
        const day = String(date[0]).padStart(2, "0");
        const month = String(date[1]).padStart(2, "0");
        const year = String(date[2]).padStart(2, "0");
        return year+"-"+month+"-"+day;
    }
    options = [
        {_id : "none", name : "None"},
        {_id : "useCredit", name : "Use Credit"},
        {_id : "addToDebt", name : "Add to Debit"}
    ]
    handleRadio = e => {
        const value = e.target.value;
        this.setState({accountAction : value === "none" ? null : value});
    }
    render() {
        const {
            classes, 
            [hirSettingStrings.settings] : settings,
            patient, paymentData, editMode
        } = this.props;
        const {loading , accountAction} = this.state;
        let lastName, firstName; 
        if(patient){
            const {myProfile} = patient;
            lastName = myProfile.lastName;
            firstName = myProfile.firstName;
        }
        if(settings){
            const revenueTypes = settings.find(item=>item.name === "revenue");
            if(revenueTypes){
                this.formConfig = [...this.formConfig.map(item=>{
                    if(item.name === "revenueType"){
                        item.options = revenueTypes.values.map(item=>({_id : item.name, name : item.value}))                        
                    }
                    return item;
                })]
            }
        }
        const {credit, debt} = patient || {};
        return (
            <div className={classes.root}>
                <Grid container>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <div className={classes.creditWallet}>
                            <div style={{width : "30%", borderRight : "solid 1px", display : "flex", justifyContent : "flex-end", padding : 10}}>
                                <AccountBalanceWallet/>
                            </div>
                            <div style={{padding : 10, display : "flex", flexDirection : "column"}}>
                                <strong>Credit</strong>
                                <span>{Number(credit || 0).toLocaleString()}</span>
                            </div>
                        </div>
                    </Grid>
                    <Grid item xs={12} sm={6} md={6} lg={6} xl={6}>
                        <div className={classes.creditWallet}>
                            <div style={{width : "30%", borderRight : "solid 1px", display : "flex", justifyContent : "flex-end", padding : 10}}>
                                <AccountBalance/>
                            </div>
                            <div style={{padding : 10, display : "flex", flexDirection : "column"}}>
                                <strong>Debts</strong>
                                <span>{Number(debt || 0).toLocaleString()}</span>
                            </div>
                        </div>
                    </Grid>
                </Grid>
                <div style={{marginBottom : 20}}/>
                <FormDisplay
                    getContext={context=>this.newPaymentFormContext = context}
                    header={lastName && "Payment for "+lastName+", "+firstName}
                    formName="newAppointment"
                    formConfig={this.formConfig}
                    formData={paymentData ? {
                        ...paymentData, 
                        amount : String(paymentData.amount),
                        actionDate : this.calendarFormat(new Date(paymentData.actionDate).toLocaleDateString()),
                    } : null}
                    inputFieldProps={{
                        itemContainerProps : {
                            style : { marginBottom : 20}
                        }
                    }}
                />
                <FormControl fullWidth style={{padding : 10}}>
                    <Fragment>
                        <FormLabel>Account Actions</FormLabel>
                        <RadioGroup
                            onChange={this.handleRadio.bind(this)}
                            value={accountAction}
                            name={"CreditOptions"}
                            aria-label={"CreditOptions"}
                        >
                            {this.options.map((item, index)=>{
                                return <FormControlLabel
                                disabled={editMode}
                                key={index}
                                label={<span>{item.name}</span>}
                                value={item._id}
                                control={<Radio size="small"/>}/>
                            })}
                        </RadioGroup>
                    </Fragment>
                    <FormHelperText></FormHelperText>
                </FormControl>
                {this.createAptButton({loading})}
            </div>
        );
    }
}


_HIRNewPayment.propTypes = {
    classes : PropTypes.object.isRequired,
    patient : PropTypes.object,
    postPayment : PropTypes.func,
    editMode : PropTypes.bool,
    paymentData : PropTypes.object,
    editPayment : PropTypes.func,
    showDescription : PropTypes.bool,
};
const mapStateToProps = ({hirSettingReducer}) => ({
    [hirSettingStrings.settings] : hirSettingReducer[hirSettingStrings.settings],
})


export const HIRNewPayment = connect(mapStateToProps)(withStyles(style)(_HIRNewPayment));
export {HIRNewPayment as default}