import React, { PureComponent, Fragment } from 'react';
import PropTypes from 'prop-types';
import { withStyles } from '@material-ui/styles';
import { Divider, makeStyles} from '@material-ui/core';
import { TreeView, TreeItem } from '@material-ui/lab';
import {Link} from 'react-router-dom';
import LocalOfferIcon from '@material-ui/icons/LocalOffer';
import ArrowDropDownIcon from '@material-ui/icons/ArrowDropDown';
import ArrowRightIcon from '@material-ui/icons/ArrowRight';
import $ from 'jquery';
import { history } from '../../helpers';

const useTreeItemStyles = makeStyles(theme => ({
    root: {
      color: theme.palette.text.secondary,
      '&:focus > $content': {
        // backgroundColor: `var(${theme.colors?.primary}, ${theme.palette.grey[400]})`,
        // backgroundColor: `var(--tree-view-bg-color, ${theme.colors?.primary})`,
        color: 'var(--tree-view-color)',
      },
    },
    content: {
        width : "auto",
        color: theme.palette.text.secondary,
        fontWeight: theme.typography.fontWeightMedium,
        '$expanded > &': {
            fontWeight: theme.typography.fontWeightRegular,
        },
        padding : "10px 0"
    },
    group: {
      marginLeft: 0,
      '& $content': {
        paddingLeft: theme.spacing(2),
      },
    },
    expanded: {},
    label: {
      fontWeight: 'inherit',
      color: 'inherit',
    },
    labelRoot: {
      display: 'flex',
      alignItems: 'center',
      padding: theme.spacing(0.5, 0),
    },
    labelIcon: {
      marginRight: 5,
      marginLeft : 10,
    },
    labelText: {
      fontWeight: 'inherit',
      flexGrow: 1,
    },
    iconRoot : {
      minWidth : 0
    },
    selected : {
        backgroundColor : theme.colors?.secondary,
    }
  }));
  
function StyledTreeItem(props) {
    const classes = useTreeItemStyles();
    const { labelText, labelIcon: LabelIcon, labelInfo, color, bgColor, ...other } = props;
    return (
      <TreeItem
        icon={LabelIcon && <LabelIcon color="inherit" style={{color}} />}
        label={<span style={{color}}>{labelText}</span>}
        style={{
            '--tree-view-color': color,
            '--tree-view-bg-color': bgColor,
            // backgroundColor : bgColor,
        }}
        classes={{
            selected : classes.selected,
            root: classes.root,
            content: classes.content,
            expanded: classes.expanded,
            group: classes.group,
            label: classes.label,
            iconContainer : classes.labelIcon,
        }}
        {...other}
      />
    );
}
  
StyledTreeItem.propTypes = {
    bgColor: PropTypes.string,
    color: PropTypes.string,
    labelIcon: PropTypes.elementType,
    labelInfo: PropTypes.string,
    labelText: PropTypes.string.isRequired,
};
  





export const drawerWidth = 240;
const styles = theme => ({
    root : {
        width : drawerWidth,
    },
    // toolbar: theme.mixins.toolbar, //need a themeProvider
    toolbar : {
        minHeight : 65,
    },
    link : {
      textDecoration : "none"
    }
})
class _Drawer extends PureComponent {
    loopThroughMenuObject(menu=[]){
        return menu.map((item, index)=>{
          const {classes, color, bgColor} = this.props;
            return !item.tree ? 
                <Link 
                    className={classes.link}
                    key={JSON.stringify(item)}
                    to={{pathname : item.pathname}}>
                      <StyledTreeItem 
                      color={color}
                      bgColor={bgColor}
                      nodeId={item.nodeId}
                      labelIcon={item.labelIcon || LocalOfferIcon} 
                      labelText={item.name}/></Link>
                      : 
                <StyledTreeItem 
                    key={JSON.stringify(item)}
                    color={color}
                    bgColor={bgColor}
                    nodeId={item.nodeId}
                    // labelIcon={item.labelIcon || LocalOfferIcon} 
                    labelText={item.name}>
                        {this.loopThroughMenuObject([...item.tree.map(i=>({
                            ...i, pathname : item.pathname ? item.pathname+i.pathname : i.pathname
                        }))])}
                    </StyledTreeItem>
        })
    }
    render() {
        const {classes, lists, bgColor, color, drawerHeader : Header } = this.props;
        let pathname = history?.location?.pathname;
        if(String(pathname).charAt(pathname.length-1) === "/"){
            pathname = String(pathname).substr(0, pathname.length - 1);
        }
        const parent = lists && lists[0] && lists[0].find(
            item=>!item.tree ? 
                item.pathname === pathname : 
                item.tree.find(i=>i.pathname === pathname)
        );
        const child = parent?.tree?.find(i=>i.pathname === pathname);
        let item;
        if(!parent?.tree) item = parent;
        else item = child;
        return (
            <div className={classes.root}
                style={{/* backgroundColor : bgColor */}}>
                <div className={!Header ? classes.toolbar : ""}>
                    {Header && <Header/>}
                </div>
                <Divider />
                <TreeView
                    className={classes.root}                
                    defaultExpanded={[String(item?.nodeId).substr(0, 1)]}
                    defaultSelected={["11"]}
                    selected={[String(item?.nodeId)]}
                    defaultCollapseIcon={<ArrowDropDownIcon style={{color}}/>}
                    defaultExpandIcon={<ArrowRightIcon style={{color}}/>}
                    defaultEndIcon={<div style={{ width: 24 }} />}
                    >
                    {lists.map((list, index)=>{
                        return <Fragment key={index}>
                            {this.loopThroughMenuObject(list)}
                            <Divider/>
                        </Fragment>
                    })}
                </TreeView>
            </div>
        );
    }
}

_Drawer.propTypes = {
    lists : PropTypes.array,
    drawerHeader : PropTypes.object,
};

export const Drawer =  withStyles(styles)(_Drawer);
class _MyDrawer extends PureComponent{
    render(){
        const {backgroundImageDivProps, ...props}  = this.props;
        const {imageUrl, tintColor} = backgroundImageDivProps || {};
        return backgroundImageDivProps ? 
            <div style={{
                background : "url('"+imageUrl+"') no-repeat center /cover", 
                minHeight : "100%",
            }}>
                <div style={{
                    minHeight : "100%",
                    backgroundColor : tintColor,
                }}>
                    <Drawer {...props}/>
                </div>
            </div> :
            <Drawer {...props}/>
    }
}
_MyDrawer.propTypes = {
    ..._Drawer.propTypes,
    backgroundImageDivProps : PropTypes.object,
}
export const MyDrawer = _MyDrawer;