import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { hirDashboardActions } from './actions';
import { MyChart, headerActions, headerStrings, breadCrumbActions } from '../utils';
import { hirDashboardStrings } from './config';
import { monthLabels } from '../../../utils';
import { hirUtil } from '../utils';
import { Grid, FormLabel } from '@material-ui/core';
import { CountBox } from './CountBox';
import ReactToPrint from 'react-to-print';
import { hirRouteNames } from '../routeNames';
import { HIRDashboardAppointments } from './HIRDashboardAppointments';
import HIRDashboardRevenue from './HIRDashboardRevenue/HIRDashboardRevenue';
import HIRDashboardPatients from './HIRDashboardPatients/HIRDashboardPatients';


const style = theme => ({
    root: {
    },
    label : {
        fontWeight : "bold",
        color : theme.colors.primary1,
    },
    gridContainer : {
        marginTop : 20,
        marginBottom : 10,
    },
    grow : {
        display : "flex",
        flexGrow : 1
    },
    ipContainer : {
        display : 'flex',
    },
    ip : {
        padding : 10,
        borderRadius : 20,
        backgroundColor : theme.colors.secondary,
        color : theme.colors.white,
        marginRight : 10,
    }
})
class _Dashboard extends Component {
    constructor(props) {
        super(props);
        const {dispatch} = props;
        headerActions({
            [headerStrings.headerTitle] : "Dashboard",
            [headerStrings.backButtonAction] : null
        })(dispatch);
        breadCrumbActions.setBreadCrumb([
            {name : "Dashboard", pathname : hirRouteNames.dashboard}
        ])(dispatch);
    }
    
    componentDidMount() {
        const {dispatch} = this.props;
        hirDashboardActions.getLocalIP()(dispatch);
        this.getPaymentMonthDayData();
        this.getPaymentYearMonthData();

        this.getAppointmentMonthDayData();
        this.getAppointmentYearMonthData();
        this.getActualAppointmentMonthDayData();
        this.getActualAppointmentYearMonthData();

        this.getPatientMonthDayData();
        this.getPatientYearMonthData();

        this.getPaymentTotalAmounts();
        this.getAppointmentTotalCounts();
        this.getPatientTotalCounts();
    }
    getPatientTotalCounts(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getPatientDayTotalCount(
            date.getFullYear(),
            date.getMonth() + 1,
            date.getDate()
        )(dispatch);
        hirDashboardActions.getPatientMonthTotalCount(
            date.getFullYear(),
            date.getMonth() + 1
        )(dispatch);
        hirDashboardActions.getPatientYearTotalCount(
            date.getFullYear()
        )(dispatch);
    }
    getAppointmentTotalCounts(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getAppointmentDayTotalCount(
            date.getFullYear(),
            date.getMonth() + 1,
            date.getDate()
        )(dispatch);
        hirDashboardActions.getAppointmentMonthTotalCount(
            date.getFullYear(),
            date.getMonth() + 1
        )(dispatch);
        hirDashboardActions.getAppointmentYearTotalCount(
            date.getFullYear()
        )(dispatch);
    }
    getPaymentTotalAmounts(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getPaymentDayTotalAmount(
            date.getFullYear(),
            date.getMonth() + 1,
            date.getDate()
        )(dispatch);
        hirDashboardActions.getPaymentMonthTotalAmount(
            date.getFullYear(),
            date.getMonth() + 1
        )(dispatch);
        hirDashboardActions.getPaymentYearTotalAmount(
            date.getFullYear()
        )(dispatch);
    }
    getPatientMonthDayData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getPatientMonthDayData(
            date.getFullYear(), 
            date.getMonth() + 1
        )(dispatch);
    }
    getPatientYearMonthData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getPatientYearMonthData(
            date.getFullYear()
        )(dispatch);
    }
    getActualAppointmentMonthDayData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getActualAppointmentMonthDayData(
            date.getFullYear(),
            date.getMonth() + 1
        )(dispatch);
    }
    getActualAppointmentYearMonthData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getActualAppointmentYearMonthData(
            date.getFullYear()
        )(dispatch);
    }
    getAppointmentMonthDayData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getAppointmentMonthDayData(
            date.getFullYear(),
            date.getMonth() + 1
        )(dispatch);
    }
    getAppointmentYearMonthData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getAppointmentYearMonthData(
            date.getFullYear()
        )(dispatch);
    }
    getPaymentYearMonthData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getPaymentYearMonthData(
            date.getFullYear()
        )(dispatch);
    }
    getPaymentMonthDayData(){
        const {dispatch} = this.props;
        const date = new Date();
        hirDashboardActions.getPaymentMonthDayData(
            date.getFullYear(), date.getMonth() + 1
        )(dispatch);
    }
    deriveDailyData(data){
        const returnData = [];
        if(data) for (let i = 1; i < 31; i++) {
            const value = data.find(item=>item._id.day ===i);
            if(value)returnData.push(value.amount);
            else returnData.push(0);
        }
        return returnData;
    }
    deriveMonthlyData(data, valueName){
        const returnData = [];
        if(data) for (let i = 0; i < monthLabels.length; i++) {
            const value = data.find(item=>item._id.month==i+1);
            if(value){
                returnData.push(value[valueName]);
            }else returnData.push(0);
        }
        return returnData;
    }
    generateSequence(end){
        const returnData =[];
        for (let i = 0; i < end; i++) {
            returnData.push(i+1)
        }
        return returnData;
    }
    deriveDay(data, valueName){
        const returnData = [];
        if(data) for (let i = 0; i < 31; i++) {
            const value = data.find(item=>item._id.day === i+1)
            if(value) returnData.push(value[valueName]);
            else returnData.push(0);
        }
        return returnData;
    }
    render() {
        const {
            classes,
            [hirDashboardStrings.ip] : ip,
        } = this.props;
        const date = new Date();
        return (
            <div className={classes.root}>
                <div className={classes.ipContainer}>
                    <div className={classes.grow}/>
                    <div className={classes.ip}>IP (Public/ WIFI): http://{ip}</div>
                    <div className={classes.ip}>IP (LAN): http://192.168.0.10{ip && String(ip).substr(String(ip).lastIndexOf(":"))}</div>
                </div>
                <HIRDashboardRevenue/>
                <HIRDashboardAppointments/>
                <HIRDashboardPatients/>
            </div>
        );
    }
}


_Dashboard.propTypes = {
    classes : PropTypes.object.isRequired
};
const mapStateToProps = ({hirDashboardReducer}) => ({
    [hirDashboardStrings.ip] : hirDashboardReducer[hirDashboardStrings.ip],
})


export const Dashboard = connect(mapStateToProps)(withStyles(style)(_Dashboard));
export {Dashboard as default}