import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {withStyles} from '@material-ui/core/styles';
import { FormControl, Popover, Typography, FormLabel } from '@material-ui/core';
import { HIRButton } from '../Buttons';
import Calendar from 'react-calendar';


const style = theme => ({
    root: {
    }
})
class _HIRStartEndDates extends Component {
    constructor(props) {
        super(props);
        this.state = {
            anchorEl : null,
            dateType : null,
            startDate : null,
            endDate : null,
        }
    }
    handleDateSelection = date => {
        const {dateType} = this.state;
        const {onDateChange} = this.props;
        this.setState({[dateType] : date, anchorEl : null}, ()=>{
            const {startDate, endDate} = this.state;
            onDateChange && onDateChange(startDate, endDate, this);
        });
    }
    handleDateBtn = (dateType) => e => {
        this.setState({dateType, anchorEl : e.target});
    }
    render() {
        const {classes} = this.props;
        const {anchorEl, dateType, startDate, endDate} = this.state;
        return (
            <div className={classes.root} {...this.props.containerProps}>
                {!this.props.noTitle && <FormLabel>{this.props.title || "Date Range Picker"}</FormLabel>}
                <FormControl fullWidth className={classes.formcontrol} style={{
                    justifyContent : "space-around",
                    flexDirection : 'row',
                    marginTop : 20,
                    marginBottom : 15,
                }}>
                    <HIRButton
                        classes={{
                            btn : classes.termBtn
                        }}
                        type="primary" 
                        onClick={this.handleDateBtn("startDate")}>
                            Start Date: 
                            {startDate && new Date(startDate).toLocaleDateString()}
                    </HIRButton>
                    <HIRButton 
                        classes={{
                            btn : classes.termBtn
                        }}
                        type="secondary" 
                        onClick={this.handleDateBtn("endDate")}>
                            End Date : 
                            {endDate && new Date(endDate).toLocaleDateString()}
                    </HIRButton>
                </FormControl> 
                <Popover
                    open={Boolean(anchorEl)}
                    anchorEl={anchorEl}
                    onClose={() => this.setState({anchorEl : null})}
                    anchorOrigin={{
                        vertical: 'bottom',
                        horizontal: 'left',
                    }}
                    transformOrigin={{
                        vertical: 'top',
                        horizontal: 'left',
                    }}
                >
                    <Typography style={{textAlign:"center"}}>{dateType === "startDate" ? "Start Date" : "End Date"}</Typography>
                    <Calendar
                        onChange={this.handleDateSelection.bind(this)}/>
                </Popover>
            </div>
        );
    }
}


_HIRStartEndDates.propTypes = {
    classes : PropTypes.object.isRequired,
    onDateChange : PropTypes.func,
    title : PropTypes.string,
    noTitle : PropTypes.bool,
    containerProps : PropTypes.object,
};

export const HIRStartEndDates = withStyles(style)(_HIRStartEndDates);
export {HIRStartEndDates as default}