
import React, { Component } from 'react';
import PropTypes from 'prop-types';
import {connect} from 'react-redux';
import {withStyles} from '@material-ui/core/styles';
import { FormLabel, LinearProgress } from '@material-ui/core';


const style = theme => ({
    root: {
        width : "100%",
        minHeight : "100vh",
        display : "flex",
        flexDirection : "column",
        justifyContent : "center",
        alignItems : "center",
    }
})
class _MyProgressbar extends Component {
    render() {
        const {classes, header, description, containerProps={}} = this.props;
        return (
            <div className={classes.root} {...containerProps}>
                <FormLabel>{header}</FormLabel>
                <div style={{marginTop : 20}}/>
                <LinearProgress style={{width : "80%"}} variant="indeterminate"/>
            </div>
        );
    }
}


_MyProgressbar.propTypes = {
    classes : PropTypes.object.isRequired,
    header : PropTypes.string,
    description : PropTypes.string,
    containerProps : PropTypes.object,
};
export const MyProgressbar = connect()(withStyles(style)(_MyProgressbar));
export {MyProgressbar as default}